const CHARACTER_EXPANSION_V1_TYPES = [
    'guardian_naga',
    'garuda_hero',
    'kotsri',
    'elephant_king',
    'lopburi_monkey',
    'phi_ta_khon',
    'phuket_diver',
    'ayutthaya_warrior'
];

const DEFAULT_PLAYABLE_CHARACTER_TYPES = [
    'cat',
    'elephant',
    'tuktuk',
    'tea_idol',
    ...CHARACTER_EXPANSION_V1_TYPES
];

const playableTemplates = characterTemplates.filter(t => DEFAULT_PLAYABLE_CHARACTER_TYPES.includes(t.type));

function getDefaultCharacterFragments() {
    const fragments = {};
    characterTemplates.forEach(template => {
        if (template.type !== 'cat') {
            fragments[template.type] = 0;
        }
    });
    return fragments;
}

function ensureCharacterExpansionCompatibility() {
    if (!state.progression.unlockedCharacters || state.progression.unlockedCharacters.length === 0) {
        state.progression.unlockedCharacters = [...DEFAULT_PLAYABLE_CHARACTER_TYPES];
    } else {
        DEFAULT_PLAYABLE_CHARACTER_TYPES.forEach(type => {
            if (!state.progression.unlockedCharacters.includes(type)) {
                state.progression.unlockedCharacters.push(type);
            }
        });
    }

    if (!state.progression.characterFragments) {
        state.progression.characterFragments = getDefaultCharacterFragments();
    } else {
        const defaults = getDefaultCharacterFragments();
        Object.keys(defaults).forEach(type => {
            if (state.progression.characterFragments[type] === undefined) {
                state.progression.characterFragments[type] = defaults[type];
            }
        });
    }
}

