function t(key) {
    if (!state || !state.lang) return key;
    const dict = TRANSLATIONS[state.lang] || TRANSLATIONS['th'];
    return dict[key] || TRANSLATIONS['en'][key] || key;
}

function getThaiLocationName(name) {
    if (!name) return "";
    const clean = name.replace(/ 🏖️| 🛕| ☕| 🍜| 🚝| 🥢| 🛺| ⛵| 🥭| 💆| 🛍️| 🏮| 🐘| ✈️| 🚩| 🧱| 🌅| 🍍| 🚡| ⛱️| 🍚| ⛰️| 🍵| 🧖| 🐵| 🎺| 🏟️| 🎸| 🛝| 💦| 🎈| 👕/g, "").trim();
    return TRANSLATIONS['th'][clean] || name;
}

