    btnRoll.dataset.rollListenerAttached = 'true';
    btnRoll.addEventListener('click', () => {
        if (state.debugModeActive) {
            console.log("[ROLL DEBUG]", getRollDebugPayload());
        }

        if (state.currentPlayerIndex !== 0) {
            debugRollGuard('Ignored click: not the human player turn.');
            return;
        }
        if (!isRollButtonVisibleAndClickable(btnRoll)) {
            debugRollGuard('Ignored click: roll button is not visibly clickable.');
            return;
        }
        if (state.interactiveTutorialActive && state.tutorialStep === 1) {
            const rollBtn = document.getElementById('btn-roll-dice');
            if (rollBtn) rollBtn.classList.remove('tutorial-highlight');
            
            // Advance player roll dice to move
            state.tutorialStep = 2;
            hideTutorialOverlay();
        }
        const anyPlayerMoving = state.players.some(p => p.isMoving);
        if (anyPlayerMoving) {
            debugRollGuard('Ignored click: a player is still moving.');
            return;
        }
        if (state.dice.isRolling) {
            debugRollGuard('Ignored click: dice is already rolling.');
            return;
        }
        
        emergencyRollDirect();
    });

    // Sound & Volume controls UI bindings
    const btnMusic = document.getElementById('btn-toggle-music');
    const btnSfx = document.getElementById('btn-toggle-sfx');
    const btnAmbient = document.getElementById('btn-toggle-ambient');

