    const sliderSfx = document.getElementById('slider-sfx-volume');
    const sliderAmbient = document.getElementById('slider-ambient-volume');

    // Autoplay Context Activator Helper
    const resumeAudioOnInteraction = () => {
        if (!state.audio.initialized) {
            initAudio();
        } else if (audioCtx && audioCtx.state === 'suspended') {
            audioCtx.resume();
        }
    };
    
    btnMusic.addEventListener('click', (e) => {
        e.stopPropagation();
        resumeAudioOnInteraction();
        state.audio.musicEnabled = !state.audio.musicEnabled;
        btnMusic.classList.toggle('active', state.audio.musicEnabled);
        updateAudioVolumes();
        triggerHopSFX();
    });

    btnSfx.addEventListener('click', (e) => {
        e.stopPropagation();
        resumeAudioOnInteraction();
        state.audio.sfxEnabled = !state.audio.sfxEnabled;
        btnSfx.classList.toggle('active', state.audio.sfxEnabled);
        triggerHopSFX();
    });

    btnAmbient.addEventListener('click', (e) => {
        e.stopPropagation();
        resumeAudioOnInteraction();
        state.audio.ambientEnabled = !state.audio.ambientEnabled;
        btnAmbient.classList.toggle('active', state.audio.ambientEnabled);
        updateAmbientVolume();
        triggerHopSFX();
    });

