function updateWanderingNPCs(dt) {
    const time = clock.getElapsedTime();
    wanderingNPCs.forEach(n => {
        if (n.type === "cat") {
            n.stateTimer -= dt;
            
            if (n.stateTimer <= 0) {
                const states = ["sleep", "wander", "idle"];
                n.state = states[Math.floor(Math.random() * states.length)];
                n.stateTimer = 4.0 + Math.random() * 4.0;
                
                if (n.state === "wander") {
                    n.targetX = 2.5 + (Math.random() - 0.5) * 2.5;
                    n.targetZ = 2.5 + (Math.random() - 0.5) * 2.5;
                }
            }
            
            if (n.state === "sleep") {
                const s = 1.0 + Math.sin(time * 1.8) * 0.05;
                n.group.scale.set(s, 0.8, s);
                n.group.rotation.y = 0;
            } else if (n.state === "wander") {
                const dx = n.targetX - n.group.position.x;
                const dz = n.targetZ - n.group.position.z;
                const dist = Math.sqrt(dx*dx + dz*dz);
                
                if (dist > 0.1) {
                    n.group.position.x += (dx / dist) * n.speed * dt;
                    n.group.position.z += (dz / dist) * n.speed * dt;
                    n.group.rotation.y = Math.atan2(dx, dz);
                    
                    const w = 1.0 + Math.abs(Math.sin(time * 8.0)) * 0.12;
                    n.group.scale.set(1.0, w, 1.0);
                    n.group.position.y = -0.2 + Math.abs(Math.sin(time * 8.0)) * 0.06;
                } else {
                    n.state = "idle";
                }
            } else {
                const s = 1.0 + Math.sin(time * 3.5) * 0.03;
                n.group.scale.set(1.0, s, 1.0);
                n.group.position.y = -0.2;
                n.group.rotation.y = Math.sin(time * 1.2) * 0.25;
            }
        }
        
        if (n.type === "tourist") {
            n.angle += dt * n.speed;
            const px = Math.cos(n.angle) * n.radius;
            const pz = Math.sin(n.angle) * n.radius;
            
            n.group.position.set(px, 0.08, pz);
            n.group.rotation.y = -n.angle + Math.PI/2;
            
            n.group.position.y = 0.08 + Math.abs(Math.sin(time * 7.5 + n.wobbleOffset)) * 0.05;
            n.group.rotation.z = Math.sin(time * 7.5 + n.wobbleOffset) * 0.06;
        }

        if (n.type === "monk") {
            n.angle += dt * n.speed;
            const px = n.startX + Math.cos(n.angle) * n.radius;
            const pz = n.startZ + Math.sin(n.angle) * n.radius;
            n.group.position.set(px, 0.08, pz);
            n.group.rotation.y = -n.angle + Math.PI/2;
            n.group.position.y = 0.08 + Math.abs(Math.sin(time * 3.5 + n.wobbleOffset)) * 0.03; // slow meditative bob
        }

        if (n.type === "chef") {
            const s = 1.0 + Math.sin(time * 2.5) * 0.03;
            n.group.scale.set(1.0, s, 1.0);
            n.group.rotation.y = Math.sin(time * 0.8) * 0.12;
        }

        if (n.type === "dog") {
            n.stateTimer -= dt;
            if (n.stateTimer <= 0) {
                const states = ["sleep", "wander", "idle"];
                n.state = states[Math.floor(Math.random() * states.length)];
                n.stateTimer = 3.0 + Math.random() * 5.0;
                
                if (n.state === "wander") {
                    n.targetX = -2.5 + (Math.random() - 0.5) * 3.0;
                    n.targetZ = -2.5 + (Math.random() - 0.5) * 3.0;
                }
            }
            
            if (n.state === "sleep") {
                const s = 1.0 + Math.sin(time * 1.5) * 0.06;
                n.group.scale.set(s, 0.75, s);
                n.group.rotation.y = 0;
            } else if (n.state === "wander") {
                const dx = n.targetX - n.group.position.x;
                const dz = n.targetZ - n.group.position.z;
                const dist = Math.sqrt(dx*dx + dz*dz);
                
                if (dist > 0.1) {
                    n.group.position.x += (dx / dist) * n.speed * dt;
                    n.group.position.z += (dz / dist) * n.speed * dt;
                    n.group.rotation.y = Math.atan2(dx, dz);
                    
                    const w = 1.0 + Math.abs(Math.sin(time * 9.0)) * 0.14;
                    n.group.scale.set(1.0, w, 1.0);
                    n.group.position.y = -0.2 + Math.abs(Math.sin(time * 9.0)) * 0.08;
                } else {
                    n.state = "idle";
                }
            } else {
                n.group.position.y = -0.2;
                n.group.rotation.y = Math.sin(time * 2.0) * 0.3;
            }
        }

        if (n.type === "tuktuk_traffic") {
            n.angle += dt * n.speed;
            const px = Math.cos(n.angle) * n.radius;
            const pz = Math.sin(n.angle) * n.radius;
            const py = 0.08 + Math.abs(Math.sin(time * 14 + n.wobbleOffset)) * 0.03; // cute vibration
            
            n.group.position.set(px, py, pz);
            n.group.rotation.y = -n.angle + Math.PI / 2;
            n.group.rotation.z = Math.sin(time * 14 + n.wobbleOffset) * 0.04;
        }

        if (n.type === "canal_boat") {
            n.angle += dt * n.speed;
            const radius = n.radius;
            const px = n.startX + Math.sin(n.angle) * radius;
            const pz = n.startZ + Math.cos(n.angle * 0.5) * radius * 1.5;
            const py = -0.82 + Math.sin(time * 2.2 + n.wobbleOffset) * 0.02; // soft wave rock
            
            n.group.position.set(px, py, pz);
            
            const nextAngle = n.angle + 0.01;
            const npx = n.startX + Math.sin(nextAngle) * radius;
            const npz = n.startZ + Math.cos(nextAngle * 0.5) * radius * 1.5;
            n.group.rotation.y = Math.atan2(npx - px, npz - pz);
            n.group.rotation.z = Math.sin(time * 2.2 + n.wobbleOffset) * 0.05;
        }

        if (n.type === "sky_bird") {
            n.angle += dt * n.speed;
            const px = Math.cos(n.angle) * n.radius;
            const pz = Math.sin(n.angle) * n.radius;
            const py = n.height + Math.sin(time * 2.5 + n.wobbleOffset) * 0.35;
            
            n.group.position.set(px, py, pz);
            n.group.rotation.y = -n.angle + Math.PI; // forward flight path
            
            const flap = Math.sin(time * 12.0 + n.wobbleOffset) * 0.65;
            if (n.wingL) {
                n.wingL.rotation.x = flap;
                n.wingL.position.y = 0.02 + Math.abs(flap) * 0.06;
            }
            if (n.wingR) {
                n.wingR.rotation.x = -flap;
                n.wingR.position.y = 0.02 + Math.abs(flap) * 0.06;
            }
        }
    });
}

// --- COZY DETAILS: WIND SWAYING MOTION (TREES & SIGNS) ---
function setupSwayingProps() {
    scene.traverse(child => {
        if (child.isGroup && child.children.length > 0) {
            if (child.children.some(c => c.geometry && c.geometry.type === "BoxGeometry" && c.material.color && c.material.color.getHex() === 0x10b981)) {
                swayingElements.trees.push({
                    group: child,
                    offset: Math.random() * Math.PI * 2
                });
            }
        }
        if (child.isMesh && child.name !== "3d_die" && child !== state.dice.mesh && child.name.includes("outline") === false && child.parent && child.geometry && child.geometry.type === "BoxGeometry" && child.position.y > 0.8) {
            swayingElements.signs.push({
                mesh: child,
                offset: Math.random() * Math.PI * 2,
                startY: child.position.y
            });
        }
    });
}

function updateSwaying(dt) {
    const time = clock.getElapsedTime();
    
    swayingElements.trees.forEach(t => {
        t.group.rotation.z = Math.sin(time * 1.6 + t.offset) * 0.04;
        t.group.rotation.x = Math.cos(time * 1.2 + t.offset) * 0.03;
    });
    
    swayingElements.signs.forEach(s => {
        s.mesh.rotation.z = Math.sin(time * 2.2 + s.offset) * 0.08;
    });
}

// --- JUICY DETAILS: INTERACTIVE EMOTE BUBBLE SYSTEM ---
function triggerPlayerEmote(emoji, targetMesh = null) {
    const mesh = targetMesh || (state.players[state.currentPlayerIndex] ? state.players[state.currentPlayerIndex].mesh : null);
    if (!mesh) return;
    
    if (playerEmoteBubble) {
        scene.remove(playerEmoteBubble);
    }
    
    const canvas = document.createElement('canvas');
    canvas.width = 128;
    canvas.height = 128;
    const ctx = canvas.getContext('2d');
    
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.arc(64, 54, 40, 0, Math.PI * 2);
    ctx.fill();
    
    ctx.beginPath();
    ctx.moveTo(64, 94);
    ctx.lineTo(54, 114);
    ctx.lineTo(74, 94);
    ctx.fill();
    
    ctx.strokeStyle = '#2e1a11';
    ctx.lineWidth = 6;
    ctx.stroke();
    
    ctx.font = '54px Fredoka, Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(emoji, 64, 54);
    
    const tex = new THREE.CanvasTexture(canvas);
    const bubbleMat = new THREE.SpriteMaterial({ map: tex, transparent: true });
    playerEmoteBubble = new THREE.Sprite(bubbleMat);
    playerEmoteBubble.scale.set(1.6, 1.6, 1.6);
    playerEmoteBubble.targetMesh = mesh; // Attach to custom mesh
    scene.add(playerEmoteBubble);
    
    playerEmoteTimer = 2.2;
    setPlayerFaceReaction(emoji, mesh);
}

function triggerPlayerChat(text, targetMesh = null) {
    const mesh = targetMesh || (state.players[state.currentPlayerIndex] ? state.players[state.currentPlayerIndex].mesh : null);
    if (!mesh) return;
    
    if (playerEmoteBubble) {
        scene.remove(playerEmoteBubble);
    }
    
    const canvas = document.createElement('canvas');
    canvas.width = 256;
    canvas.height = 128;
    const ctx = canvas.getContext('2d');
    
    // Draw bubble base
    ctx.fillStyle = '#ffffff';
    ctx.strokeStyle = '#2e1a11';
    ctx.lineWidth = 4;
    
    ctx.beginPath();
    // Rounded rect fallback
    if (typeof ctx.roundRect === 'function') {
        ctx.roundRect(10, 10, 236, 80, 15);
    } else {
        ctx.rect(10, 10, 236, 80);
    }
    ctx.fill();
    ctx.stroke();
    
    // Little pointer arrow at the bottom
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.moveTo(128, 90);
    ctx.lineTo(118, 110);
    ctx.lineTo(138, 90);
    ctx.fill();
    
    ctx.beginPath();
    ctx.moveTo(118, 90);
    ctx.lineTo(118, 110);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(138, 90);
    ctx.lineTo(138, 110);
    ctx.stroke();
    
    // Text drawing
    ctx.fillStyle = '#2e1a11';
    ctx.font = 'bold 13px Fredoka, Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    
    // Wrap text into two lines if it's too long
    const words = text.split(' ');
    let line1 = '';
    let line2 = '';
    let isLine2 = false;
    
    words.forEach(w => {
        if (!isLine2) {
            if (ctx.measureText(line1 + w + ' ').width < 210) {
                line1 += w + ' ';
            } else {
                isLine2 = true;
                line2 = w + ' ';
            }
        } else {
            line2 += w + ' ';
        }
    });
    
    if (line2 === '') {
        ctx.fillText(line1.trim(), 128, 50);
    } else {
        ctx.fillText(line1.trim(), 128, 38);
        ctx.fillText(line2.trim(), 128, 62);
    }
    
    const tex = new THREE.CanvasTexture(canvas);
    const bubbleMat = new THREE.SpriteMaterial({ map: tex, transparent: true });
    playerEmoteBubble = new THREE.Sprite(bubbleMat);
    playerEmoteBubble.scale.set(2.8, 1.4, 1.0); // Wider for text!
    playerEmoteBubble.targetMesh = mesh;
    scene.add(playerEmoteBubble);
    
    playerEmoteTimer = 3.5; // Slightly longer for reading!
}

