        tracks.position.y = 0.11;
        landmarkGroup.add(tracks);

        // Station Pillars
        const pillarGeo = new THREE.BoxGeometry(0.16, 0.9, 0.16);
        const pill1 = new THREE.Mesh(pillarGeo, new THREE.MeshStandardMaterial({ color: 0xdddddd }));
        pill1.position.set(-0.35, 0.45, -0.6);
        landmarkGroup.add(pill1);
        const pill2 = pill1.clone();
        pill2.position.set(-0.35, 0.45, 0.6);
        landmarkGroup.add(pill2);

        // Station Canopy roof
        const stationCanopy = new THREE.Mesh(new THREE.BoxGeometry(0.9, 0.1, 1.9), canopyMat);
        stationCanopy.position.set(-0.35, 0.9, 0);
        landmarkGroup.add(stationCanopy);

        // Miniature staircase leading up to platform!
