let currentActiveEventPostClose = null;

function triggerCoinBurstAtPlayer(player) {
    if (player && player.mesh) {
        triggerCoinBurst(player.mesh.position.x, player.mesh.position.y + 0.6, player.mesh.position.z);
    }
}

function triggerTileSparklesAtPlayer(player, color) {
    if (player && player.mesh) {
        triggerTileSparkles(player.position, color, 20);
    }
}

function playLowBeepWarning() {
    if (audioCtx) {
        try {
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.type = 'sawtooth';
            osc.frequency.setValueAtTime(140, audioCtx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(80, audioCtx.currentTime + 0.35);
            gain.gain.setValueAtTime(0.2, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.35);
            osc.connect(gain);
            gain.connect(audioCtx.destination);
            osc.start();
            osc.stop(audioCtx.currentTime + 0.36);
        } catch(e) {}
    }
}

function triggerNagaEventForwardMove(steps) {
    setFlowPhase('movement_pending');
    startPlayerHopSequence(steps);
}

function triggerNagaEventBackwardMove(steps) {
    setFlowPhase('movement_pending');
    startPlayerBackwardHopSequence(steps);
}

function triggerBangkokEvent() {
    const isHuman = state.currentPlayerIndex === 0;
    const activePlayer = state.players[state.currentPlayerIndex];
    
    // Choose random event based on current map
    let eventPool = bangkokEvents;
    const mapId = state.currentMap || 'bangkok';
    if (mapId === 'chiangmai') {
        eventPool = chiangmaiEvents;
    } else if (mapId === 'phuket') {
        eventPool = phuketEvents;
    } else if (mapId === 'ayutthaya') {
        eventPool = ayutthayaEvents;
    }
    const randomIdx = Math.floor(Math.random() * eventPool.length);
    const event = eventPool[randomIdx];
    
    // Run mechanics
    const result = event.run(activePlayer);
    
    // UI elements update
    const card = document.getElementById('event-modal-card');
    card.classList.remove('border-red', 'border-yellow');
    
    const pill = document.getElementById('event-reward-pill');
    pill.classList.remove('pill-success', 'pill-warning', 'pill-lucky');
    
    const isThai = state.lang === 'th';
    const headerBg = document.getElementById('event-header-bg');
    
    if (event.rewardType === 'success') {
        headerBg.style.background = 'linear-gradient(135deg, #10b981 0%, #059669 100%)';
        pill.classList.add('pill-success');
        document.getElementById('event-reward-icon').innerText = '💰';
    } else if (event.rewardType === 'warning') {
        headerBg.style.background = 'linear-gradient(135deg, #ef4444 0%, #b91c1c 100%)';
        card.classList.add('border-red');
        pill.classList.add('pill-warning');
        document.getElementById('event-reward-icon').innerText = '⚠️';
    } else {
        headerBg.style.background = 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)';
        card.classList.add('border-yellow');
        pill.classList.add('pill-lucky');
        document.getElementById('event-reward-icon').innerText = '✨';
    }
    
    headerBg.innerText = isThai 
        ? (event.id === 'traffic_jam' || event.id === 'monsoon_rain' || event.id === 'mountain_rain' || event.id === 'island_storm' || event.id === 'heavy_rain_ay' ? 'คำเตือนกิจกรรม! ⚠️' : 'กิจกรรมท่องเที่ยว! 🎉') 
        : (event.id === 'traffic_jam' || event.id === 'monsoon_rain' || event.id === 'mountain_rain' || event.id === 'island_storm' || event.id === 'heavy_rain_ay' ? 'WARNING EVENT! ⚠️' : 'TOUR EVENT! 🎉');
        
    document.getElementById('event-card-icon').innerText = event.icon;
    
    let titleStr = isThai ? event.thTitle : event.title;
    if (!isHuman) {
        titleStr = `${activePlayer.name}: ${titleStr}`;
    }
    
    document.getElementById('event-card-title').innerText = titleStr;
    document.getElementById('event-card-desc').innerText = isThai ? event.thDesc : event.desc;
    document.getElementById('event-reward-text').innerText = isThai ? result.thGainText : result.gainText;
    
    // Log to alerts
    triggerAlertLog(result.log);
    
    // Store post-close action
    currentActiveEventPostClose = result.postClose || null;
    
    // Show event modal
    showModal('bangkok-event-modal');
    
    if (isHuman) {
        const closeBtn = document.getElementById('btn-close-event');
        // Clear previous event listener safely by cloning
        const newBtn = closeBtn.cloneNode(true);
        closeBtn.parentNode.replaceChild(newBtn, closeBtn);
        
        newBtn.addEventListener('click', () => {
            const turnContext = claimModalInteraction('bangkok-event-modal');
            if (!turnContext) return;
            consumeLandingAction('event');
            triggerHaptic([20, 30]);
            hideModal('bangkok-event-modal');
            
            if (currentActiveEventPostClose) {
                currentActiveEventPostClose();
                currentActiveEventPostClose = null;
            } else {
                scheduleLandingTurnCompletion(activePlayer, 600);
            }
        });
    } else {
        // Automatic bot reading timer of exactly 3 seconds!
        const turnContext = captureTurnContext();
        scheduleForCurrentTurn(() => {
            hideModal('bangkok-event-modal');
            if (currentActiveEventPostClose) {
                currentActiveEventPostClose();
                currentActiveEventPostClose = null;
            } else {
                finishCurrentTurn(400, turnContext);
            }
        }, 3000, turnContext);
    }
}

