function triggerChanceCardDraw() {
    const player = state.players[state.currentPlayerIndex];
    const isThai = state.lang === 'th';
    const activePlayers = state.players.filter(p => !p.stats.isBankrupt);
    
    let isTrailing = false;
    if (state.turnsPlayed >= 1 && activePlayers.length > 1 && !player.stats.isBankrupt) {
        let lowestNetWorth = Infinity;
        activePlayers.forEach(p => {
            const nw = getPlayerNetWorth(p);
            if (nw < lowestNetWorth) {
                lowestNetWorth = nw;
            }
        });
        if (getPlayerNetWorth(player) === lowestNetWorth) {
            isTrailing = true;
        }
    }

    if (isTrailing && Math.random() < 0.65) {
        // Trigger Lucky Traveler Event!
        drawnChanceCard = luckyTravelerCards[Math.floor(Math.random() * luckyTravelerCards.length)];
        const pName = isThai ? (player.thName || player.name) : player.name;
        triggerAlertLog(isThai
            ? `🔮 เหตุการณ์นักท่องเที่ยวผู้โชคดี! เพื่อสนับสนุน ${pName} ในการตามพรรคพวก!`
            : `🔮 Lucky Traveler Event! Supporting trailing player ${player.name} to catch up!`
        );
    } else {
        // Choose random card (with local Chiang Mai board overrides)
        if (state.currentMap === 'chiangmai') {
        const localCards = [
            { 
                title: "Yi Peng Festival! 🏮", 
                thTitle: "เทศกาลโคมลอยยี่เป็ง! 🏮",
                desc: "You release a golden sky lantern. The wind carries it to Doi Suthep and blesses you! Gain 300 coins!", 
                thDesc: "คุณปล่อยโคมลอยยี่เป็งสีทองขึ้นสู่ท้องฟ้า สายลมพัดพาโคมลอยไปยอดดอยสุเทพ รับโบนัสเหรียญนำโชค 300 เหรียญ!",
                amount: 300, type: "gain", rarity: "festival", icon: "🏮" 
            },
            { 
                title: "Mountain Rain! 🌦️", 
                thTitle: "ฝนตกยอดดอย! 🌦️",
                desc: "A sudden misty mountain shower sweeps Doi Inthanon. Slippery slopes! Pay 150 coins for gear maintenance.", 
                thDesc: "เกิดฝนหลวงและไอหมอกมรสุมพัดผ่านยอดดอยอินทนนท์ ถนนลื่น! จ่ายค่าบำรุงรักษาอุปกรณ์ปีนเขา 150 เหรียญ",
                amount: -150, type: "monsoon", rarity: "common", icon: "🌦️" 
            },
            { 
                title: "Tourist Season! 📈", 
                thTitle: "ฤดูกาลท่องเที่ยวไฮซีซั่น! 📈",
                desc: "High tourist season in Nimman Street! Massive toy cafe crowds arrive. Gain 120 coins for every property you own!", 
                thDesc: "เข้าสู่ฤดูกาลท่องเที่ยวไฮซีซั่นบริเวณถนนนิมมานฯ! ฝูงชนตบเท้าเข้าร้านกาแฟของคุณ รับโบนัส 120 เหรียญต่อที่ดินที่ครอบครอง!",
                amount: 120, type: "rent_bonus", rarity: "lucky", icon: "📈" 
            },
            { 
                title: "Flower Festival! 🌸", 
                thTitle: "เทศกาลแห่บุปผชาติ! 🌸",
                desc: "Gorgeous pastel blossom parades fill the city! Collect a flower merchant premium bonus of 250 coins!", 
                thDesc: "ขบวนแห่บุปผชาติไม้บล็อกพาสเทลแสนงดงามเคลื่อนผ่านเมือง! รับโบนัสแม่ค้าขายดอกไม้หวานชื่น 250 เหรียญ!",
                amount: 250, type: "gain", rarity: "lucky", icon: "🌸" 
            }
        ];
        drawnChanceCard = localCards[Math.floor(Math.random() * localCards.length)];
    } else {
        drawnChanceCard = chanceCards[Math.floor(Math.random() * chanceCards.length)];
    }
    }
    
    if (state.currentPlayerIndex === 0) {
        updateMissionProgress('draw_chance', 1);
        
        const isPositive = !(drawnChanceCard.type === 'move_backward' || drawnChanceCard.type === 'monsoon' || drawnChanceCard.amount < 0);
        if (isPositive) {
            updateMissionProgress('trigger_event', 1);
        }
    }
    
    // Set UI card elements
    document.getElementById('chance-card-title').innerText = isThai ? (drawnChanceCard.thTitle || drawnChanceCard.title) : drawnChanceCard.title;
    document.getElementById('chance-card-desc').innerText = isThai ? (drawnChanceCard.thDesc || drawnChanceCard.desc) : drawnChanceCard.desc;
    document.getElementById('chance-card-icon').innerText = drawnChanceCard.icon;

    // Set dynamic rarity badge
    const rarityBadge = document.getElementById('chance-card-rarity');
    if (rarityBadge) {
        rarityBadge.innerText = drawnChanceCard.rarity.toUpperCase();
        rarityBadge.className = `card-badge card-rarity-badge rarity-${drawnChanceCard.rarity}`;
    }

    // Happy sound for positive rarity, sad sound for negative card types
    if (drawnChanceCard.type === 'move_backward' || drawnChanceCard.type === 'monsoon' || drawnChanceCard.amount < 0) {
        triggerSadRentSFX();
        triggerPlayerEmote('😰');
    } else {
        triggerPurchaseChime();
        triggerPlayerEmote(drawnChanceCard.icon || '✨');
    }

    // Trigger visual pop modal
    showModal('chance-card-modal');
}

function executeChanceCardEffects(turnContext = captureTurnContext()) {
    if (!isTurnContextCurrent(turnContext)) return;
    const card = drawnChanceCard;
    if (!card) return;

    const isHuman = state.currentPlayerIndex === 0;
    const activePlayer = state.players[state.currentPlayerIndex];
    const activeName = activePlayer.name;
    const isThai = state.lang === 'th';

    if (!isHuman) {
        triggerBotPersonalityDialogue(activePlayer, 'draw_chance');
    }

    let shouldAdvanceTurn = true;

    // Apply specific event card rules based on type
    if (card.type === 'lucky_elephant' || card.type === 'tuktuk_turbo') {
        // Lucky Traveler Movement + Coins card!
        shouldAdvanceTurn = false;
        const steps = card.amount; // steps to move forward
        const coinsGift = card.coinReward; // coin bonus
        
        activePlayer.coins += coinsGift;
        activePlayer.stats.totalCoinsEarned += coinsGift;
        
        triggerHaptic([80, 120]);
        triggerPurchaseChime();
        triggerPlayerEmote(card.icon);
        
        const titleText = isThai ? (card.thTitle || card.title) : card.title;
        triggerAlertLog(`${titleText}! ${activeName} receives +${coinsGift} Coins and advances forward ${steps} tiles! 🐘✨`);
        
        if (activePlayer.mesh) {
            triggerFloatingText(`+${coinsGift} 💰`, activePlayer.mesh.position, 'bonus');
            triggerCoinBurstAtPlayer(activePlayer);
            
            // Brief camera focus on player
            state.cameraFocusTarget = activePlayer.mesh.position;
            state.cameraFocusDuration = 1.5;
        }
        
        setFlowPhase('movement_pending');
        scheduleForCurrentTurn(() => {
            startPlayerHopSequence(steps);
        }, 1200, turnContext);
        
    } else if (card.type === 'naga_blessing') {
        // Pure coin award
        const coinsGift = card.coinReward;
        activePlayer.coins += coinsGift;
        activePlayer.stats.totalCoinsEarned += coinsGift;
        
        triggerHaptic([60, 100]);
        triggerPurchaseChime();
        triggerPlayerEmote(card.icon);
        
        const titleText = isThai ? (card.thTitle || card.title) : card.title;
        triggerAlertLog(`${titleText}! ${activeName} receives a grand blessing of +${coinsGift} Coins! 🐉✨`);
        
        if (activePlayer.mesh) {
            triggerFloatingText(`+${coinsGift} 💰`, activePlayer.mesh.position, 'bonus');
            triggerCoinBurstAtPlayer(activePlayer);
        }
        
        // Standard turn completion since no movement happened
        scheduleLandingTurnCompletion(activePlayer, 1200);
        
    } else if (card.type === 'songkran') {
        // All 4 players receive card.amount coins!
        state.players.forEach(p => {
            let amount = card.amount;
            let catTriggered = false;
            let pixieTriggered = false;
            if (p.characterType === 'cat') {
                amount = Math.floor(amount * 1.2);
                catTriggered = true;
            } else if (p.characterType === 'pixie') {
                amount = Math.floor(amount * 1.2);
                pixieTriggered = true;
            }
            p.coins += amount;
            p.stats.totalCoinsEarned += amount;
            p.stats.festivalBonusCoins += amount;
            
            // Sparkle particles for each active mesh
            if (p.mesh) {
                triggerCoinBurst(p.mesh.position.x, p.mesh.position.y + 0.5, p.mesh.position.z);
            }
            
            if (catTriggered) {
                triggerPlayerEmote('🛕', p.mesh);
                triggerAlertLog(`${p.name}'s Temple Blessing boosts Songkran Splash to ${amount} Coins! 🛕💦`);
            } else if (pixieTriggered) {
                triggerPlayerEmote('🧚', p.mesh);
                triggerAlertLog(`${p.name}'s Lotus Blessing boosts Songkran Splash to ${amount} Coins! 🧚💦`);
            }
        });
        
        updateCoinsHUD(); // syncs active coins
        
        triggerPurchaseChime();
        triggerConfettiBurst();
        triggerPlayerEmote('💦');
        triggerAlertLog("Songkran Splash! All players received coins! 💦✨");
        
    } else if (card.type === 'upgrade') {
        // Free property upgrade! Locate active player's owned properties under level 3
        const owned = activePlayer.properties; // indices of owned properties
        const upgradeable = owned.filter(idx => {
            const tile = state.board[idx];
            return tile && tile.type === 'property' && tile.level < 3;
        });

        if (upgradeable.length > 0) {
            const randomIdx = upgradeable[Math.floor(Math.random() * upgradeable.length)];
            const tile = state.board[randomIdx];
            tile.level++;
            activePlayer.stats.upgradesDone++;
            
            // Discover sticker!
            const propType = getPropertyType(tile.name, tile.icon);
            discoverProperty(propType, tile.level, activePlayer.characterType);
            
            // Spawn updated building
            spawnMiniatureCottage(tile, tile.level);
            triggerUpgradeSparkles(tile);
            
            // Wobbly bounce effect on level up
            if (tile.mesh) {
                tile.mesh.position.y = -0.5;
                setTimeout(() => tile.mesh.position.y = -0.05, 150);
            }
            
            triggerPurchaseChime();
            triggerConfettiBurst();
            triggerPlayerEmote('☕');
            
            triggerAlertLog(`Viral Cafe Trend! ${activeName} upgraded ${tile.name} to level ${tile.level} for FREE! ☕✨`);
        } else {
            // No resorts to upgrade - give compensation coins instead!
            activePlayer.coins += 250;
            activePlayer.stats.totalCoinsEarned += 250;
            activePlayer.stats.festivalBonusCoins += 250;
            if (isHuman) {
                updateCoinsHUD();
            } else if (activePlayer.mesh) {
                triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y, activePlayer.mesh.position.z);
            }
            
            triggerPurchaseChime();
            triggerConfettiBurst();
            triggerPlayerEmote('💰');
            
            triggerAlertLog(`No resorts to upgrade! ${activeName} received 250 coins compensation instead! 💰`);
        }
        
    } else if (card.type === 'double_roll') {
        // Roll again immediately! Bypasses normal turn transition!
        shouldAdvanceTurn = false;
        
        triggerPurchaseChime();
        triggerConfettiBurst();
        triggerPlayerEmote('⚡');
        
        if (isHuman) {
            // Human extra roll
            setFlowPhase('awaiting_roll');
            setRollButtonState(true);
            triggerAlertLog("Double Dice Energy! You get an extra roll turn! ⚡🎲");
        } else {
            // Bot extra roll
            triggerAlertLog(`Double Dice Energy! ${activeName} rolls again!`);
            setFlowPhase('bot_thinking');
            scheduleForCurrentTurn(() => {
                rollDice3D();
            }, 1800, turnContext);
        }
        
    } else if (card.type === 'move_forward') {
        // Move forward a specified number of tiles
        shouldAdvanceTurn = false;
        const steps = Math.abs(card.amount);
        
        triggerHaptic([50, 100]);
        triggerPurchaseChime();
        triggerPlayerEmote(card.icon || '🏃');
        
        const titleText = isThai ? (card.thTitle || card.title) : card.title;
        triggerAlertLog(`${titleText}! ${activeName} advances forward ${steps} tiles! 🛺✨`);
        
        if (activePlayer.mesh) {
            triggerFloatingText(`+${steps} 🏃`, activePlayer.mesh.position, 'bonus');
            
            // Brief camera focus on player
            state.cameraFocusTarget = activePlayer.mesh.position;
            state.cameraFocusDuration = 1.5;
        }
        
        setFlowPhase('movement_pending');
        scheduleForCurrentTurn(() => {
            startPlayerHopSequence(steps);
        }, 800, turnContext);
        
    } else if (card.type === 'move_backward' || card.type === 'monsoon') {
        // Monsoon Frog Rain Boots immunity!
        if (activePlayer.characterType === 'frog') {
            triggerPlayerEmote('🐸');
            triggerAlertLog(isThai
                ? `🐸 รองเท้าบูทฝนหลวง! น้องกบฝนหลวงกระโดดข้ามพายุมรสุม/การติดขัดจราจรอย่างปลอดภัย! ☔✨`
                : `🐸 Rain Boots! Monsoon Frog hops safely over the monsoon storm/traffic congestion! ☔✨`
            );
            triggerPurchaseChime();
            // Advance turn normally since no movement occurred
            scheduleLandingTurnCompletion(activePlayer, 1200);
            return;
        }

        // Reverse slide backward a specified number of tiles
        shouldAdvanceTurn = false;
        const steps = Math.abs(card.amount);
        
        triggerHaptic([100, 50, 80]);
        triggerSadRentSFX();
        triggerPlayerEmote(card.icon || '🌧️');
        
        const titleText = isThai ? (card.thTitle || card.title) : card.title;
        triggerAlertLog(`${titleText}! ${activeName} slipped backward ${steps} tiles! 🌧️🏃`);
        activePlayer.stats.monsoonSlipped++;
        
        if (activePlayer.mesh) {
            triggerFloatingText(`-${steps} 🏃`, activePlayer.mesh.position, 'start');
            
            // Brief camera focus on player
            state.cameraFocusTarget = activePlayer.mesh.position;
            state.cameraFocusDuration = 1.5;
        }
        
        setFlowPhase('movement_pending');
        scheduleForCurrentTurn(() => {
            startPlayerBackwardHopSequence(steps);
        }, 800, turnContext);
        
    } else if (card.type === 'rent_bonus') {
        // Gain bonus coins for every property owned
        const ownedCount = activePlayer.properties.length;
        let bonusAmount = ownedCount * card.amount;
        let noPropertyConsolation = false;
        
        if (ownedCount === 0) {
            bonusAmount = 100; // Flat friendly consolation bonus
            noPropertyConsolation = true;
        }
        
        let catTriggered = false;
        let pixieTriggered = false;
        if (bonusAmount > 0) {
            if (activePlayer.characterType === 'cat') {
                bonusAmount = Math.floor(bonusAmount * 1.2);
                catTriggered = true;
            } else if (activePlayer.characterType === 'pixie') {
                bonusAmount = Math.floor(bonusAmount * 1.2);
                pixieTriggered = true;
            }
        }
        
        activePlayer.coins += bonusAmount;
        activePlayer.stats.totalCoinsEarned += bonusAmount;
        activePlayer.stats.festivalBonusCoins += bonusAmount;
        
        if (isHuman) {
            updateCoinsHUD();
        } else if (activePlayer.mesh) {
            triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y + 0.5, activePlayer.mesh.position.z);
        }
        
        triggerPurchaseChime();
        triggerConfettiBurst();
        triggerPlayerEmote(card.icon || '💰');
        
        const titleText = isThai ? (card.thTitle || card.title) : card.title;
        if (noPropertyConsolation) {
            let amountText = pixieTriggered ? `${bonusAmount} (โบนัสพิกซี่)` : "100";
            let amountEngText = pixieTriggered ? `${bonusAmount} (Pixie Bonus)` : "100";
            const msg = isThai ? `ไม่มีที่ดินในครอบครอง! ${activeName} ได้รับเหรียญปลอบใจ ${amountText} เหรียญ! 💰` : `No properties owned! ${activeName} gets a ${amountEngText} Coins consolation bonus! 💰`;
            triggerAlertLog(msg);
            if (activePlayer.mesh) {
                triggerFloatingText(`+${bonusAmount} 💰`, activePlayer.mesh.position, 'bonus');
            }
        } else {
            let suffixThai = pixieTriggered ? ` (โบนัสพิกซี่!)` : "";
            let suffixEng = pixieTriggered ? ` (Pixie Bonus!)` : "";
            const msg = isThai ? `${titleText}! ${activeName} ได้รับโบนัส ${bonusAmount} เหรียญ จากที่ดิน ${ownedCount} แห่ง!${suffixThai} 📈✨` : `${titleText}! ${activeName} earned ${bonusAmount} Coins for owning ${ownedCount} properties!${suffixEng} 📈✨`;
            triggerAlertLog(msg);
            if (activePlayer.mesh) {
                triggerFloatingText(`+${bonusAmount} 💰`, activePlayer.mesh.position, 'bonus');
            }
        }
        
    } else if (card.type === 'mystery_tourist') {
        // Mysterious tourist coin flip game!
        const isHeads = Math.random() < 0.5;
        let amt = 0;
        let msg = "";
        let thMsg = "";
        
        if (isHeads) {
            amt = card.amount; // +400 coins
            let pixieTriggered = false;
            if (activePlayer.characterType === 'cat') {
                amt = Math.floor(amt * 1.2);
            } else if (activePlayer.characterType === 'pixie') {
                amt = Math.floor(amt * 1.2);
                pixieTriggered = true;
            }
            activePlayer.coins += amt;
            activePlayer.stats.totalCoinsEarned += amt;
            activePlayer.stats.festivalBonusCoins += amt;
            
            triggerPurchaseChime();
            triggerConfettiBurst();
            triggerPlayerEmote('👑');
            
            let suffixThai = pixieTriggered ? ` (โบนัสพิกซี่!)` : "";
            let suffixEng = pixieTriggered ? ` (Pixie Bonus!)` : "";
            msg = `Heads! The Mysterious Tourist gifted ${activeName} ${amt} Coins!${suffixEng} 👤✨`;
            thMsg = `ออกหัว! นักท่องเที่ยวปริศนามอบเหรียญทองให้ ${activeName} ${amt} เหรียญ!${suffixThai} 👤✨`;
            
            if (activePlayer.mesh) {
                triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y + 0.5, activePlayer.mesh.position.z);
                triggerFloatingText(`+${amt} 💰`, activePlayer.mesh.position, 'bonus');
            }
        } else {
            amt = -100; // Lose 100 coins
            let pixieTriggered = false;
            if (activePlayer.characterType === 'pixie') {
                amt = -80; // mitigate penalty by 20%
                pixieTriggered = true;
            }
            const startingCoins = activePlayer.coins;
            activePlayer.coins = Math.max(0, activePlayer.coins + amt);
            activePlayer.stats.rentPaid += Math.min(startingCoins, Math.abs(amt));
            
            triggerSadRentSFX();
            triggerPlayerEmote('😰');
            
            let suffixThai = pixieTriggered ? ` (พรจากพิกซี่!)` : "";
            let suffixEng = pixieTriggered ? ` (Pixie Blessing!)` : "";
            msg = `Tails! The Mysterious Tourist asked for a ${Math.abs(amt)} Coins guide tip!${suffixEng} 👤💸`;
            thMsg = `ออกก้อย! นักท่องเที่ยวปริศนาขอทิปนำทาง ${Math.abs(amt)} เหรียญจาก ${activeName}!${suffixThai} 👤💸`;
            
            checkBankruptcy(activePlayer);
            
            if (activePlayer.mesh) {
                triggerFloatingText("-100 💸", activePlayer.mesh.position, 'start');
            }
        }
        
        if (isHuman) {
            updateCoinsHUD();
        }
        triggerAlertLog(isThai ? thMsg : msg);
        
    } else if (card.type === 'durian_challenge') {
        // Durian challenge game! 60% success chance (Mumu Pig has 100% success!)
        const isPig = activePlayer.characterType === 'pig';
        const success = isPig ? true : (Math.random() < 0.6);
        let amt = 0;
        let msg = "";
        let thMsg = "";
        
        if (success) {
            amt = card.amount; // +350 coins
            let pixieTriggered = false;
            if (activePlayer.characterType === 'cat') {
                amt = Math.floor(amt * 1.2);
            } else if (activePlayer.characterType === 'pixie') {
                amt = Math.floor(amt * 1.2);
                pixieTriggered = true;
            }
            activePlayer.coins += amt;
            activePlayer.stats.totalCoinsEarned += amt;
            activePlayer.stats.festivalBonusCoins += amt;
            
            triggerPurchaseChime();
            triggerConfettiBurst();
            triggerPlayerEmote('😋');
            
            let suffixThai = pixieTriggered ? ` (โบนัสพิกซี่!)` : (isPig ? ` (โบนัสราชาทุเรียน!)` : "");
            let suffixEng = pixieTriggered ? ` (Pixie Bonus!)` : (isPig ? ` (Durian King Bonus!)` : "");
            msg = `Success! ${activeName} devoured the Durian! Earned ${amt} Coins!${suffixEng} 🥭✨`;
            thMsg = `สำเร็จ! ${activeName} กินทุเรียนหมดเกลี้ยงจาน! รับรางวัล ${amt} เหรียญ!${suffixThai} 🥭✨`;
            
            if (activePlayer.mesh) {
                triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y + 0.5, activePlayer.mesh.position.z);
                triggerFloatingText(`+${amt} 🥭`, activePlayer.mesh.position, 'bonus');
            }
        } else {
            amt = -150; // Lose 150 coins
            let pixieTriggered = false;
            if (activePlayer.characterType === 'pixie') {
                amt = -120; // Mitigate penalty by 20%
                pixieTriggered = true;
            }
            const startingCoins = activePlayer.coins;
            activePlayer.coins = Math.max(0, activePlayer.coins + amt);
            activePlayer.stats.rentPaid += Math.min(startingCoins, Math.abs(amt));
            
            triggerSadRentSFX();
            triggerPlayerEmote('🤮');
            
            let suffixThai = pixieTriggered ? ` (พรจากพิกซี่!)` : "";
            let suffixEng = pixieTriggered ? ` (Pixie Blessing!)` : "";
            msg = `Smelly! ${activeName} couldn't stomach the durian! Paid ${Math.abs(amt)} Coins cleanup fee.${suffixEng} 🤢💸`;
            thMsg = `กลิ่นแรงมาก! ${activeName} กินไม่ไหว พ่ายแพ้ต่อกลิ่นทุเรียน จ่ายค่าเคลียร์จาน ${Math.abs(amt)} เหรียญ${suffixThai} 🤢💸`;
            
            checkBankruptcy(activePlayer);
            
            if (activePlayer.mesh) {
                triggerFloatingText("-150 💸", activePlayer.mesh.position, 'start');
            }
        }
        
        if (isHuman) {
            updateCoinsHUD();
        }
        triggerAlertLog(isThai ? thMsg : msg);
        
    } else if (card.type === 'minigame_tea' || card.type === 'minigame_tuktuk') {
        // Legacy/minigame fallback (in case triggered)
        shouldAdvanceTurn = false;
        const gameType = card.type === 'minigame_tea' ? 'tea' : 'tuktuk';
        
        if (isHuman) {
            setFlowPhase('minigame_pending');
            scheduleForCurrentTurn(() => {
                MiniGameManager.start(gameType, () => {
                    endTurn(turnContext);
                });
            }, 1000, turnContext);
        } else {
            const randScore = Math.floor(20 + Math.random() * 30);
            const reward = randScore * 10;
            activePlayer.coins += reward;
            activePlayer.stats.totalCoinsEarned += reward;
            activePlayer.stats.festivalBonusCoins += reward;
            
            scheduleForCurrentTurn(() => {
                if (activePlayer.mesh) {
                    triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y + 0.5, activePlayer.mesh.position.z);
                }
                const gameName = gameType === 'tea' ? "Thai Tea Rush 🥤" : "Tuk Tuk Drift 🛺";
                triggerAlertLog(`${activeName} played ${gameName} and scored ${randScore}! Earned ${reward} Coins! 💰`);
                triggerPlayerEmote(gameType === 'tea' ? '🥤' : '🛺', activePlayer.mesh);
                triggerPurchaseChime();
            }, 800, turnContext);
            
            scheduleForCurrentTurn(() => endTurn(turnContext), 2200, turnContext);
        }
    } else {
        // Standard Gain or Loss coins
        let amt = card.amount;
        const startingCoins = activePlayer.coins;
        let skillTriggered = false;
        let pixieTriggered = false;
        
        if (amt > 0) {
            if (activePlayer.characterType === 'cat') {
                amt = Math.floor(amt * 1.2);
                skillTriggered = true;
            } else if (activePlayer.characterType === 'pixie') {
                amt = Math.floor(amt * 1.2);
                pixieTriggered = true;
            }
        } else {
            if (activePlayer.characterType === 'pixie') {
                amt = Math.floor(amt * 0.8); // mitigate by 20%
                pixieTriggered = true;
            }
        }

        activePlayer.coins = Math.max(0, activePlayer.coins + amt);
        if (amt > 0) {
            activePlayer.stats.totalCoinsEarned += amt;
            if (card.rarity === 'legendary' || card.rarity === 'festival' || card.rarity === 'lucky') {
                activePlayer.stats.festivalBonusCoins += amt;
            }
        } else {
            activePlayer.stats.rentPaid += Math.min(startingCoins, Math.abs(amt));
        }
        if (isHuman) {
            updateCoinsHUD();
        } else if (activePlayer.mesh) {
            if (amt > 0) {
                triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y, activePlayer.mesh.position.z);
            }
        }
        checkBankruptcy(activePlayer);

        if (card.amount > 0) {
            triggerPurchaseChime();
            triggerConfettiBurst();
            if (activePlayer.mesh) {
                triggerFloatingText(`+${amt} 💰`, activePlayer.mesh.position, 'bonus');
            }
            if (skillTriggered) {
                triggerPlayerEmote('🛕');
                triggerAlertLog(`${activeName} triggers Temple Blessing! Earned boosted ${amt} Coins! 🛕✨`);
            } else if (pixieTriggered) {
                triggerPlayerEmote('🧚');
                triggerAlertLog(`${activeName} triggers Lotus Blessing! Earned boosted ${amt} Coins! 🧚✨`);
            } else {
                triggerPlayerEmote('✨');
                triggerAlertLog(`${activeName} earned ${card.amount} Coins! ✨`);
            }
        } else {
            triggerSadRentSFX();
            triggerPlayerEmote('😰');
            if (activePlayer.mesh) {
                triggerFloatingText(`-${Math.abs(amt)} 💸`, activePlayer.mesh.position, 'start');
            }
            if (pixieTriggered) {
                triggerPlayerEmote('🧚');
                triggerAlertLog(`${activeName} triggers Lotus Blessing! Mitigated penalty to ${Math.abs(amt)} Coins! 🧚✨`);
            } else {
                triggerAlertLog(`${activeName} paid ${Math.abs(card.amount)} Coins! 💸`);
            }
        }
    }

    // Turn transition for non-movement, non-continuation cards
    if (shouldAdvanceTurn) {
        scheduleLandingTurnCompletion(activePlayer, 1800);
    }

    drawnChanceCard = null;
}

// --- HUD SELECTORS DATA SYNC ---
function updateCoinsHUD() {
    const activePlayer = state.players[state.currentPlayerIndex];
    const leaderboardRows = document.querySelectorAll('.leaderboard-row');
    const row = leaderboardRows[state.currentPlayerIndex];
    const topCoinsText = document.getElementById('hud-player-coins');

    if (topCoinsText && state.players[0]) {
        topCoinsText.innerText = state.players[0].coins.toLocaleString();
    }
    
    // Sync gems and energy
    const gemsText = document.getElementById('hud-player-gems');
    if (gemsText) {
        gemsText.innerText = (state.progression.gems ?? 48).toLocaleString();
    }
    const energyText = document.getElementById('hud-player-energy');
    if (energyText) {
        energyText.innerText = `${state.progression.energy ?? 5}/5`;
    }
    
    if (row) {
        row.classList.remove('pulse-shake');
        void row.offsetWidth; // Trigger reflow
        row.classList.add('pulse-shake');
        setTimeout(() => row.classList.remove('pulse-shake'), 800);
    }

    // Erupt 3D spinning gold coins from player position
    if (state.started && activePlayer.mesh) {
        triggerCoinBurst(activePlayer.mesh.position.x, activePlayer.mesh.position.y + 0.5, activePlayer.mesh.position.z);
    }

    const coinsId = activePlayer.id === 'player' ? 'player-coins' : `coins-${activePlayer.id}`;
    const coinsText = document.getElementById(coinsId);
    if (coinsText) {
        // Bubbly increment slide effect
        let currentVal = parseInt(coinsText.innerText.replace(/,/g, ''));
        const targetVal = activePlayer.coins;
        
        const countInterval = setInterval(() => {
            if (currentVal === targetVal) {
                clearInterval(countInterval);
            } else {
                const step = Math.ceil(Math.abs(targetVal - currentVal) * 0.18);
                if (currentVal < targetVal) {
                    currentVal = Math.min(targetVal, currentVal + step);
                } else {
                    currentVal = Math.max(targetVal, currentVal - step);
                }
                coinsText.innerText = currentVal.toLocaleString();
            }
        }, 24);
    }
}

function updateOwnedPropertiesGrid() {
    const grid = document.getElementById('properties-grid');
    const resortCount = document.getElementById('resort-count');
    
    if (grid) {
        grid.innerHTML = '';
        const owned = state.player.properties;
        if (resortCount) {
            resortCount.innerText = owned.length;
        }

        if (owned.length === 0) {
            const isThai = state.lang === 'th';
            grid.innerHTML = `<div class="no-properties-text">${isThai ? "ยังไม่มีที่ดินในครอบครองเลย!" : "No properties bought yet!"}</div>`;
            return;
        }

        owned.forEach(idx => {
            const tile = state.board[idx];
            const isThai = state.lang === 'th';
            const stars = '⭐'.repeat(tile.level);
            const tag = document.createElement('div');
            tag.className = 'property-tag';
            tag.style.backgroundColor = "#" + tile.color.toString(16).padStart(6, '0');
            const nameStr = isThai ? getThaiLocationName(tile.name) : tile.name;
            tag.innerText = `${tile.icon} ${nameStr} (Lv. ${tile.level} ${stars})`;
            grid.appendChild(tag);
        });
    }
    
    if (typeof renderDistrictCollectionsHUD === 'function') {
        renderDistrictCollectionsHUD();
    }
}

function triggerAlertLog(msg) {
    const alertBox = document.getElementById('hud-alert-log');
    alertBox.innerHTML = msg;
    alertBox.classList.add('active');
    setTimeout(() => alertBox.classList.remove('active'), 3200);
}

// --- DYNAMIC RIATION splatters particles ---
function triggerWalkSplash(x, z, size = 1.0) {
    const geo = new THREE.RingGeometry(0.01, 0.35 * size, 8);
    geo.rotateX(-Math.PI / 2);
    const mat = new THREE.MeshBasicMaterial({
        color: 0xffffff,
        transparent: true,
        opacity: 0.6,
        blending: THREE.AdditiveBlending
    });
    const spl = new THREE.Mesh(geo, mat);
    spl.position.set(x, 0.05, z);
    scene.add(spl);
    
    activeFootprints.push({
        mesh: spl,
        mat: mat,
        age: 0,
        life: 0.2,
        scaleSpeed: 6 * size
    });
}

function updateFootprints(dt) {
    for (let i = activeFootprints.length - 1; i >= 0; i--) {
        const fp = activeFootprints[i];
        fp.age += dt;
        const progress = fp.age / fp.life;
        
        if (progress >= 1.0) {
            scene.remove(fp.mesh);
            fp.mesh.geometry.dispose();
            fp.mat.dispose();
            activeFootprints.splice(i, 1);
        } else {
            // Scale up outward splash ring
            const s = 1.0 + fp.scaleSpeed * fp.age;
            fp.mesh.scale.set(s, 1.0, s);
            // Fade out
            fp.mat.opacity = 0.6 * (1.0 - progress);
        }
    }
}

