function createChibiTukTukBoy() {
    const group = new THREE.Group();
    group.position.copy(boardCoordinates[0]);
    group.position.y = boardCoordinates[0].y;
    
    // Apply position cluster offsets
    const offset = getPlayerOffset(2);
    group.position.x += offset.x;
    group.position.z += offset.z;

    // 1. Head (Cream sphere)
    const headMat = new THREE.MeshStandardMaterial({ color: 0xffe4e6, roughness: 0.25 });
    const head = new THREE.Mesh(new THREE.SphereGeometry(0.5, 20, 20), headMat);
    head.position.y = 1.0;
    head.castShadow = true;
    group.add(head);

    // Cute pink cheeks blush cylinders
    const blushMat = new THREE.MeshBasicMaterial({ color: 0xffa8bc, transparent: true, opacity: 0.75 });
    const blushGeo = new THREE.CylinderGeometry(0.07, 0.07, 0.02, 6);
    blushGeo.rotateX(Math.PI / 2);
    const blushL = new THREE.Mesh(blushGeo, blushMat);
    blushL.position.set(-0.25, 0.9, 0.4);
    group.add(blushL);
    const blushR = blushL.clone();
    blushR.position.x = 0.25;
    group.add(blushR);

    // 2. Blue Driving Cap (Cylinder)
    const capMat = new THREE.MeshStandardMaterial({ color: 0x0ea5e9, roughness: 0.3 });
    const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.48, 0.5, 0.25, 12), capMat);
    cap.position.y = 1.45;
    group.add(cap);

    // Visor (Black box extending forward)
    const visorMat = new THREE.MeshStandardMaterial({ color: 0x221a1a, roughness: 0.1 });
    const visor = new THREE.Mesh(new THREE.BoxGeometry(0.55, 0.06, 0.25), visorMat);
    visor.position.set(0, 1.34, 0.42);
    visor.rotation.x = 0.12; // tilt slightly down
    group.add(visor);

    // Tiny yellow cap badge/button on top center
    const badgeMat = new THREE.MeshStandardMaterial({ color: 0xfef08a, roughness: 0.2 });
    const badge = new THREE.Mesh(new THREE.SphereGeometry(0.08, 8, 8), badgeMat);
    badge.position.set(0, 1.58, 0);
    group.add(badge);

    // 3. Eyes
    const eyeMat = new THREE.MeshStandardMaterial({ color: 0x221a1a, roughness: 0.1 });
    const eyeL = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 0.06), eyeMat);
    eyeL.name = "eyeL";
    eyeL.rotation.x = Math.PI / 2;
    eyeL.position.set(-0.14, 1.0, 0.44);
    group.add(eyeL);
    const eyeR = eyeL.clone();
    eyeR.name = "eyeR";
    eyeR.position.x = 0.14;
    group.add(eyeR);

    // Smile mouth (Curved ring slice)
    const mouthGeo = new THREE.RingGeometry(0.015, 0.055, 8, 1, 0, Math.PI);
    mouthGeo.rotateZ(Math.PI);
    const mouth = new THREE.Mesh(mouthGeo, eyeMat);
    mouth.position.set(0, 0.88, 0.46);
    group.add(mouth);

    // 4. Body (Sky blue cylindrical overalls)
    const bodyMat = new THREE.MeshStandardMaterial({ color: 0x0ea5e9, roughness: 0.25 });
    const body = new THREE.Mesh(new THREE.CylinderGeometry(0.26, 0.2, 0.44, 12), bodyMat);
    body.position.y = 0.42;
    body.castShadow = true;
    group.add(body);

    // Yellow straps
    const strapMat = new THREE.MeshStandardMaterial({ color: 0xfef08a, roughness: 0.3 });
    const strapL = new THREE.Mesh(new THREE.BoxGeometry(0.07, 0.38, 0.28), strapMat);
    strapL.position.set(-0.13, 0.52, 0.04);
    group.add(strapL);
    const strapR = strapL.clone();
    strapR.position.x = 0.13;
    group.add(strapR);

    // Shadow Plane
    const shadowCanvas = document.createElement('canvas');
    shadowCanvas.width = 64;
    shadowCanvas.height = 64;
    const sCtx = shadowCanvas.getContext('2d');
    const grad = sCtx.createRadialGradient(32, 32, 0, 32, 32, 28);
    grad.addColorStop(0, 'rgba(0, 0, 0, 0.45)');
    grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
    sCtx.fillStyle = grad;
    sCtx.fillRect(0, 0, 64, 64);
    const shadowTex = new THREE.CanvasTexture(shadowCanvas);
    const shadowPlane = new THREE.Mesh(
        new THREE.PlaneGeometry(1.4, 1.4),
        new THREE.MeshBasicMaterial({ map: shadowTex, transparent: true, depthWrite: false })
    );
    shadowPlane.rotation.x = -Math.PI / 2;
    shadowPlane.position.y = 0.01;
    group.add(shadowPlane);

    applyOutlineRecursive(group, 0.04);
    scene.add(group);
    tuktukMesh = group;
    state.players[2].mesh = group; // Tuk Tuk Boy replaces slot 2
}

