const PARTY_MINIGAME_TYPES = Object.keys(PARTY_MINIGAMES);

function getPartyMiniGameName(type) {
    const meta = PARTY_MINIGAMES[type] || PARTY_MINIGAMES.tea;
    return state.lang === 'th' ? meta.thTitle : meta.title;
}

function getPartyMiniGameEmoji(type) {
    return (PARTY_MINIGAMES[type] || PARTY_MINIGAMES.tea).icon;
}

function chooseMiniGameForTile(tile, tileIdx) {
    if (tileIdx === 1 || tileIdx === 9) return 'tea';
    if (tileIdx === 6) return 'tuktuk';

    const name = (tile && tile.name ? tile.name : '').toLowerCase();
    if (name.includes('floating') || name.includes('pier') || name.includes('market')) return 'fishing';
    if (name.includes('wat') || name.includes('temple') || name.includes('arun') || name.includes('buddha')) return 'cannon';
    if (name.includes('beach') || name.includes('island') || name.includes('resort')) return 'treasure';
    if (tile && tile.type === 'chance') return PARTY_MINIGAME_TYPES[Math.floor(Math.random() * PARTY_MINIGAME_TYPES.length)];
    return null;
}

const MiniGameManager = {
    activeGame: null,
    callback: null,
    score: 0,
    timer: 10,
    timerInterval: null,
    countdownInterval: null,
    loopId: null,
    gameActive: false,
    combo: 0,
    status: 'idle',
    turnContext: null,
    rewardApplied: false,
    callbackClaimed: false,

    // Tuk Tuk Drift specifics
    tuktukState: {
        lanes: [45, 135, 225],
        currentLane: 1,
        player: { x: 135, y: 145, width: 28, height: 42, targetX: 135 },
        entities: [],
        spawnTimer: 0,
        roadScroll: 0,
        roadSpeed: 240
    },

    simpleGameState: {
        wheelRotation: 0,
        cannonAim: 0,
        cannonDir: 1,
        treasureDug: new Set(),
        fishingStreak: 0
    },

    init() {
        // Bind UI buttons
        const btnStart = document.getElementById('btn-start-minigame');
        if (btnStart) {
            btnStart.addEventListener('click', () => this.startCountdown());
        }

        const btnTapTea = document.getElementById('btn-tap-tea');
        if (btnTapTea) {
            btnTapTea.addEventListener('click', (e) => {
                e.preventDefault();
                this.tapTea();
            });
            btnTapTea.addEventListener('touchstart', (e) => {
                e.preventDefault();
                this.tapTea();
            });
        }

        const btnLeft = document.getElementById('btn-tuktuk-left');
        if (btnLeft) {
            btnLeft.addEventListener('click', (e) => {
                e.preventDefault();
                this.steerTukTuk(-1);
            });
            btnLeft.addEventListener('touchstart', (e) => {
                e.preventDefault();
                this.steerTukTuk(-1);
            });
        }

        const btnRight = document.getElementById('btn-tuktuk-right');
        if (btnRight) {
            btnRight.addEventListener('click', (e) => {
                e.preventDefault();
                this.steerTukTuk(1);
            });
            btnRight.addEventListener('touchstart', (e) => {
                e.preventDefault();
                this.steerTukTuk(1);
            });
        }

        const btnWheelSpin = document.getElementById('btn-wheel-spin');
        if (btnWheelSpin) {
            btnWheelSpin.addEventListener('click', (e) => {
                e.preventDefault();
                this.spinWheel();
            });
        }

        document.querySelectorAll('.treasure-dig-tile').forEach(tile => {
            tile.addEventListener('click', (e) => {
                e.preventDefault();
                this.digTreasure(tile);
            });
        });

        const btnCannonFire = document.getElementById('btn-cannon-fire');
        if (btnCannonFire) {
            btnCannonFire.addEventListener('click', (e) => {
                e.preventDefault();
                this.fireTempleCannon();
            });
        }

        document.querySelectorAll('.fishing-ripple').forEach(ripple => {
            ripple.addEventListener('click', (e) => {
                e.preventDefault();
                this.catchMarketFish(ripple);
            });
        });

        const canvas = document.getElementById('tuktuk-game-canvas');
        if (canvas) {
            canvas.addEventListener('touchstart', (e) => {
                e.preventDefault();
                const rect = canvas.getBoundingClientRect();
                const touchX = e.touches[0].clientX - rect.left;
                if (touchX < rect.width / 2) {
                    this.steerTukTuk(-1);
                } else {
                    this.steerTukTuk(1);
                }
            }, { passive: false });
            
            canvas.addEventListener('mousedown', (e) => {
                e.preventDefault();
                const rect = canvas.getBoundingClientRect();
                const clickX = e.clientX - rect.left;
                if (clickX < rect.width / 2) {
                    this.steerTukTuk(-1);
                } else {
                    this.steerTukTuk(1);
                }
            });
        }

        const btnClaim = document.getElementById('btn-claim-minigame');
        if (btnClaim) {
            btnClaim.addEventListener('click', () => this.claimReward());
        }

        // Global keyboard listener
        window.addEventListener('keydown', (e) => {
            if (!this.gameActive) return;

            if (this.activeGame === 'tea') {
                if (e.code === 'Space') {
                    e.preventDefault();
                    this.tapTea();
                }
            } else if (this.activeGame === 'tuktuk') {
                if (e.code === 'ArrowLeft' || e.code === 'KeyA') {
                    e.preventDefault();
                    this.steerTukTuk(-1);
                } else if (e.code === 'ArrowRight' || e.code === 'KeyD') {
                    e.preventDefault();
                    this.steerTukTuk(1);
                }
            } else if (this.activeGame === 'wheel' && e.code === 'Space') {
                e.preventDefault();
                this.spinWheel();
            } else if (this.activeGame === 'cannon' && e.code === 'Space') {
                e.preventDefault();
                this.fireTempleCannon();
            }
        });
    },

    start(gameType, callback) {
        if (this.status !== 'idle' || state.activeModal) {
            debugFlow('Rejected duplicate mini-game start.');
            return;
        }
        this.turnContext = captureTurnContext();
        if (!isTurnContextCurrent(this.turnContext)) return;
        this.activeGame = gameType;
        this.callback = callback;
        this.score = 0;
        this.combo = 0;
        this.gameActive = false;
        this.rewardApplied = false;
        this.callbackClaimed = false;
        this.status = 'intro';

        // Reset score HUD
        document.getElementById('minigame-score').innerText = '0';
        
        // Show correct badges and instruction view
        const badge = document.getElementById('minigame-type-badge');
        const title = document.getElementById('minigame-title');
        const icon = document.getElementById('minigame-icon');
        const instructions = document.getElementById('minigame-instructions');

        const isThai = state.lang === 'th';
        const meta = PARTY_MINIGAMES[gameType] || PARTY_MINIGAMES.tea;
        if (meta) {
            badge.innerText = isThai ? meta.thBadge : meta.badge;
            title.innerText = isThai ? meta.thTitle : meta.title;
            icon.innerText = meta.icon;
            instructions.innerText = isThai ? meta.thInstructions : meta.instructions;
            this.timer = meta.timer;

            document.getElementById('tea-fluid').style.height = '0%';
            document.getElementById('tea-bubbles-container').innerHTML = '';
            document.getElementById('tea-combo-alert').innerText = '';
            this.resetSimpleGameViews();

            document.getElementById('minigame-timer').innerText = this.timer;
            this.showSubview('minigame-intro-view');
            showModal('minigame-modal');
            return;
        }
        if (gameType === 'tea') {
            badge.innerText = isThai ? "ปาร์ตี้ชงชา! 🥤" : "COZY RUSH! 🥤";
            title.innerText = isThai ? "เทศกาลชงชาไทย" : "THAI TEA RUSH";
            icon.innerText = "🥤";
            instructions.innerText = isThai 
                ? "ชงชาไทยแสนหวาน! กดแท็บถ้วยชานมพาสเทล หรือกดปุ่ม SPACEBAR ให้เร็วที่สุดเพื่อชงชาไทยสีส้มแสนอร่อยพร้อมไข่มุกเหนียวหนึบ! 🥤✨" 
                : "Brew sweet Thai milk tea! Tap the shaking cup or hit the SPACEBAR as fast as possible to fill the glass with sweet orange tea and glossy tapioca pearls! 🥤✨";
            
            document.getElementById('tea-fluid').style.height = '0%';
            document.getElementById('tea-bubbles-container').innerHTML = '';
            document.getElementById('tea-combo-alert').innerText = '';
            this.timer = 10;
        } else {
            badge.innerText = isThai ? "ซิ่งตุ๊กตุ๊ก! 🛺" : "ROAD ARCADE! 🛺";
            title.innerText = isThai ? "ซิ่งตุ๊กตุ๊กสุดมันส์" : "TUK TUK DRIFT";
            icon.innerText = "🛺";
            instructions.innerText = isThai 
                ? "ดริฟต์รถตุ๊กตุ๊กสามล้อสุดน่ารัก! สะสมเหรียญทองและหลบฝูงควาย 🐃 รวมถึงรถบรรทุก 🚚! แตะซ้าย/ขวาของหน้าจอ หรือใช้ปุ่มลูกศรเพื่อเคลื่อนเลน! 🛺💨" 
                : "Steer the three-wheeled Tuk Tuk taxi! Collect shiny gold coins and dodge water buffaloes 🐃 and trucks 🚚! Touch the left/right screen or use Arrow Keys! 🛺💨";
            this.timer = 12;
        }

        document.getElementById('minigame-timer').innerText = this.timer;
        this.showSubview('minigame-intro-view');
        showModal('minigame-modal');
    },

    showSubview(viewId) {
        const subviews = ['minigame-intro-view', 'minigame-countdown-view', 'minigame-play-view', 'minigame-results-view'];
        subviews.forEach(id => {
            const el = document.getElementById(id);
            if (el) {
                el.classList.toggle('active-view', id === viewId);
            }
        });
    },

    startCountdown() {
        if (this.status !== 'intro') return;
        this.status = 'countdown';
        this.showSubview('minigame-countdown-view');
        const countEl = document.getElementById('minigame-countdown-number');
        let currentCount = 3;
        countEl.innerText = currentCount;
        countEl.style.color = 'var(--pastel-red)';
        
        triggerMiniGameCountdownBeep(currentCount);

        this.countdownInterval = setInterval(() => {
            currentCount--;
            if (currentCount > 0) {
                countEl.innerText = currentCount;
                triggerMiniGameCountdownBeep(currentCount);
            } else if (currentCount === 0) {
                countEl.innerText = "GO!";
                countEl.style.color = 'var(--pastel-mint)';
                triggerMiniGameCountdownBeep('GO');
            } else {
                clearInterval(this.countdownInterval);
                this.countdownInterval = null;
                this.play();
            }
        }, 800);
    },

    play() {
        if (this.status !== 'countdown' || !isTurnContextCurrent(this.turnContext)) return;
        this.status = 'playing';
        this.showSubview('minigame-play-view');
        this.gameActive = true;

        this.activateMiniGameView();
        if (this.activeGame === 'tuktuk') {
            this.initTukTukGame();
        } else if (['wheel', 'treasure', 'cannon', 'fishing'].includes(this.activeGame)) {
            this.initSimpleGame();
        }

        this.timerInterval = setInterval(() => {
            this.timer--;
            document.getElementById('minigame-timer').innerText = this.timer;
            if (this.timer <= 0) {
                this.endGame();
            }
        }, 1000);
        return;

        if (this.activeGame === 'tea') {
            document.getElementById('game-tea-view').style.display = 'block';
            document.getElementById('game-tuktuk-view').style.display = 'none';
        } else {
            document.getElementById('game-tea-view').style.display = 'none';
            document.getElementById('game-tuktuk-view').style.display = 'block';
            this.initTukTukGame();
        }

        // Start timer
        this.timerInterval = setInterval(() => {
            this.timer--;
            document.getElementById('minigame-timer').innerText = this.timer;
            if (this.timer <= 0) {
                this.endGame();
            }
        }, 1000);
    },

    activateMiniGameView() {
        const viewMap = {
            tea: 'game-tea-view',
            tuktuk: 'game-tuktuk-view',
            wheel: 'game-wheel-view',
            treasure: 'game-treasure-view',
            cannon: 'game-cannon-view',
            fishing: 'game-fishing-view'
        };
        Object.values(viewMap).forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = id === viewMap[this.activeGame] ? 'block' : 'none';
        });
    },

    resetSimpleGameViews() {
        const wheel = document.getElementById('fortune-wheel-disc');
        if (wheel) wheel.style.transform = 'rotate(0deg)';
        const wheelResult = document.getElementById('wheel-result-text');
        if (wheelResult) wheelResult.innerText = 'Line up the pointer and spin for prizes.';

        this.simpleGameState.treasureDug = new Set();
        document.querySelectorAll('.treasure-dig-tile').forEach(tile => {
            tile.disabled = false;
            tile.classList.remove('dug');
            tile.innerText = '?';
        });
        const treasureResult = document.getElementById('treasure-result-text');
        if (treasureResult) treasureResult.innerText = 'Tap sand tiles to uncover hidden travel treasure.';

        this.simpleGameState.cannonAim = 0;
        this.simpleGameState.cannonDir = 1;
        const cannonResult = document.getElementById('cannon-result-text');
        if (cannonResult) cannonResult.innerText = 'Fire when the lantern is centered.';
        const cannonTarget = document.getElementById('temple-cannon-target');
        if (cannonTarget) cannonTarget.style.left = '50%';
        const cannonMeter = document.getElementById('temple-cannon-meter-fill');
        if (cannonMeter) cannonMeter.style.transform = 'translateX(0%)';

        this.simpleGameState.fishingStreak = 0;
        document.querySelectorAll('.fishing-ripple').forEach(ripple => {
            ripple.disabled = false;
            ripple.innerText = '~';
        });
        const fishingResult = document.getElementById('fishing-result-text');
        if (fishingResult) fishingResult.innerText = 'Tap ripples to catch lucky market fish.';
    },

    initSimpleGame() {
        this.resetSimpleGameViews();
        if (this.activeGame !== 'cannon') return;

        let lastTime = performance.now();
        const tick = (now) => {
            if (!this.gameActive || this.activeGame !== 'cannon') return;
            let dt = (now - lastTime) / 1000;
            if (dt > 0.1) dt = 0.1;
            lastTime = now;

            const simple = this.simpleGameState;
            simple.cannonAim += simple.cannonDir * dt * 1.35;
            if (simple.cannonAim >= 1) {
                simple.cannonAim = 1;
                simple.cannonDir = -1;
            } else if (simple.cannonAim <= -1) {
                simple.cannonAim = -1;
                simple.cannonDir = 1;
            }

            const target = document.getElementById('temple-cannon-target');
            if (target) target.style.left = `${50 + simple.cannonAim * 34}%`;
            const meter = document.getElementById('temple-cannon-meter-fill');
            if (meter) meter.style.transform = `translateX(${(simple.cannonAim + 1) * 370}%)`;

            this.loopId = requestAnimationFrame(tick);
        };
        this.loopId = requestAnimationFrame(tick);
    },

    addMiniGameScore(points, statusId, text) {
        this.score = Math.max(0, this.score + points);
        document.getElementById('minigame-score').innerText = this.score;
        const status = document.getElementById(statusId);
        if (status) status.innerText = text;
        if (points > 0) {
            triggerPurchaseChime();
        } else {
            triggerSadRentSFX();
        }
    },

    spinWheel() {
        if (!this.gameActive || this.activeGame !== 'wheel') return;
        const wedges = [
            { label: 'Coin shower! +4', points: 4 },
            { label: 'Gem sparkle! +6', points: 6 },
            { label: 'Lucky star! +8', points: 8 },
            { label: 'Grand wedge! +12', points: 12 },
            { label: 'Soft bump. +2', points: 2 }
        ];
        const result = wedges[Math.floor(Math.random() * wedges.length)];
        this.simpleGameState.wheelRotation += 540 + Math.floor(Math.random() * 360);
        const wheel = document.getElementById('fortune-wheel-disc');
        if (wheel) wheel.style.transform = `rotate(${this.simpleGameState.wheelRotation}deg)`;
        this.addMiniGameScore(result.points, 'wheel-result-text', result.label);
    },

    digTreasure(tile) {
        if (!this.gameActive || this.activeGame !== 'treasure' || !tile || tile.disabled) return;
        const index = tile.getAttribute('data-dig');
        if (this.simpleGameState.treasureDug.has(index)) return;
        this.simpleGameState.treasureDug.add(index);
        tile.disabled = true;
        tile.classList.add('dug');

        const roll = Math.random();
        let points = 3;
        let symbol = '🐚';
        let message = 'Shell charm! +3';
        if (roll > 0.78) {
            points = 10;
            symbol = '💎';
            message = 'Rare gem cache! +10';
        } else if (roll > 0.42) {
            points = 5;
            symbol = '🏺';
            message = 'Ancient souvenir! +5';
        } else if (roll < 0.16) {
            points = -2;
            symbol = '🪨';
            message = 'Just a warm rock. -2';
        }
        tile.innerText = symbol;
        this.addMiniGameScore(points, 'treasure-result-text', message);
    },

    fireTempleCannon() {
        if (!this.gameActive || this.activeGame !== 'cannon') return;
        const accuracy = 1 - Math.min(1, Math.abs(this.simpleGameState.cannonAim));
        let points = 3;
        let message = 'Lantern grazed! +3';
        if (accuracy > 0.86) {
            points = 12;
            message = 'Perfect temple shot! +12';
        } else if (accuracy > 0.56) {
            points = 7;
            message = 'Clean festival hit! +7';
        }
        const target = document.getElementById('temple-cannon-target');
        if (target) {
            target.style.transform = 'translateX(-50%) scale(1.25)';
            setTimeout(() => { target.style.transform = 'translateX(-50%)'; }, 120);
        }
        this.addMiniGameScore(points, 'cannon-result-text', message);
    },

    catchMarketFish(ripple) {
        if (!this.gameActive || this.activeGame !== 'fishing' || !ripple) return;
        const roll = Math.random();
        let points = 3;
        let symbol = '🐟';
        let message = 'Market fish! +3';
        if (roll > 0.82) {
            points = 10;
            symbol = '🦐';
            message = 'Golden river prawn! +10';
        } else if (roll > 0.48) {
            points = 5;
            symbol = '🐠';
            message = 'Colorful lucky fish! +5';
        } else if (roll < 0.18) {
            points = -2;
            symbol = '👢';
            message = 'Old canal boot. -2';
        }
        ripple.innerText = symbol;
        setTimeout(() => { if (this.gameActive) ripple.innerText = '~'; }, 420);
        this.addMiniGameScore(points, 'fishing-result-text', message);
    },

    tapTea() {
        if (!this.gameActive || this.activeGame !== 'tea') return;

        // Bouncy cup physical animation
        const cup = document.querySelector('.tea-cup-container');
        if (cup) {
            cup.classList.remove('shake-cup');
            void cup.offsetWidth; // Reflow
            cup.classList.add('shake-cup');
        }

        this.combo++;
        let mult = 1;
        let alertText = "";
        if (this.combo >= 25) {
            mult = 5;
            alertText = "🔥 ULTRA FLAMING TEA!!! 🔥";
        } else if (this.combo >= 15) {
            mult = 3;
            alertText = "✨ SUPER COMBO!!!";
        } else if (this.combo >= 5) {
            mult = 2;
            alertText = "🥤 COMBO x2!";
        }

        this.score += mult;
        document.getElementById('minigame-score').innerText = this.score;
        document.getElementById('tea-combo-alert').innerText = alertText;

        // Increase visual fluid height
        const fluid = document.getElementById('tea-fluid');
        if (fluid) {
            fluid.style.height = Math.min(100, this.score * 1.5) + '%';
        }

        // Spawn tapioca pearls inside the glass cup
        const bubbleContainer = document.getElementById('tea-bubbles-container');
        if (bubbleContainer) {
            const bubble = document.createElement('div');
            bubble.className = 'tapioca-bubble';
            bubble.style.left = (15 + Math.random() * 70) + '%';
            
            // Random landing height near the bottom curve
            const settleY = 122 + (Math.random() - 0.5) * 20;
            bubble.style.setProperty('--settle-y', settleY + 'px');
            bubbleContainer.appendChild(bubble);
        }

        triggerTeaPourSFX();
    },

    initTukTukGame() {
        const state = this.tuktukState;
        state.currentLane = 1;
        state.player = { x: 135, y: 145, width: 28, height: 42, targetX: 135 };
        state.entities = [];
        state.spawnTimer = 0;
        state.roadScroll = 0;

        const canvas = document.getElementById('tuktuk-game-canvas');
        const ctx = canvas.getContext('2d');

        let lastTime = performance.now();

        const tick = (now) => {
            if (!this.gameActive || this.activeGame !== 'tuktuk') return;

            let dt = (now - lastTime) / 1000;
            if (dt > 0.1) dt = 0.1;
            lastTime = now;

            this.updateTukTuk(dt);
            this.renderTukTuk(ctx, canvas);

            this.loopId = requestAnimationFrame(tick);
        };

        this.loopId = requestAnimationFrame(tick);
    },

    steerTukTuk(dir) {
        if (!this.gameActive || this.activeGame !== 'tuktuk') return;
        const state = this.tuktukState;
        state.currentLane = Math.max(0, Math.min(2, state.currentLane + dir));
        triggerTukTukDriftSFX();
    },

    updateTukTuk(dt) {
        const state = this.tuktukState;
        
        state.roadScroll = (state.roadScroll + state.roadSpeed * dt) % 40;

        // Interpolate player X
        state.player.targetX = state.lanes[state.currentLane];
        state.player.x += (state.player.targetX - state.player.x) * 16 * dt;

        // Spawn entities
        state.spawnTimer += dt;
        if (state.spawnTimer > 0.85) {
            state.spawnTimer = 0;
            
            const type = Math.random() < 0.65 ? 'coin' : 'obstacle';
            const lane = Math.floor(Math.random() * 3);
            const x = state.lanes[lane];
            const y = -30;
            
            state.entities.push({
                type: type,
                lane: lane,
                x: x,
                y: y,
                width: type === 'coin' ? 18 : 26,
                height: type === 'coin' ? 18 : 32,
                speed: 190 + Math.random() * 40,
                obstacleType: Math.random() < 0.5 ? 'buffalo' : 'truck',
                collected: false,
                crashed: false
            });
        }

        // Bounding collision updates
        state.entities.forEach(entity => {
            entity.y += entity.speed * dt;

            const px = state.player.x;
            const py = state.player.y;
            const pw = state.player.width;
            const ph = state.player.height;
            const ex = entity.x;
            const ey = entity.y;
            const ew = entity.width;
            const eh = entity.height;

            if (!entity.collected && !entity.crashed) {
                if (px - pw/2 < ex + ew/2 &&
                    px + pw/2 > ex - ew/2 &&
                    py < ey + eh &&
                    py + ph > ey) {
                    
                    if (entity.type === 'coin') {
                        entity.collected = true;
                        this.score += 2;
                        document.getElementById('minigame-score').innerText = this.score;
                        triggerPurchaseChime(); // coin chime
                    } else {
                        entity.crashed = true;
                        this.score = Math.max(0, this.score - 4);
                        document.getElementById('minigame-score').innerText = this.score;
                        triggerSadRentSFX(); // crash chime
                        
                        // shake canvas effect
                        const canvas = document.getElementById('tuktuk-game-canvas');
                        if (canvas) {
                            canvas.style.transform = 'translate(4px, 2px) rotate(1deg)';
                            setTimeout(() => canvas.style.transform = '', 120);
                        }
                    }
                }
            }
        });

        state.entities = state.entities.filter(e => e.y < 220 && !e.collected && !e.crashed);
    },

    renderTukTuk(ctx, canvas) {
        const state = this.tuktukState;

        // Draw asphalt road
        ctx.fillStyle = '#475569';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw highway borders
        ctx.fillStyle = '#fbbf24';
        ctx.fillRect(15, 0, 4, canvas.height);
        ctx.fillRect(281, 0, 4, canvas.height);

        // Draw road dashes
        ctx.fillStyle = '#ffffff';
        const dashHeight = 15;
        const dashGap = 25;
        const dividerX1 = 100;
        const dividerX2 = 200;

        for (let y = -40 + state.roadScroll; y < canvas.height; y += dashHeight + dashGap) {
            ctx.fillRect(dividerX1 - 1.5, y, 3, dashHeight);
            ctx.fillRect(dividerX2 - 1.5, y, 3, dashHeight);
        }

        // Draw grass sidewalks
        ctx.fillStyle = '#86efac';
        ctx.fillRect(0, 0, 15, canvas.height);
        ctx.fillRect(285, 0, 15, canvas.height);

        // Draw oncoming objects
        state.entities.forEach(entity => {
            if (entity.type === 'coin') {
                ctx.fillStyle = '#fef08a';
                ctx.strokeStyle = '#ea580c';
                ctx.lineWidth = 2;
                
                ctx.beginPath();
                ctx.arc(entity.x, entity.y + 9, 8, 0, Math.PI * 2);
                ctx.fill();
                ctx.stroke();
                
                ctx.fillStyle = '#ffffff';
                ctx.font = "8px Arial";
                ctx.fillText("★", entity.x - 3, entity.y + 11);
            } else {
                ctx.font = "24px Arial";
                if (entity.obstacleType === 'buffalo') {
                    ctx.fillText("🐃", entity.x - 12, entity.y + 14);
                } else {
                    ctx.fillText("🚚", entity.x - 12, entity.y + 14);
                }
            }
        });

        // Draw Player Tuk Tuk (blocky blue and yellow vector design)
        const p = state.player;
        ctx.save();
        ctx.translate(p.x, p.y + 20);

        ctx.fillStyle = '#1e293b'; // wheels
        ctx.fillRect(-15, -10, 6, 12);
        ctx.fillRect(9, -10, 6, 12);
        ctx.fillRect(-2, -36, 4, 10);

        ctx.fillStyle = '#3b82f6'; // body chassis
        ctx.fillRect(-12, -26, 24, 24);

        ctx.fillStyle = '#93c5fd'; // windshield glass
        ctx.fillRect(-10, -22, 20, 8);

        ctx.fillStyle = '#fef08a'; // sweet yellow canopy
        ctx.fillRect(-14, -12, 28, 12);
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(-14, -14, 28, 2);

        ctx.fillStyle = '#fef08a'; // yellow headlights
        ctx.beginPath();
        ctx.arc(-8, -25, 3, 0, Math.PI * 2);
        ctx.arc(8, -25, 3, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
    },

    endGame() {
        if (this.status !== 'playing' || !isTurnContextCurrent(this.turnContext)) return;
        this.status = 'results';
        this.gameActive = false;
        clearInterval(this.timerInterval);
        this.timerInterval = null;
        if (this.loopId) cancelAnimationFrame(this.loopId);
        this.loopId = null;

        this.showSubview('minigame-results-view');

        const reward = this.score * 5;
        const isThai = state.lang === 'th';

        if (this.turnContext.playerIndex === 0) {
            updateMissionProgress('play_minigame', 1);
            if (this.activeGame === 'tea') {
                updateMissionProgress('score_tea_rush', this.score);
            } else if (this.activeGame === 'tuktuk') {
                updateMissionProgress('score_tuktuk_drift', this.score);
            } else {
                const meta = PARTY_MINIGAMES[this.activeGame];
                if (meta && meta.scoreType) {
                    updateMissionProgress(meta.scoreType, this.score);
                }
            }
            if (this.score >= 15) {
                updateMissionProgress('win_minigame', 1);
            }
        }
        
        // Translate results screen header
        const resultsTitle = document.querySelector('#minigame-results-view h3');
        if (resultsTitle) {
            resultsTitle.innerText = isThai ? "ท้าทายสำเร็จ!" : "CHALLENGE COMPLETE!";
        }
        
        // Translate claim button
        const claimBtn = document.getElementById('btn-claim-minigame');
        if (claimBtn) {
            claimBtn.innerText = isThai ? "ดำเนินการต่อ" : "Continue";
        }

        // Translate results text paragraph
        const resultText = document.getElementById('minigame-result-text');
        if (resultText) {
            if (isThai) {
                resultText.innerHTML = `คุณทำคะแนนได้ <span id="minigame-final-score" style="color: var(--pastel-yellow); -webkit-text-stroke: 1.5px var(--border-dark); font-size: 1.4rem;">${this.score}</span> คะแนน!<br>ได้รับเหรียญรางวัล <span id="minigame-reward-text" style="color: var(--pastel-green); -webkit-text-stroke: 1.5px var(--border-dark); font-size: 1.4rem;">💰 +${reward} เหรียญ!</span>`;
            } else {
                resultText.innerHTML = `You scored <span id="minigame-final-score" style="color: var(--pastel-yellow); -webkit-text-stroke: 1.5px var(--border-dark); font-size: 1.4rem;">${this.score}</span> points!<br>Earned <span id="minigame-reward-text" style="color: var(--pastel-green); -webkit-text-stroke: 1.5px var(--border-dark); font-size: 1.4rem;">💰 +${reward} Coins!</span>`;
            }
        } else {
            // Fallback
            document.getElementById('minigame-final-score').innerText = this.score;
            document.getElementById('minigame-reward-text').innerHTML = `💰 +${reward} Coins!`;
        }

        // Payout exactly once to the player who opened this session.
        if (!this.rewardApplied) {
            const player = state.players[this.turnContext.playerIndex];
            player.coins += reward;
            player.stats.totalCoinsEarned += reward;
            player.stats.festivalBonusCoins += reward;
            this.rewardApplied = true;
        }

        triggerMiniGameVictoryJingle();
        triggerConfettiBurst();
    },

    claimReward() {
        if (this.status !== 'results' || this.callbackClaimed ||
            !isTurnContextCurrent(this.turnContext)) return;
        consumeLandingAction('minigame');
        this.callbackClaimed = true;
        this.status = 'idle';
        hideModal('minigame-modal');
        updateCoinsHUD();
        const callback = this.callback;
        this.callback = null;
        if (callback) {
            callback();
        }
    },

    cancel() {
        if (this.timerInterval) clearInterval(this.timerInterval);
        if (this.countdownInterval) clearInterval(this.countdownInterval);
        if (this.loopId) cancelAnimationFrame(this.loopId);
        this.timerInterval = null;
        this.countdownInterval = null;
        this.loopId = null;
        this.gameActive = false;
        this.callback = null;
        this.turnContext = null;
        this.status = 'idle';
    }
};

window.CozyMiniGameManager = MiniGameManager;

// ==========================================
// CUTE MINI-GAME WEB AUDIO SYNTH EFFECTS
// ==========================================
function triggerMiniGameCountdownBeep(number) {
    if (!state.audio.sfxEnabled || !audioCtx) return;
    const time = audioCtx.currentTime;
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    
    osc.type = 'sine';
    let freq = 440; // 3: A4
    if (number === 2) freq = 554.37; // 2: C#5
    if (number === 1) freq = 659.25; // 1: E5
    if (number === 'GO') freq = 880; // GO: A5
    
    osc.frequency.setValueAtTime(freq, time);
    gain.gain.setValueAtTime(0.04, time);
    gain.gain.exponentialRampToValueAtTime(0.0001, time + 0.35);
    
    osc.connect(gain);
    gain.connect(audioCtx.destination);
    
    osc.start(time);
    osc.stop(time + 0.35);
}

function triggerTeaPourSFX() {
    if (!state.audio.sfxEnabled || !audioCtx) return;
    const time = audioCtx.currentTime;
    
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    
    osc.type = 'sine';
    osc.frequency.setValueAtTime(150 + Math.random() * 80, time);
    osc.frequency.exponentialRampToValueAtTime(800 + Math.random() * 150, time + 0.1);
    
    gain.gain.setValueAtTime(0.03, time);
    gain.gain.exponentialRampToValueAtTime(0.0001, time + 0.12);
    
    osc.connect(gain);
    gain.connect(audioCtx.destination);
    
    osc.start(time);
    osc.stop(time + 0.12);
}

function triggerTukTukDriftSFX() {
    if (!state.audio.sfxEnabled || !audioCtx) return;
    const time = audioCtx.currentTime;
    
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(120, time);
    osc.frequency.linearRampToValueAtTime(260, time + 0.12);
    
    gain.gain.setValueAtTime(0.015, time);
    gain.gain.exponentialRampToValueAtTime(0.0001, time + 0.15);
    
    osc.connect(gain);
    gain.connect(audioCtx.destination);
    
    osc.start(time);
    osc.stop(time + 0.15);
}

function triggerMiniGameVictoryJingle() {
    if (!state.audio.sfxEnabled || !audioCtx) return;
    const time = audioCtx.currentTime;
    
    const notes = [523.25, 659.25, 783.99, 1046.50]; // C5 - E5 - G5 - C6 Arpeggio
    notes.forEach((freq, idx) => {
        const noteTime = time + idx * 0.08;
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();
        
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(freq, noteTime);
        gain.gain.setValueAtTime(0.03, noteTime);
        gain.gain.exponentialRampToValueAtTime(0.0001, noteTime + 0.35);
        
        osc.connect(gain);
        gain.connect(audioCtx.destination);
        
        osc.start(noteTime);
        osc.stop(noteTime + 0.35);
    });
}


