// --- DYNAMIC BOARD ENVIRONMENT LAUNCHER SYSTEMS ---
function createLocalTilePattern() {
    const patternCanvas = document.createElement('canvas');
    patternCanvas.width = 128;
    patternCanvas.height = 128;
    const ctx = patternCanvas.getContext('2d');
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, 128, 128);
    ctx.strokeStyle = 'rgba(0, 0, 0, 0.12)';
    ctx.lineWidth = 6;
    ctx.strokeRect(8, 8, 112, 112);
    ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
    [[20, 20], [108, 20], [20, 108], [108, 108]].forEach(pos => {
        ctx.beginPath();
        ctx.arc(pos[0], pos[1], 4, 0, Math.PI * 2);
        ctx.fill();
    });
    return new THREE.CanvasTexture(patternCanvas);
}

function cleanupBoard() {
    boardEnvironmentMeshes.forEach(mesh => {
        scene.remove(mesh);
        mesh.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
                if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                else child.material.dispose();
            }
        });
    });
    boardEnvironmentMeshes = [];
    
    if (tilesGroup) {
        scene.remove(tilesGroup);
        tilesGroup.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material && child.material.dispose) child.material.dispose();
        });
        tilesGroup = null;
    }
    
    skyLanterns.forEach(l => {
        if (l.group) scene.remove(l.group);
        if (l.mesh) scene.remove(l.mesh);
    });
    skyLanterns = [];
    
    krathongs.forEach(k => {
        if (k.mesh) scene.remove(k.mesh);
    });
    krathongs = [];
    
    wanderingNPCs.forEach(n => {
        if (n.mesh) {
            scene.remove(n.mesh);
            if (n.mesh.geometry) n.mesh.geometry.dispose();
            if (n.mesh.material && n.mesh.material.dispose) n.mesh.material.dispose();
        }
        if (n.group) {
            scene.remove(n.group);
            n.group.traverse(child => {
                if (child.geometry) child.geometry.dispose();
                if (child.material) {
                    if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                    else if (child.material.dispose) child.material.dispose();
                }
            });
        }
    });
    wanderingNPCs = [];
    
    swayingElements = { trees: [], signs: [] };
    drivingTukTuk = null;
    btsTrainGroup = null;

    if (skyNagaModel) {
        scene.remove(skyNagaModel);
        skyNagaModel.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
                if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                else child.material.dispose();
            }
        });
        skyNagaModel = null;
    }
    skyNagaMixer = null;

    if (guardianNagaModel) {
        scene.remove(guardianNagaModel);
        guardianNagaModel.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
                if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                else child.material.dispose();
            }
        });
        guardianNagaModel = null;
    }
    guardianNagaMixer = null;
}

function loadBoardTheme(themeId, isFirstLoad = false) {
    if (!boardConfigurations[themeId]) return;
    state.currentMap = themeId;
    const config = boardConfigurations[themeId];
    
    if (!isFirstLoad) {
        cleanupBoard();
    }
    
    tilesData = config.tiles;
    state.board = tilesData;
    
    // Dynamic Economic Rebalancing at Runtime for all map properties and START tile descriptions
    state.board.forEach(tile => {
        if (tile.type === 'property') {
            // Upgrade Price: exactly 85% of base purchase price to make it a strategic capital decision!
            tile.upgradePrice = Math.round(tile.price * 0.85);
            // Base Rent: exactly 20% of base purchase price to scale smoothly
            tile.rent = Math.round(tile.price * 0.20);
        }
        if (tile.type === 'start') {
            tile.desc = state.lang === 'th' ? "ได้รับโบนัส 300 เหรียญเมื่อแลนดิ้ง!" : "Collect 300 Coins when landing!";
        }
    });
    
    boardCoordinates = [];
    
    const L = tilesData.length;
    const S = L / 4; // Side length (e.g., 4 for 16 tiles, 6 for 24 tiles)
    const d = 4.0;
    const halfWidth = S * d / 2; // e.g., 8 for 16 tiles, 12 for 24 tiles
    
    for (let i = 0; i < S; i++) {
        const baseHeight = (i === 0) ? 0.08 : -0.05;
        boardCoordinates.push(new THREE.Vector3(-halfWidth + i * d, baseHeight + 0.2, halfWidth));
    }
    for (let i = 0; i < S; i++) {
        const baseHeight = (i === 0) ? 0.08 : -0.05;
        boardCoordinates.push(new THREE.Vector3(halfWidth, baseHeight + 0.2, halfWidth - i * d));
    }
    for (let i = 0; i < S; i++) {
        const baseHeight = (i === 0) ? 0.08 : -0.05;
        boardCoordinates.push(new THREE.Vector3(halfWidth - i * d, baseHeight + 0.2, -halfWidth));
    }
    for (let i = 0; i < S; i++) {
        const baseHeight = (i === 0) ? 0.08 : -0.05;
        boardCoordinates.push(new THREE.Vector3(-halfWidth, baseHeight + 0.2, -halfWidth + i * d));
    }
    
    if (scene) {
        scene.background = new THREE.Color(config.skyColor);
        if (scene.fog) {
            scene.fog.color = new THREE.Color(config.fogColor || config.skyColor);
        }
    }
    
    const bottomBaseWidth = 2 * halfWidth + 8.2;
    const bottomBaseGeo = new THREE.BoxGeometry(bottomBaseWidth, 0.8, bottomBaseWidth);
    const bottomBaseMat = new THREE.MeshStandardMaterial({
        color: config.baseColor,
        roughness: 0.22,
        metalness: 0.08
    });
    bottomBaseMesh = new THREE.Mesh(bottomBaseGeo, bottomBaseMat);
    bottomBaseMesh.position.y = -1.2;
    bottomBaseMesh.receiveShadow = true;
    scene.add(bottomBaseMesh);
    boardEnvironmentMeshes.push(bottomBaseMesh);
    applyOutlineRecursive(bottomBaseMesh, 0.015);
    
    const islandWidth = 2 * halfWidth + 5.8;
    islandMesh = new THREE.Mesh(new THREE.BoxGeometry(islandWidth, 0.8, islandWidth), new THREE.MeshStandardMaterial({
        color: config.islandColor,
        roughness: 0.25,
        metalness: 0.08
    }));
    islandMesh.position.y = -0.4;
    islandMesh.receiveShadow = true;
    scene.add(islandMesh);
    boardEnvironmentMeshes.push(islandMesh);
    applyOutlineRecursive(islandMesh, 0.015);
    
    const grassWidth = 2 * halfWidth + 5.6;
    const islandGrass = new THREE.Mesh(new THREE.PlaneGeometry(grassWidth, grassWidth), new THREE.MeshStandardMaterial({
        map: grassTexture,
        roughness: 0.9,
        metalness: 0.02
    }));
    islandGrass.rotation.x = -Math.PI / 2;
    islandGrass.position.set(0, 0.405, 0);
    islandGrass.receiveShadow = true;
    islandMesh.add(islandGrass);
    
    tilesGroup = new THREE.Group();
    scene.add(tilesGroup);
    
    const tileGeo = createRoundedBoxGeometry(3.6, 0.4, 3.6, 0.16, 8);
    const tilePattern = createLocalTilePattern();
    
    tilesData.forEach((tileInfo, idx) => {
        const coords = boardCoordinates[idx];
        const tileMat = new THREE.MeshStandardMaterial({
            map: tilePattern,
            color: tileInfo.color,
            roughness: 0.22,
            metalness: 0.08
        });
        
        const tileMesh = new THREE.Mesh(tileGeo, tileMat);
        const isCorner = idx % S === 0;
        const baseHeight = isCorner ? 0.08 : -0.05;
        
        tileMesh.position.set(coords.x, baseHeight, coords.z);
        tileMesh.receiveShadow = true;
        tileMesh.castShadow = true;
        tilesGroup.add(tileMesh);
        applyOutlineRecursive(tileMesh, 0.04);
        
        tileInfo.mesh = tileMesh;
        tileInfo.coords = coords.clone();
        tileInfo.owner = null;
        tileInfo.level = 0;
        tileInfo.buildingMesh = null;
        tileInfo.landmarkMesh = null;
        tileInfo.bounceTimer = 0.0;
        tileInfo.glowIntensity = 0.0;
        tileInfo.isPathHighlight = false;
        
        const shadowMat = new THREE.MeshBasicMaterial({
            color: 0x3d2b1f,
            transparent: true,
            opacity: 0.26,
            depthWrite: false
        });
        const tileShadow = new THREE.Mesh(new THREE.PlaneGeometry(3.85, 3.85), shadowMat);
        tileShadow.rotation.x = -Math.PI / 2;
        tileShadow.position.y = -0.21;
        tileMesh.add(tileShadow);
        
        const sidewalk = new THREE.Mesh(new THREE.BoxGeometry(3.85, 0.24, 3.85), new THREE.MeshStandardMaterial({ color: 0xfffef0, roughness: 0.25 }));
        sidewalk.position.y = -0.15;
        tileMesh.add(sidewalk);
        tileInfo.sidewalkMesh = sidewalk;
        
        createMiniatureLandmark(idx, tileMesh);
    });
    
    if (themeId === 'bangkok') {
        createCentralParkAndCanal();
        createLampPosts();
        createCenterDecorations();
    } else if (themeId === 'phuket') {
        createPhuketEnvironment();
        createLampPosts();
    } else if (themeId === 'chiangmai') {
        createChiangMaiEnvironment();
        createLampPosts();
    } else if (themeId === 'ayutthaya') {
        createAyutthayaEnvironment();
        createLampPosts();
    } else if (themeId === 'songkran') {
        createSongkranEnvironment();
        createLampPosts();
    } else if (themeId === 'floating') {
        createFloatingMarketEnvironment();
        createLampPosts();
    }

    // Generate the immersive background diorama scenery surrounding the board
    createBackgroundScenery(themeId);
    
    state.players.forEach((p, idx) => {
        if (p.mesh) {
            const offset = getPlayerOffset(idx);
            p.mesh.position.set(
                boardCoordinates[0].x + offset.x,
                boardCoordinates[0].y,
                boardCoordinates[0].z + offset.z
            );
            p.mesh.rotation.set(0, 0, 0);
            p.mesh.scale.set(1, 1, 1);
            p.position = 0;
            applyPlayerCosmetics(p.mesh, p.id === 'player');
        }
    });
    
    activeChordWaveType = config.chordType || 'triangle';
    chordProgression = config.chords;
    melodyProgression = config.melodies;
    updateMusicTempo(config.tempo);
    
    updateOwnedPropertiesGrid();
    updateCoinsHUD();

    // Spawn Giant Sky Naga & Board Guardian Naga ambient mascots!
    spawnSkyNaga();
    spawnGuardianNaga();

    // Disable village hub and restore match mesh visibility
    window.villageHubActive = false;
    if (typeof setMatchMeshesVisible === 'function') {
        setMatchMeshesVisible(true);
    }
}

function spawnSkyNaga() {
    // 1. Cleanup old Naga mesh
    if (skyNagaModel) {
        scene.remove(skyNagaModel);
        skyNagaModel.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
                if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                else child.material.dispose();
            }
        });
        skyNagaModel = null;
    }
    skyNagaMixer = null;

    // 2. Fetch loaded GLTF landmark naga
    const model = loadedModels.landmarks['giant_sky_naga'];
    if (!model) {
        console.warn("Giant Sky Naga model not loaded yet, skipping ambient spawn.");
        return;
    }

    // 3. Clone and configure mascot mesh
    skyNagaModel = model.clone();
    skyNagaModel.scale.set(1.4, 1.4, 1.4);
    
    // Enable shadows on all child elements
    skyNagaModel.traverse(child => {
        if (child.isMesh) {
            child.castShadow = true;
            child.receiveShadow = true;
        }
    });

    scene.add(skyNagaModel);

    // 4. Setup Animation Mixer
    if (model.animations && model.animations.length > 0) {
        skyNagaMixer = new THREE.AnimationMixer(skyNagaModel);
        const action = skyNagaMixer.clipAction(model.animations[0]);
        action.play();
    }
    if (state.debugModeActive) console.debug("Giant Sky Naga ambient mascot spawned successfully in the sky.");
}

function spawnGuardianNaga() {
    // 1. Cleanup old Naga mesh
    if (guardianNagaModel) {
        scene.remove(guardianNagaModel);
        guardianNagaModel.traverse(child => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
                if (Array.isArray(child.material)) child.material.forEach(m => m.dispose());
                else child.material.dispose();
            }
        });
        guardianNagaModel = null;
    }
    guardianNagaMixer = null;

    // 2. Fetch loaded GLTF landmark naga
    const model = loadedModels.landmarks['board_guardian_naga'];
    if (!model) {
        console.warn("Giant Board Guardian Naga model not loaded yet, skipping ambient spawn.");
        return;
    }

    // 3. Clone and configure mascot mesh
    guardianNagaModel = model.clone();
    guardianNagaModel.scale.set(1.5, 1.5, 1.5);
    
    // Enable shadows on all child elements
    guardianNagaModel.traverse(child => {
        if (child.isMesh) {
            child.castShadow = true;
            child.receiveShadow = true;
        }
    });

    scene.add(guardianNagaModel);

    // 4. Setup Animation Mixer for Swim_Loop & Idle_Head simultaneously!
    if (model.animations && model.animations.length > 0) {
        guardianNagaMixer = new THREE.AnimationMixer(guardianNagaModel);
        
        let swimClip = model.animations.find(clip => clip.name === "Swim_Loop");
        if (swimClip) {
            const action = guardianNagaMixer.clipAction(swimClip);
            action.setEffectiveWeight(1.0);
            action.play();
        }
        
        let idleClip = model.animations.find(clip => clip.name === "Idle_Head");
        if (idleClip) {
            const action = guardianNagaMixer.clipAction(idleClip);
            action.setEffectiveWeight(0.85); // Blend smoothly!
            action.play();
        }
    }

    // 5. Build the smooth closed spline path loop around the board perimeter
    const points = [];
    const numPoints = 8;
    const baseRadius = 17.5;
    for (let i = 0; i < numPoints; i++) {
        const theta = (i / numPoints) * Math.PI * 2;
        // Introduce sweet wavy variations in the spline for natural curves
        const r = baseRadius + Math.sin(theta * 3) * 1.2;
        const y = 0.22 + Math.cos(theta * 2) * 0.15;
        points.push(new THREE.Vector3(r * Math.cos(theta), y, r * Math.sin(theta)));
    }
    guardianNagaPath = new THREE.CatmullRomCurve3(points, true); // True makes it a closed loop spline!

    if (state.debugModeActive) console.debug("Giant Board Guardian Naga ambient mascot spawned successfully.");
}

function triggerNagaGlance(targetPos) {
    if (!targetPos) return;
    nagaGlanceTimer = 3.2; // Glance for 3.2 seconds
    nagaGlanceTarget.copy(targetPos);
}

function updateMusicTempo(newTempo) {
    startMusicTimer(newTempo);
}

function createPhuketEnvironment() {
    const lagoon = new THREE.Mesh(new THREE.BoxGeometry(12, 0.1, 12), new THREE.MeshStandardMaterial({ color: 0x0ea5e9, roughness: 0.15, metalness: 0.2 }));
    lagoon.position.set(0, -0.38, 0);
    scene.add(lagoon);
    boardEnvironmentMeshes.push(lagoon);
    applyOutlineRecursive(lagoon, 0.015);
    
    const shore = new THREE.Mesh(new THREE.BoxGeometry(13, 0.18, 13), new THREE.MeshStandardMaterial({ color: 0xfef08a, roughness: 0.7 }));
    shore.position.set(0, -0.4, 0);
    scene.add(shore);
    boardEnvironmentMeshes.push(shore);
    applyOutlineRecursive(shore, 0.015);

    const palmPositions = [
        new THREE.Vector3(-4, 0.4, -4),
        new THREE.Vector3(4, 0.4, -4),
        new THREE.Vector3(4, 0.4, 4),
        new THREE.Vector3(-4, 0.4, 4),
    ];
    palmPositions.forEach(pos => {
        const palm = new THREE.Group();
        palm.position.copy(pos);
        
        const trunkMat = new THREE.MeshStandardMaterial({ color: 0x854d0e, roughness: 0.8 });
        const leafMat = new THREE.MeshStandardMaterial({ color: 0x10b981, roughness: 0.9 });
        
        for (let i = 0; i < 5; i++) {
            const segment = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.1, 0.4), trunkMat);
            segment.position.y = 0.2 + i * 0.35;
            segment.rotation.z = 0.1 * i;
            palm.add(segment);
        }
        
        for (let i = 0; i < 5; i++) {
            const leaf = new THREE.Mesh(new THREE.BoxGeometry(1.2, 0.04, 0.3), leafMat);
            leaf.position.set(0, 1.8, 0);
            leaf.rotation.y = (i * Math.PI * 2) / 5;
            leaf.rotation.z = 0.2;
            palm.add(leaf);
        }
        
        applyOutlineRecursive(palm, 0.03);
        scene.add(palm);
        boardEnvironmentMeshes.push(palm);
    });

    const yachtGroup = new THREE.Group();
    yachtGroup.position.set(0, -0.32, 0);
    
    const hull = new THREE.Mesh(new THREE.BoxGeometry(1.2, 0.3, 2.4), new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.2 }));
    yachtGroup.add(hull);
    
    const sail = new THREE.Mesh(new THREE.ConeGeometry(0.1, 1.6, 3), new THREE.MeshStandardMaterial({ color: 0xff3366, roughness: 0.8 }));
    sail.position.set(0, 0.9, -0.2);
    yachtGroup.add(sail);
    
    applyOutlineRecursive(yachtGroup, 0.03);
    scene.add(yachtGroup);
    boardEnvironmentMeshes.push(yachtGroup);

    drivingTukTuk = yachtGroup;
}

