        { id: 'rare', name: isThai ? 'หีบหายาก 💎' : 'Rare Chest 💎', emoji: '💎', cost: 600, desc: isThai ? 'เหรียญ, XP, ชาร์ดหายาก, ลุ้นเต๋า' : 'Coins, XP, Rare Shards, Dice' },
        { id: 'epic', name: isThai ? 'หีบอีปิค 🔮' : 'Epic Chest 🔮', emoji: '🔮', cost: 1200, desc: isThai ? 'รางวัลระดับสูง, ชาร์ดอีปิค, ลุ้นเต๋าทอง' : 'High Drops, Epic Shards, Gold Dice' },
        { id: 'legendary', name: isThai ? 'หีบในตำนาน 👑' : 'Legendary Chest 👑', emoji: '👑', cost: 2500, desc: isThai ? 'ในตำนาน! ชาร์ดกินรีทอง, โอกาสเต๋าสงกรานต์' : 'Legendary! Kinnaree Shards, Songkran Dice' }
