    applyOutlineRecursive(lhBase, 0.02);

    const tower = new THREE.Mesh(new THREE.CylinderGeometry(0.42, 0.58, 2.2, 6), new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.4 }));
