    lhGroup.add(stripe2);

    const lightRoom = new THREE.Mesh(new THREE.CylinderGeometry(0.34, 0.34, 0.4, 6), new THREE.MeshStandardMaterial({ color: 0x334155, metalness: 0.5 }));
    lightRoom.position.y = 2.5;
    lhGroup.add(lightRoom);

    const glass = new THREE.Mesh(new THREE.CylinderGeometry(0.3, 0.3, 0.3, 6), new THREE.MeshBasicMaterial({ color: 0xfef08a, transparent: true, opacity: 0.7 }));
