    applyOutlineRecursive(dome, 0.02);

    // Rotating Spotlight beam cone!
    const lightCone = new THREE.Mesh(
        new THREE.ConeGeometry(1.2, 5.0, 8),
        new THREE.MeshBasicMaterial({
            color: 0xfef08a,
            transparent: true,
            opacity: 0.34,
            depthWrite: false,
            blending: THREE.AdditiveBlending
        })
    );
    lightCone.rotation.x = Math.PI / 2;
