function checkMissionsRollover() {
    if (!state.progression.missions) {
        state.progression.missions = { active: [], chestClaimed: false, lastRolloverDate: "" };
    }
    
    const today = new Date().toDateString();
    const missions = state.progression.missions;
    
    if (missions.lastRolloverDate !== today || !missions.active || missions.active.length === 0) {
        const selectedTemplates = [];
        const templatesCopy = [...missionTemplates];
        
        for (let i = 0; i < 3; i++) {
            if (templatesCopy.length === 0) break;
            const randIdx = Math.floor(Math.random() * templatesCopy.length);
            selectedTemplates.push(templatesCopy.splice(randIdx, 1)[0]);
        }
        
        missions.active = selectedTemplates.map(template => ({
            templateId: template.id,
            progress: 0,
            completed: false,
            claimed: false
        }));
        
        missions.chestClaimed = false;
        missions.lastRolloverDate = today;
        
        saveMissionsState();
    }
}

function saveMissionsState() {
    if (state.progression && state.progression.missions) {
        localStorage.setItem('thailand_daily_missions', JSON.stringify(state.progression.missions));
    }
}

function loadMissionsState() {
    const saved = localStorage.getItem('thailand_daily_missions');
    if (saved) {
        try {
            state.progression.missions = JSON.parse(saved);
        } catch (e) {
            console.error("Failed to parse daily missions state:", e);
            state.progression.missions = { active: [], chestClaimed: false, lastRolloverDate: "" };
        }
    } else {
        state.progression.missions = { active: [], chestClaimed: false, lastRolloverDate: "" };
    }
}

function initMissionsDOM() {
    const btnOpenLobby = document.getElementById('btn-open-missions');
    const btnOpenHUD = document.getElementById('btn-open-missions-hud');
    const btnClose = document.getElementById('btn-close-missions');
    const grandChest = document.getElementById('grand-chest-btn');
    
    if (btnOpenLobby) {
        btnOpenLobby.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(15);
            openMissionsModal();
        });
    }
    
    if (btnOpenHUD) {
        btnOpenHUD.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(15);
            openMissionsModal();
        });
    }
    
    if (btnClose) {
        btnClose.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(12);
            hideModal('missions-modal');
        });
    }
    
    if (grandChest) {
        grandChest.addEventListener('click', (e) => {
            e.stopPropagation();
            claimGrandChestReward();
        });
    }
}

function openMissionsModal() {
    checkMissionsRollover();
    showModal('missions-modal');
    renderMissionsModal();
}

function renderMissionsModal() {
    const isThai = state.lang === 'th';
    
    if (!state.progression.missions || !state.progression.missions.active) {
        checkMissionsRollover();
    }
    
    const missions = state.progression.missions;
    
    const badgeText = document.getElementById('missions-badge-text');
    const titleText = document.getElementById('missions-title-text');
    const grandTitle = document.getElementById('lbl-grand-chest-title');
    const grandDesc = document.getElementById('lbl-grand-chest-desc');
    const resetText = document.getElementById('missions-reset-text');
    
    if (badgeText) badgeText.innerText = isThai ? "ภารกิจประจำวัน 📅" : "DAILY CHALLENGES 📅";
    if (titleText) titleText.innerText = isThai ? "ภารกิจประจำวัน" : "DAILY MISSIONS";
    if (grandTitle) grandTitle.innerText = isThai ? "รางวัลใหญ่ประจำวัน" : "DAILY GRAND PRIZE";
    if (resetText) resetText.innerText = isThai ? "ภารกิจจะรีเซ็ตอัตโนมัติเมื่อเริ่มวันใหม่" : "Missions reset automatically every rollover";
    
    const container = document.getElementById('active-missions-list');
    if (!container) return;
    container.innerHTML = '';
    
    let completedAndClaimedCount = 0;
    
    missions.active.forEach((mission, idx) => {
        const template = missionTemplates.find(t => t.id === mission.templateId);
        if (!template) return;
        
        const card = document.createElement('div');
        card.className = `mission-item-card ${mission.completed ? 'mission-completed' : ''}`;
        
        const progressPct = Math.min(100, (mission.progress / template.target) * 100);
        
        let btnHTML = '';
        if (mission.claimed) {
            completedAndClaimedCount++;
            btnHTML = `
                <div class="mission-claim-stamp">
                    ${isThai ? 'สำเร็จ!' : 'COMPLETED!'}
                </div>
            `;
        } else if (mission.completed) {
            btnHTML = `
                <button class="cute-mini-btn btn-mission-claim" data-idx="${idx}" style="background-color: var(--pastel-mint); border-color: var(--border-dark); color: var(--text-dark); font-weight: 800; padding: 6px 12px; font-size: 0.8rem; box-shadow: 0 3px 0 var(--border-dark); cursor: pointer;">
                    ${isThai ? 'รับรางวัล' : 'CLAIM'}
                </button>
            `;
        } else {
            btnHTML = `
                <button class="cute-mini-btn" style="background-color: #f1ebd9; border-color: #cbd5e1; color: #94a3b8; font-weight: 800; padding: 6px 12px; font-size: 0.8rem; cursor: not-allowed; box-shadow: none;" disabled>
                    ${isThai ? 'กำลังทำ' : 'IN PROGRESS'}
                </button>
            `;
        }
        
        const title = isThai ? template.thDesc : template.desc;
        const rewardLabel = isThai ? 'รางวัล:' : 'Reward:';
        
        card.innerHTML = `
            <div class="mission-card-left">
                <div class="mission-card-title">${title}</div>
                <div class="mission-card-reward">
                    <span>🎁</span>
                    <span>${rewardLabel} 💰 +${template.reward}</span>
                </div>
                <div class="mission-progress-row">
                    <div class="mission-progress-bar-container">
                        <div class="mission-progress-bar-fill" style="width: ${progressPct}%"></div>
                    </div>
                    <div class="mission-progress-text">${mission.progress}/${template.target}</div>
                </div>
            </div>
            ${btnHTML}
        `;
        
        container.appendChild(card);
    });
    
    container.querySelectorAll('.btn-mission-claim').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const idx = parseInt(btn.getAttribute('data-idx'));
            claimMissionReward(idx);
        });
    });
    
    const grandPct = (completedAndClaimedCount / 3) * 100;
    const progressFill = document.getElementById('missions-grand-progress');
    if (progressFill) progressFill.style.width = `${grandPct}%`;
    
    const chestHalo = document.getElementById('grand-chest-halo');
    const chestIcon = document.getElementById('grand-chest-icon');
    
    if (grandDesc) {
        if (completedAndClaimedCount < 3) {
            const remaining = 3 - completedAndClaimedCount;
            grandDesc.innerText = isThai 
                ? `ทำภารกิจที่เหลืออีก ${remaining} ข้อเพื่อปลดล็อกรางวัลใหญ่!` 
                : `Complete ${remaining} more active missions to unlock!`;
        } else {
            grandDesc.innerText = isThai 
                ? "ปลดล็อกสำเร็จแล้ว! คลิกกล่องของขวัญเพื่อรับรางวัลใหญ่!" 
                : "Unlocked! Tap the gift box to claim your Grand Prize!";
        }
    }
    
    if (missions.chestClaimed) {
        if (chestHalo) chestHalo.style.display = 'none';
        if (chestIcon) {
            chestIcon.innerText = '🔓🎁';
            chestIcon.className = 'chest-icon';
            chestIcon.style.transform = 'scale(1)';
        }
        if (grandDesc) grandDesc.innerText = isThai ? "รับรางวัลใหญ่แล้ว! กลับมาพรุ่งนี้เพื่อพบภารกิจใหม่!" : "Grand Prize Claimed! Come back tomorrow for new missions!";
    } else if (completedAndClaimedCount === 3) {
        if (chestHalo) chestHalo.style.display = 'block';
        if (chestIcon) {
            chestIcon.innerText = '🔒🎁';
            chestIcon.className = 'chest-icon chest-unlocked';
        }
    } else {
        if (chestHalo) chestHalo.style.display = 'none';
        if (chestIcon) {
            chestIcon.innerText = '🔒🎁';
            chestIcon.className = 'chest-icon';
            chestIcon.style.transform = 'scale(1)';
        }
    }
}

function updateMissionProgress(type, amount = 1) {
    if (!state.started || state.currentPlayerIndex !== 0) return;
    
    // Piggyback Achievement Progression
    updateAchievementProgress(type, amount);
    
    if (!state.progression.missions || !state.progression.missions.active) return;
    
    let stateChanged = false;
    state.progression.missions.active.forEach((activeMission, idx) => {
        const template = missionTemplates.find(t => t.id === activeMission.templateId);
        if (template && (template.type === type || (type.startsWith('roll_value_') && template.type === type))) {
            if (!activeMission.completed) {
                activeMission.progress = Math.min(template.target, activeMission.progress + amount);
                if (activeMission.progress >= template.target) {
                    activeMission.completed = true;
                    triggerMissionsCompletedReaction(idx);
                }
                stateChanged = true;
            }
        }
    });
    
    if (stateChanged) {
        saveMissionsState();
        if (state.activeModal === 'missions-modal') {
            renderMissionsModal();
        }
    }
}

function triggerMissionsCompletedReaction(idx) {
    if (!state.progression.missions || !state.progression.missions.active) return;
    const mission = state.progression.missions.active[idx];
    const template = missionTemplates.find(t => t.id === mission.templateId);
    if (!template) return;
    
    const isThai = state.lang === 'th';
    const text = isThai ? `🎯 ภารกิจสำเร็จ: ${template.thDesc}! (คลิกดูที่ภารกิจประจำวัน)` : `🎯 Mission Completed: ${template.desc}! (Check Daily Challenges)`;
    triggerAlertLog(text);
    
    if (state.audio.sfxEnabled && audioCtx) {
        try {
            const time = audioCtx.currentTime;
            const freqs = [523.25, 659.25, 783.99, 1046.50];
            freqs.forEach((freq, i) => {
                const noteTime = time + i * 0.08;
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.type = 'triangle';
                osc.frequency.setValueAtTime(freq, noteTime);
                gain.gain.setValueAtTime(0.04 * state.audio.sfxVolume, noteTime);
                gain.gain.exponentialRampToValueAtTime(0.0001, noteTime + 0.3);
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.start(noteTime);
                osc.stop(noteTime + 0.32);
            });
        } catch(e) {}
    }
}

function claimMissionReward(idx) {
    const missions = state.progression.missions;
    if (!missions || !missions.active || !missions.active[idx]) return;
    const mission = missions.active[idx];
    if (!mission.completed || mission.claimed) return;
    
    const template = missionTemplates.find(t => t.id === mission.templateId);
    if (!template) return;
    
    triggerHaptic([30, 50]);
    
    mission.claimed = true;
    
    state.players[0].coins += template.reward;
    state.players[0].stats.totalCoinsEarned += template.reward;
    addXP(100);
    
    saveProgression();
    
    if (state.audio.sfxEnabled && audioCtx) {
        try {
            const time = audioCtx.currentTime;
            const notes = [523.25, 659.25, 783.99, 1046.50];
            notes.forEach((freq, i) => {
                const noteTime = time + i * 0.08;
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.type = 'triangle';
                osc.frequency.setValueAtTime(freq, noteTime);
                gain.gain.setValueAtTime(0.06 * state.audio.sfxVolume, noteTime);
                gain.gain.exponentialRampToValueAtTime(0.0001, noteTime + 0.35);
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.start(noteTime);
                osc.stop(noteTime + 0.4);
            });
        } catch(e) {}
    }
    
    triggerConfettiBurst();
    triggerAlertLog(state.lang === 'th'
        ? `🎁 รับรางวัลภารกิจ! ได้รับ 💰 +${template.reward} เหรียญ และ ⭐ +100 XP!`
        : `🎁 Claimed mission reward! Received 💰 +${template.reward} Coins and ⭐ +100 XP!`
    );
    
    updateCoinsHUD();
    renderMissionsModal();
}

function claimGrandChestReward() {
    const missions = state.progression.missions;
    if (!missions || missions.chestClaimed) return;
    
    const allClaimed = missions.active.every(m => m.claimed);
    if (!allClaimed) {
        triggerLockedBeep();
        triggerAlertLog(state.lang === 'th'
            ? "สะสมของรางวัลประจำวันให้ครบ 3 ข้อเพื่อเปิดกล่องรางวัลใหญ่นี้! 🔒"
            : "Claim all 3 active daily missions to unlock this grand gift box! 🔒"
        );
        return;
    }
    
    triggerHaptic([40, 70, 40]);
    
    missions.chestClaimed = true;
    
    state.players[0].coins += 1000;
    state.players[0].stats.totalCoinsEarned += 1000;
    addXP(500);
    
    saveProgression();
    
    if (state.audio.sfxEnabled && audioCtx) {
        try {
            const time = audioCtx.currentTime;
            const notes = [523.25, 659.25, 783.99, 1046.50, 1318.51, 1567.98, 2093.00];
            notes.forEach((freq, i) => {
                const noteTime = time + i * 0.06;
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.type = 'triangle';
                osc.frequency.setValueAtTime(freq, noteTime);
                gain.gain.setValueAtTime(0.08 * state.audio.sfxVolume, noteTime);
                gain.gain.exponentialRampToValueAtTime(0.0001, noteTime + 0.5);
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.start(noteTime);
                osc.stop(noteTime + 0.65);
            });
        } catch(e) {}
    }
    
    triggerConfettiBurst();
    for (let i = 0; i < 5; i++) {
        setTimeout(() => {
            triggerConfettiBurst();
        }, i * 200);
    }
    
    triggerAlertLog(state.lang === 'th'
        ? "🎉 ยินดีด้วย! คุณเปิดกล่องรางวัลใหญ่ประจำวัน ได้รับ 💰 +1000 เหรียญ และ ⭐ +500 XP! 🏆🎁"
        : "🎉 CONGRATULATIONS! You opened the Daily Grand Prize Chest! Received 💰 +1000 Coins and ⭐ +500 XP! 🏆🎁"
    );
    
    updateCoinsHUD();
    renderMissionsModal();
}

