function updateAchievementProgress(type, amount = 1) {
    if (!state.started || state.currentPlayerIndex !== 0) return;
    if (!state.progression || !state.progression.lifetimeStats) return;
    
    // For high scores, we take the absolute value. For other keys, we increment.
    const isAbsolute = (
        type === 'score_tea_rush' ||
        type === 'score_tuktuk_drift' ||
        type === 'score_wheel_fortune' ||
        type === 'score_treasure_dig' ||
        type === 'score_temple_cannon' ||
        type === 'score_market_fishing'
    );
    
    if (isAbsolute) {
        state.progression.lifetimeStats[type] = Math.max(state.progression.lifetimeStats[type] || 0, amount);
    } else {
        state.progression.lifetimeStats[type] = (state.progression.lifetimeStats[type] || 0) + amount;
    }
    
    const currentVal = state.progression.lifetimeStats[type];
    let saveNeeded = false;
    
    achievementTemplates.forEach(ach => {
        if (ach.type === type) {
            if (!state.progression.achievements) state.progression.achievements = {};
            const achState = state.progression.achievements[ach.id] || { completed: false, claimed: false };
            if (!achState.completed && currentVal >= ach.target) {
                achState.completed = true;
                state.progression.achievements[ach.id] = achState;
                triggerAchievementUnlockNotification(ach);
                saveNeeded = true;
            }
        }
    });
    
    if (saveNeeded) {
        saveProgression();
        if (state.activeModal === 'achievements-modal') {
            renderAchievementsModal();
        }
    }
}

function triggerAchievementUnlockNotification(ach) {
    const isThai = state.lang === 'th';
    const achTitle = isThai ? ach.thTitle : ach.title;
    
    // Play bell sound
    if (state.audio.sfxEnabled && audioCtx) {
        try {
            const now = audioCtx.currentTime;
            // Glockenspiel sweep arpeggio
            const notes = [523.25, 659.25, 783.99, 1046.50, 1318.51];
            notes.forEach((freq, i) => {
                const noteTime = now + i * 0.08;
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.type = 'triangle';
                osc.frequency.setValueAtTime(freq, noteTime);
                gain.gain.setValueAtTime(0.04 * state.audio.sfxVolume, noteTime);
                gain.gain.exponentialRampToValueAtTime(0.0001, noteTime + 0.35);
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.start(noteTime);
                osc.stop(noteTime + 0.4);
            });
        } catch (e) {}
    }
    
    // Cute alert log
    triggerAlertLog(isThai 
        ? `🏆 ปลดล็อกตราประทับพาสปอร์ต: ${achTitle}! (ดูที่ถ้วยรางวัลเกียรติยศ)` 
        : `🏆 Unlocked Passport Stamp: ${achTitle}! (Check Badge Scrapbook)`
    );
    
    // Floating toast popup
    const container = document.createElement('div');
    container.className = 'achievement-unlock-toast';
    container.style.cssText = `
        position: fixed;
        top: 20px;
        left: 50%;
        transform: translate(-50%, -100px);
        background: linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%);
        border: 4px solid #3a3232;
        border-radius: 24px;
        padding: 12px 20px;
        box-shadow: 0 10px 0 #3a3232, 0 15px 30px rgba(0,0,0,0.25);
        display: flex;
        align-items: center;
        gap: 15px;
        z-index: 100000;
        opacity: 0;
        transition: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        font-family: var(--font-cute), "Fredoka", sans-serif;
        pointer-events: none;
    `;
    
    // Choose appropriate emoji based on category
    let catEmoji = "✈️";
    if (ach.category === "tycoon") catEmoji = "🏡";
    else if (ach.category === "finance") catEmoji = "💰";
    else if (ach.category === "fortune") catEmoji = "🍀";
    else if (ach.category === "party") catEmoji = "🎮";
    
    const emojiHTML = `<div style="font-size: 2.2rem; transform: scale(1); animation: sticker-bob 2s infinite ease-in-out alternate;">${catEmoji}</div>`;
    
    const textHTML = `
        <div style="display: flex; flex-direction: column;">
            <span style="font-size: 0.7rem; font-weight: 800; color: #16a34a; text-transform: uppercase; letter-spacing: 1px;">${isThai ? '🎉 ปลดล็อกตราประทับเกียรติยศ!' : '🎉 PASSPORT BADGE UNLOCKED!'}</span>
            <span style="font-size: 1.15rem; font-weight: 800; color: #3a3232; line-height: 1.2;">${achTitle}</span>
            <span style="font-size: 0.8rem; font-weight: 700; color: #4b5563;">${isThai ? 'รางวัล: 💰 ' + ach.reward + ' เหรียญ' : 'Reward: 💰 ' + ach.reward + ' Coins'}</span>
        </div>
    `;
    
    container.innerHTML = emojiHTML + textHTML;
    document.body.appendChild(container);
    
    // Animate slide-in from top
    requestAnimationFrame(() => {
        container.style.opacity = '1';
        container.style.transform = 'translate(-50%, 0)';
    });
    
    // Animate slide-out
    setTimeout(() => {
        container.style.opacity = '0';
        container.style.transform = 'translate(-50%, -100px)';
        setTimeout(() => container.remove(), 600);
    }, 3800);
}

function claimAchievementReward(id) {
    if (!state.progression || !state.progression.achievements) return;
    const ach = achievementTemplates.find(a => a.id === id);
    if (!ach) return;
    
    const achState = state.progression.achievements[id] || { completed: false, claimed: false };
    if (!achState.completed || achState.claimed) return;
    
    // Trigger haptic & sound
    triggerHaptic([30, 60]);
    if (state.audio.sfxEnabled && audioCtx) {
        try {
            const now = audioCtx.currentTime;
            // Wooden stamp slap sound
            const slapOsc = audioCtx.createOscillator();
            const slapGain = audioCtx.createGain();
            slapOsc.type = 'sine';
            slapOsc.frequency.setValueAtTime(140, now);
            slapOsc.frequency.exponentialRampToValueAtTime(30, now + 0.12);
            slapGain.gain.setValueAtTime(0.25 * state.audio.sfxVolume, now);
            slapGain.gain.exponentialRampToValueAtTime(0.001, now + 0.14);
            slapOsc.connect(slapGain);
            slapGain.connect(audioCtx.destination);
            slapOsc.start(now);
            slapOsc.stop(now + 0.15);
            
            // Sparkling bell note
            const chimeOsc = audioCtx.createOscillator();
            const chimeGain = audioCtx.createGain();
            chimeOsc.type = 'triangle';
            chimeOsc.frequency.setValueAtTime(987.77, now + 0.04); // B5 note
            chimeGain.gain.setValueAtTime(0.08 * state.audio.sfxVolume, now + 0.04);
            chimeGain.gain.exponentialRampToValueAtTime(0.0001, now + 0.45);
            chimeOsc.connect(chimeGain);
            chimeGain.connect(audioCtx.destination);
            chimeOsc.start(now + 0.04);
            chimeOsc.stop(now + 0.5);
        } catch(e) {}
    }
    
    // Set claimed
    achState.claimed = true;
    state.progression.achievements[id] = achState;
    
    // Award rewards
    state.players[0].coins += ach.reward;
    state.players[0].stats.totalCoinsEarned += ach.reward;
    addXP(ach.xp);
    
    if (ach.reward >= 300) {
        awardRandomSticker(state.players[0].characterType);
    }
    
    saveProgression();
    updateCoinsHUD();
    
    // Confetti explosion
    triggerConfettiBurst();
    
    const isThai = state.lang === 'th';
    triggerAlertLog(isThai 
        ? `🎁 รับรางวัลเกียรติยศ! ได้รับ 💰 +${ach.reward} เหรียญ และ ⭐ +${ach.xp} XP!` 
        : `🎁 Badge reward claimed! Received 💰 +${ach.reward} Coins and ⭐ +${ach.xp} XP!`
    );
    
    // Re-render and apply stamp effect
    renderAchievementsModal();
}

function initAchievementsDOM() {
    const btnOpenLobby = document.getElementById('btn-open-achievements');
    const btnOpenHUD = document.getElementById('btn-open-achievements-hud');
    const btnClose = document.getElementById('btn-close-achievements');
    const searchInput = document.getElementById('achievements-search-input');
    
    if (btnOpenLobby) {
        btnOpenLobby.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(15);
            openAchievementsModal();
        });
    }
    
    if (btnOpenHUD) {
        btnOpenHUD.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(15);
            openAchievementsModal();
        });
    }
    
    if (btnClose) {
        btnClose.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(12);
            hideModal('achievements-modal');
        });
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', (e) => {
            filterAchievementsList();
        });
    }
    
    // Tab selectors click events
    const tabs = document.querySelectorAll('.achievement-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(10);
            
            // Toggle active style
            tabs.forEach(t => {
                t.classList.remove('active');
                t.style.backgroundColor = '#e2e8f0';
                t.style.transform = 'translateY(2px)';
            });
            tab.classList.add('active');
            tab.style.backgroundColor = '#fff';
            tab.style.transform = 'translateY(0px)';
            
            filterAchievementsList();
        });
    });
}

function openAchievementsModal() {
    showModal('achievements-modal');
    
    // Reset search
    const searchInput = document.getElementById('achievements-search-input');
    if (searchInput) searchInput.value = '';
    
    // Reset tab to traveler
    const tabs = document.querySelectorAll('.achievement-tab');
    tabs.forEach(tab => {
        if (tab.getAttribute('data-category') === 'traveler') {
            tab.classList.add('active');
            tab.style.backgroundColor = '#fff';
            tab.style.transform = 'translateY(0px)';
        } else {
            tab.classList.remove('active');
            tab.style.backgroundColor = '#e2e8f0';
            tab.style.transform = 'translateY(2px)';
        }
    });
    
    renderAchievementsModal();
}

function renderAchievementsModal() {
    const isThai = state.lang === 'th';
    const container = document.getElementById('achievements-grid');
    if (!container) return;
    
    container.innerHTML = '';
    
    // Calculate overall achievements completion
    const totalCount = achievementTemplates.length;
    let completedCount = 0;
    let claimedCount = 0;
    
    achievementTemplates.forEach(ach => {
        if (!state.progression.achievements) state.progression.achievements = {};
        const achState = state.progression.achievements[ach.id] || { completed: false, claimed: false };
        if (achState.completed) completedCount++;
        if (achState.claimed) claimedCount++;
    });
    
    const completionPct = Math.round((completedCount / totalCount) * 100);
    
    // Update master progress
    const pctLabel = document.getElementById('achievements-pct-label');
    const pctValue = document.getElementById('achievements-pct-value');
    const progressFill = document.getElementById('achievements-progress-fill');
    
    if (pctLabel) pctLabel.innerText = isThai ? 'ระดับความสำเร็จพาสปอร์ต:' : 'PASSPORT COMPLETION:';
    if (pctValue) pctValue.innerText = `${completionPct}% (${completedCount}/${totalCount})`;
    if (progressFill) progressFill.style.width = `${completionPct}%`;
    
    // Localize header titles
    const badgeText = document.getElementById('achievements-badge-text');
    const titleText = document.getElementById('achievements-title-text');
    const footerText = document.getElementById('achievements-footer-text');
    const searchInput = document.getElementById('achievements-search-input');
    
    if (badgeText) badgeText.innerText = isThai ? 'พาสปอร์ตตราเกียรติยศ 🏆' : 'HONOR PASSPORT 🏆';
    if (titleText) titleText.innerText = isThai ? 'ทำเนียบตราประทับท่องเที่ยว' : 'PASSPORT BADGES COLLECTION';
    if (footerText) footerText.innerText = isThai ? 'ตราประทับจะปลดล็อกถาวรข้ามทริปและรอบกระดานทั้งหมด' : 'Stamps unlocked permanently across all passport trips';
    if (searchInput) searchInput.placeholder = isThai ? 'ค้นหาถ้วยรางวัล / ตราประทับ...' : 'Search achievements / stamps...';
    
    // Build cards
    achievementTemplates.forEach(ach => {
        if (!state.progression.achievements) state.progression.achievements = {};
        const achState = state.progression.achievements[ach.id] || { completed: false, claimed: false };
        const lifetimeVal = state.progression.lifetimeStats ? (state.progression.lifetimeStats[ach.type] || 0) : 0;
        
        const card = document.createElement('div');
        card.className = `achievement-item-card ${!achState.completed ? 'achievement-locked' : 'achievement-completed'}`;
        card.setAttribute('data-category', ach.category);
        card.setAttribute('data-title', ach.title);
        card.setAttribute('data-th-title', ach.thTitle);
        card.setAttribute('data-desc', ach.desc);
        card.setAttribute('data-th-desc', ach.thDesc);
        
        // Choose appropriate HSL accent color for category
        let colorHue = 195;
        let catEmoji = "✈️";
        if (ach.category === "tycoon") { colorHue = 15; catEmoji = "🏡"; }
        else if (ach.category === "finance") { colorHue = 45; catEmoji = "💰"; }
        else if (ach.category === "fortune") { colorHue = 120; catEmoji = "🍀"; }
        else if (ach.category === "party") { colorHue = 280; catEmoji = "🎮"; }
        
        card.style.borderLeft = `6px solid hsl(${colorHue}, 80%, 45%)`;
        
        const title = isThai ? ach.thTitle : ach.title;
        const desc = isThai ? ach.thDesc : ach.desc;
        const rewardLabel = isThai ? 'รางวัล:' : 'Reward:';
        
        const progressPct = Math.min(100, (lifetimeVal / ach.target) * 100);
        
        let rightColumnHTML = '';
        if (achState.claimed) {
            rightColumnHTML = `
                <div class="achievement-unlocked-stamp" style="border-color: hsl(${colorHue}, 70%, 40%); color: hsl(${colorHue}, 70%, 35%);">
                    ${isThai ? 'สำเร็จ!' : 'UNLOCKED!'}
                </div>
            `;
        } else if (achState.completed) {
            rightColumnHTML = `
                <button class="cute-mini-btn btn-achievement-claim" data-id="${ach.id}" style="background-color: var(--pastel-mint); border-color: var(--border-dark); color: var(--text-dark); font-weight: 800; padding: 6px 12px; font-size: 0.8rem; box-shadow: 0 3px 0 var(--border-dark); cursor: pointer; white-space: nowrap; z-index: 10;">
                    ${isThai ? 'รับรางวัล' : 'CLAIM'}
                </button>
            `;
        } else {
            rightColumnHTML = `
                <div style="font-size: 1.1rem; color: #94a3b8; padding-right: 6px;"><i class="fa-solid fa-lock"></i></div>
            `;
        }
        
        card.innerHTML = `
            <div class="achievement-card-left" style="flex: 1; display: flex; flex-direction: column; gap: 4px;">
                <div class="achievement-card-title" style="display: flex; align-items: center; gap: 6px; font-weight: 800; font-size: 0.95rem; color: var(--text-dark);">
                    <span class="title-emoji">${catEmoji}</span>
                    <span>${title}</span>
                </div>
                <div class="achievement-card-desc" style="font-size: 0.72rem; color: var(--text-muted); font-weight: 700;">
                    ${desc}
                </div>
                <div class="achievement-card-reward" style="font-size: 0.68rem; font-weight: 800; color: #e11d48; display: flex; align-items: center; gap: 4px; margin-top: 2px;">
                    <span>🎁</span>
                    <span>${rewardLabel} 💰 +${ach.reward} | ⭐ +${ach.xp} XP</span>
                </div>
                ${!achState.completed ? `
                    <div class="achievement-progress-row" style="display: flex; align-items: center; gap: 8px; margin-top: 4px;">
                        <div class="achievement-progress-bar-container" style="flex: 1; height: 6px; border: 1.5px solid var(--border-dark); border-radius: 3px; background: #fff; overflow: hidden; position: relative;">
                            <div class="achievement-progress-bar-fill" style="width: ${progressPct}%; height: 100%; background: hsl(${colorHue}, 80%, 45%); transition: width 0.3s;"></div>
                        </div>
                        <span class="achievement-progress-text">${lifetimeVal}/${ach.target}</span>
                    </div>
                ` : ''}
            </div>
            <div style="position: relative; display: flex; align-items: center; justify-content: center; min-width: 80px;">
                ${rightColumnHTML}
            </div>
        `;
        
        container.appendChild(card);
    });
    
    // Attach claim listeners
    container.querySelectorAll('.btn-achievement-claim').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const id = btn.getAttribute('data-id');
            claimAchievementReward(id);
        });
    });
    
    // Re-apply active filters
    filterAchievementsList();
}

function filterAchievementsList() {
    const queryEl = document.getElementById('achievements-search-input');
    const query = queryEl ? queryEl.value.toLowerCase().trim() : '';
    const activeTab = document.querySelector('.achievement-tab.active');
    const activeCategory = activeTab ? activeTab.getAttribute('data-category') : 'traveler';
    
    const cards = document.querySelectorAll('.achievement-item-card');
    cards.forEach(card => {
        const category = card.getAttribute('data-category');
        const title = card.getAttribute('data-title').toLowerCase();
        const thTitle = card.getAttribute('data-th-title').toLowerCase();
        const desc = card.getAttribute('data-desc').toLowerCase();
        const thDesc = card.getAttribute('data-th-desc').toLowerCase();
        
        const categoryMatch = (category === activeCategory);
        const searchMatch = !query || 
                            title.includes(query) || 
                            thTitle.includes(query) || 
                            desc.includes(query) || 
                            thDesc.includes(query);
                            
        if (categoryMatch && searchMatch) {
            card.style.display = 'flex';
        } else {
            card.style.display = 'none';
        }
    });
}

// ============================================================================
// CHARACTER SUMMON GACHAPON & GALLERY SCRAPBOOK CONTROLLER
// ============================================================================

// Initialize default unlocked rosters and boards if not already created
if (!state.progression) {
    state.progression = {};
}
state.progression.unlockedCharacters = [...DEFAULT_PLAYABLE_CHARACTER_TYPES];
state.progression.unlockedBoards = ['bangkok'];

// Call loadProgression during app boot sequence

let galleryDomInitialized = false;

function initGalleryDOM() {
    if (galleryDomInitialized) return;
    galleryDomInitialized = true;

    // Gallery button in Lobby
    const openBtn = document.getElementById('btn-open-gallery');
    if (openBtn) {
        openBtn.addEventListener('click', () => {
            openGalleryModal();
        });
    }

    // Gallery button in Board HUD
    const hudBtn = document.getElementById('btn-open-gallery-hud');
    if (hudBtn) {
        hudBtn.addEventListener('click', () => {
            openGalleryModal();
        });
    }

    // Close Gallery
    const closeBtn = document.getElementById('btn-close-gallery');
    if (closeBtn) {
        closeBtn.addEventListener('click', () => {
            hideModal('gallery-modal');
            triggerPurchaseChime();
        });
    }

    // Gacha Spin dial lever trigger
    const spinBtn = document.getElementById('btn-gacha-spin');
    if (spinBtn) {
        spinBtn.addEventListener('click', () => {
            summonCharacterGacha();
        });
    }

    // Close capsule reveal overlay
    const closeRevealBtn = document.getElementById('btn-gacha-reveal-ok') || document.getElementById('btn-close-reveal');
    if (closeRevealBtn) {
        closeRevealBtn.addEventListener('click', () => {
            const overlay = document.getElementById('gacha-reveal-pane') || document.getElementById('capsule-reveal-overlay');
            if (overlay) overlay.style.display = 'none';
            triggerPurchaseChime();
            renderGalleryModal();
            updateSelectionCardUI();
        });
    }

    // Close detailed scrapbook drawer
    const drawer = document.getElementById('hero-details-drawer');
    if (drawer) {
        drawer.addEventListener('click', (event) => {
            const closeBtn = event.target.closest('#btn-close-drawer, .btn-close-hero-details');
            if (!closeBtn) return;
            drawer.classList.remove('active');
            drawer.style.display = 'none';
            triggerPurchaseChime();
        });
    }
}

// Open and render Gallery
function openGalleryModal() {
    loadProgression();
    showModal('gallery-modal');
    triggerUpgradeSparkles();
    renderGalleryModal();
}

// Draw dynamic slots and discover percentages
function renderGalleryModal() {
    const grid = document.getElementById('gallery-grid');
    if (!grid) return;
    grid.innerHTML = '';

    const isThai = state.lang === 'th';
    const unlocked = state.progression.unlockedCharacters || ['cat'];
    const allChars = characterTemplates.map(x => x.type);
    
    // Sort all characters by rarity weights
    const rarityWeights = { common: 0, rare: 1, epic: 2, legendary: 3 };
    const sortedList = allChars.sort((a, b) => {
        const tA = characterTemplates.find(x => x.type === a);
        const tB = characterTemplates.find(x => x.type === b);
        return rarityWeights[tA.rarity] - rarityWeights[tB.rarity];
    });

    let discoveredCount = 0;
    sortedList.forEach(id => {
        const isUnlocked = unlocked.includes(id);
        if (isUnlocked) discoveredCount++;

        const t = characterTemplates.find(x => x.type === id);
        if (!t) return;
        const rarityUpper = t.rarity.toUpperCase();
        
        const card = document.createElement('div');
        card.className = `hero-gallery-card ${isUnlocked ? 'unlocked' : 'locked'}`;
        card.setAttribute('data-id', id);
        
        card.innerHTML = `
            ${!isUnlocked ? '<div class="lock-silhouette-sticker">🔒</div>' : ''}
            <div class="card-inner-box">
                <div class="thumbnail-wrapper" style="background: radial-gradient(circle, ${t.accentColor} 0%, rgba(0,0,0,0.2) 100%);">
                    <div class="card-emoji" style="filter: ${isUnlocked ? 'none' : 'brightness(0) contrast(1.1)'};">${t.emoji}</div>
                </div>
                <div class="gallery-card-info">
                    <span class="rarity-pill ${t.rarity}">${rarityUpper}</span>
                    <h3>${isThai ? t.thName : t.name}</h3>
                </div>
            </div>
        `;

        if (isUnlocked) {
            card.addEventListener('click', () => {
                showHeroDetails(id);
            });
        } else {
            card.addEventListener('click', () => {
                triggerSadRentSFX();
                triggerAlertLog(isThai 
                    ? `🔒 ฮีโร่คนนี้ยังไม่ได้ปลดล็อก! ใช้ไขตู้กาชาปองเพื่ออัญเชิญมาร่วมทีม! 🤖✨`
                    : `🔒 This Hero is currently locked! Pull the mechanical Gachapon to recruit them! 🤖✨`
                );
            });
        }
        grid.appendChild(card);
    });

    // Update summond balances and percent meters
    const percent = Math.floor((discoveredCount / allChars.length) * 100);
    const meter = document.getElementById('gallery-progress-fill');
    if (meter) meter.style.width = `${percent}%`;

    const text = document.getElementById('gallery-progress-text');
    if (text) {
        text.innerText = isThai
            ? `ปลดล็อกสะสม: ${discoveredCount}/${allChars.length} (${percent}%)`
            : `Collection Progress: ${discoveredCount}/${allChars.length} (${percent}%)`;
    }

    // Refresh Coins Balance displayed on Summon Box
    const coinBalText = document.getElementById('gacha-coins-balance');
    if (coinBalText) {
        coinBalText.innerText = `${state.progression.coins || 0} 💰`;
    }
    const galleryRatio = document.getElementById('gallery-unlocked-ratio');
    if (galleryRatio) {
        galleryRatio.innerText = `${discoveredCount}/${allChars.length}`;
    }

    const galleryCoins = document.getElementById('gallery-coins-val');
    if (galleryCoins) {
        galleryCoins.innerText = `${state.progression.coins ?? 0}`;
    }
}

// Summon character Gachapon loop
function summonCharacterGacha() {
    const isThai = state.lang === 'th';
    const cost = 600;
    
    loadProgression();
    let balance = state.progression.coins ?? 0;
    
    if (balance < cost) {
        triggerSadRentSFX();
        triggerAlertLog(isThai
            ? `❌ ยอดเหรียญทองไม่เพียงพอ! กาชาปอง 1 ลูกราคา 600 เหรียญทอง 💰`
            : `❌ Insufficient summon funds! 1 Gachapon pull costs 600 Coins 💰`
        );
        return;
    }

    // Deduct coins and save immediately
    state.progression.coins -= cost;
    saveProgression();

    // Disable gacha spin button during animation
    const btn = document.getElementById('btn-gacha-spin');
    if (btn) btn.disabled = true;

    // Refresh display balance immediately
    const coinBalText = document.getElementById('gacha-coins-balance');
    if (coinBalText) {
        coinBalText.innerText = `${state.progression.coins} 💰`;
    }

    const galleryCoins = document.getElementById('gallery-coins-val');
    if (galleryCoins) {
        galleryCoins.innerText = `${state.progression.coins}`;
    }

    // Play mechanical shaking and lever animation
    const dial = document.getElementById('gacha-machine-box');
    if (dial) {
        dial.classList.add('gacha-crank-shake');
        triggerDiceImpactSFX();
        setTimeout(() => {
            triggerDiceImpactSFX();
        }, 300);
        setTimeout(() => {
            triggerDiceImpactSFX();
        }, 600);
    }

    // After 1000ms: drop capsule bob animation
    setTimeout(() => {
        if (dial) dial.classList.remove('gacha-crank-shake');
        
        // Spawn capsule drop element
        const machine = document.querySelector('.gacha-machine-container');
        const capsule = document.createElement('div');
        capsule.className = 'capsule-drop';
        
        // Pick random capsule color gradient
        const colors = [
            'radial-gradient(circle, #f43f5e 0%, #be123c 100%)',
            'radial-gradient(circle, #3b82f6 0%, #1d4ed8 100%)',
            'radial-gradient(circle, #10b981 0%, #047857 100%)',
            'radial-gradient(circle, #eab308 0%, #a16207 100%)',
            'radial-gradient(circle, #a855f7 0%, #6b21a8 100%)'
        ];
        capsule.style.background = colors[Math.floor(Math.random() * colors.length)];
        
        if (machine) {
            machine.appendChild(capsule);
        }

        // After 1200ms drop completes: trigger explosion and reveal character
        setTimeout(() => {
            capsule.remove();
            triggerDiceImpactSFX();
            triggerConfettiBurst();
            
            // Weights logic: Common (50%), Rare (35%), Epic (12%), Legendary (3%)
            const roll = Math.random() * 100;
            let rarityGroup = 'common';
            if (roll < 3.0) rarityGroup = 'legendary';
            else if (roll < 15.0) rarityGroup = 'epic';
            else if (roll < 50.0) rarityGroup = 'rare';
            
            // Gather all matches in that group
            const matches = characterTemplates.filter(t => t.rarity === rarityGroup).map(t => t.type);
            
            // Select random figure from matching group
            const chosenId = matches[Math.floor(Math.random() * matches.length)] || 'cat';
            const t = characterTemplates.find(x => x.type === chosenId);
            if (!t) return;
            
            const isAlreadyUnlocked = state.progression.unlockedCharacters.includes(chosenId);
            
            let duplicateRefundText = "";
            let duplicateRefundEng = "";
            if (isAlreadyUnlocked) {
                // Duplicate gives flat 200 progression coins refund
                state.progression.coins += 200;
                saveProgression();
                duplicateRefundText = `<br><span style="color:#fcd34d; font-size:1rem; font-weight:bold;">✨ ซ้ำ! รับเงินคืนปลอบใจ 200 เหรียญทอง! 💰</span>`;
                duplicateRefundEng = `<br><span style="color:#fcd34d; font-size:1rem; font-weight:bold;">✨ Duplicate! Refunded 200 Summon Coins! 💰</span>`;
            } else {
                state.progression.unlockedCharacters.push(chosenId);
                saveProgression();
            }

            // Fire gacha voice greeting
            triggerCharacterVoice(chosenId, 'win');

            // Draw reveal overlay
            const revealBox = document.getElementById('gacha-reveal-pane') || document.getElementById('capsule-reveal-overlay');
            if (revealBox) {
                revealBox.style.display = 'flex';
                
                const emoji = document.getElementById('gacha-capsule-anim') || document.getElementById('reveal-emoji');
                if (emoji) emoji.innerText = t.emoji;
                
                const label = document.getElementById('gacha-reveal-title');
                if (label) {
                    label.innerText = isAlreadyUnlocked
                        ? (isThai ? 'Duplicate refund +200' : 'Duplicate! Refunded 200 coins')
                        : (isThai ? 'New hero summoned!' : 'New hero summoned!');
                }

                const title = document.getElementById('gacha-reveal-name') || document.getElementById('reveal-name');
                if (title) {
                    title.innerText = isThai ? t.thName : t.name;
                    title.style.display = 'block';
                }
                
                const type = document.getElementById('gacha-reveal-rarity') || document.getElementById('reveal-rarity');
                if (type) {
                    type.className = `rarity-pill ${t.rarity}`;
                    type.innerText = t.rarity.toUpperCase();
                    type.style.display = 'inline-block';
                }

                const okButton = document.getElementById('btn-gacha-reveal-ok');
                if (okButton) okButton.style.display = 'inline-block';
                
                const desc = document.getElementById('reveal-passive-desc');
                if (desc) {
                    desc.innerHTML = (isThai 
                        ? `<strong>ความสามารถพิเศษ:</strong> ${t.thPassiveDesc}${duplicateRefundText}`
                        : `<strong>Hero Passive:</strong> ${t.passiveDesc}${duplicateRefundEng}`
                    );
                }
            }

            // Restore gacha button
            if (btn) btn.disabled = false;
            
        }, 1100);

    }, 1000);
}

// Show detailed scrapbook drawer
function showHeroDetails(id) {
    const isThai = state.lang === 'th';
    const t = characterTemplates.find(x => x.type === id);
    if (!t) return;

    const drawer = document.getElementById('hero-details-drawer');
    if (!drawer) return;

    drawer.innerHTML = `
        <button id="btn-close-drawer" type="button" class="circle-bubble-btn btn-close-hero-details" style="position:absolute; top:-10px; right:-10px; width:30px; height:30px; background:var(--pastel-red); color:white;" aria-label="Close hero details">&times;</button>
        <div style="display:flex; align-items:center; gap:12px;">
            <div id="drawer-avatar" style="width:64px; height:64px; border:3px solid var(--border-dark); border-radius:16px; display:flex; align-items:center; justify-content:center; font-size:2.4rem; background:${t.accentColor || '#fff7ed'};"></div>
            <div style="min-width:0;">
                <div id="drawer-name" style="font-size:1.1rem; font-weight:900; color:var(--text-dark); line-height:1.1;"></div>
                <div id="drawer-rarity" class="rarity-pill ${t.rarity}" style="display:inline-block; margin-top:4px;"></div>
            </div>
        </div>
        <div id="drawer-desc" style="font-size:0.74rem; color:var(--text-muted); font-weight:700; line-height:1.35; margin-top:10px;"></div>
        <div id="drawer-passive" style="font-size:0.72rem; color:var(--text-dark); font-weight:800; line-height:1.35; margin-top:8px; padding:8px; border:2px dashed var(--border-dark); border-radius:10px; background:#fff8dd;"></div>
        <div id="drawer-stats-box" style="margin-top:10px;"></div>
    `;
    drawer.style.display = 'block';
    drawer.classList.add('active');
    triggerPurchaseChime();

    // Populate drawer elements
    const avatar = document.getElementById('drawer-avatar');
    if (avatar) avatar.innerText = t.emoji;

    const name = document.getElementById('drawer-name');
    if (name) name.innerText = isThai ? t.thName : t.name;

    const rarity = document.getElementById('drawer-rarity');
    if (rarity) {
        rarity.className = `rarity-pill ${t.rarity}`;
        rarity.innerText = t.rarity.toUpperCase();
    }

    const desc = document.getElementById('drawer-desc');
    if (desc) {
        desc.innerText = isThai ? t.thDesc : t.desc;
    }

    const passive = document.getElementById('drawer-passive');
    if (passive) {
        passive.innerText = isThai ? t.thPassiveDesc : t.passiveDesc;
    }

    // Populate passive bars
    const barsContainer = document.getElementById('drawer-stats-box');
    if (barsContainer) {
        barsContainer.innerHTML = '';
        
        const statLabels = isThai 
            ? { speed: 'ความเร็วบิน', luck: 'โชคการ์ด', rent: 'โบนัสค่าเช่า' }
            : { speed: 'Speed Move', luck: 'Card Luck', rent: 'Rent Power' };

        Object.keys(t.stats).forEach(stat => {
            const val = t.stats[stat];
            const maxVal = stat === 'rent' ? 150 : 100;
            const pct = Math.min(100, Math.floor((val / maxVal) * 100));

            const barWrapper = document.createElement('div');
            barWrapper.className = 'detail-stat-row';
            barWrapper.innerHTML = `
                <div class="detail-stat-header">
                    <span>${statLabels[stat]}</span>
                    <span>${val}</span>
                </div>
                <div class="detail-stat-bar-outer">
                    <div class="detail-stat-bar-inner" style="width: ${pct}%; background-color: ${t.accentColor || '#f59e0b'};"></div>
                </div>
            `;
            barsContainer.appendChild(barWrapper);
        });
    }
}

// Initialize Gallery DOM listeners
