// ============================================================================
// COZY TOY-WORLD SAVE GAME & MATCH RECONSTRUCTION SYSTEM
// ============================================================================

function saveMatchState(isManual = false) {
    if (!state.started || state.isMatchOver) return;

    try {
        const matchData = {
            currentMap: state.currentMap || 'bangkok',
            currentPlayerIndex: state.currentPlayerIndex,
            turnsPlayed: state.turnsPlayed,
            maxTurns: state.maxTurns,
            started: state.started,
            players: state.players.map(p => ({
                id: p.id,
                name: p.name,
                emoji: p.emoji,
                color: p.color,
                characterType: p.characterType,
                isBot: p.isBot,
                personality: p.personality,
                coins: p.coins,
                position: p.position,
                properties: [...p.properties],
                stats: { ...p.stats },
                touristSeasonRounds: p.touristSeasonRounds,
                templeRestorationDiscount: p.templeRestorationDiscount
            })),
            board: state.board.map(tile => ({
                owner: tile.owner,
                level: tile.level || 0
            }))
        };

        localStorage.setItem('thailand_toy_active_match', JSON.stringify(matchData));
        
        // Also save progress and statistics
        saveProgression();

        if (isManual) {
            triggerPurchaseChime();
            showModal('save-game-modal');
        }
    } catch (e) {
        console.error("Failed to auto-save match:", e);
    }
}

function continueSavedMatch() {
    const raw = localStorage.getItem('thailand_toy_active_match');
    if (!raw) return;

    try {
        const matchData = JSON.parse(raw);
        const isThai = state.lang === 'th';
        
        // 1. Hide select screen immediately
        state.isSelectionActive = false;
        const selectScreen = document.getElementById('char-select-screen');
        if (selectScreen) {
            selectScreen.classList.remove('active');
            selectScreen.style.opacity = 0;
            setTimeout(() => selectScreen.style.display = 'none', 500);
        }

        // 2. Load board theme
        loadBoardTheme(matchData.currentMap || 'bangkok', false);

        // 3. Restore global game state params
        state.currentPlayerIndex = matchData.currentPlayerIndex;
        state.turnsPlayed = matchData.turnsPlayed;
        state.maxTurns = matchData.maxTurns;
        state.started = true;

        // 4. Restore players
        matchData.players.forEach((pData, idx) => {
            const p = state.players[idx];
            if (p) {
                p.name = pData.name;
                p.emoji = pData.emoji;
                p.color = pData.color;
                p.characterType = pData.characterType;
                p.isBot = pData.isBot;
                p.personality = pData.personality;
                p.coins = pData.coins;
                p.position = pData.position;
                p.properties = [...pData.properties];
                p.stats = { ...pData.stats };
                p.touristSeasonRounds = pData.touristSeasonRounds;
                p.templeRestorationDiscount = pData.templeRestorationDiscount;
            }
        });

        // 5. Recreate player 3D chibi figures
        recreatePlayerMeshes();

        // 6. Repo player meshes to their correct positions
        state.players.forEach((p, idx) => {
            if (p.mesh) {
                p.mesh.position.copy(boardCoordinates[p.position]);
                const offset = getPlayerOffset(idx);
                p.mesh.position.x += offset.x;
                p.mesh.position.z += offset.z;
            }
        });

        state.player = state.players[0];
        state.opponent = state.players[1];

        // 7. Restore board tiles
        matchData.board.forEach((tData, idx) => {
            const tile = state.board[idx];
            if (tile) {
                tile.owner = tData.owner;
                tile.level = tData.level;
                
                if (tile.owner !== null) {
                    spawnMiniatureCottage(tile, tile.level);
                    changeTileSidewalkColor(tile, tile.owner);
                }
            }
        });

        // 8. Re-display HUD & status logs
        const hud = document.getElementById('game-hud');
        if (hud) hud.style.display = 'block';

        const roundCounter = document.getElementById('hud-round-counter');
        if (roundCounter) {
            roundCounter.innerText = `ROUND ${Math.min(state.turnsPlayed + 1, state.maxTurns)}/${state.maxTurns}`;
        }

        updateTurnIndicatorHUD();
        renderLeaderboard();
        updateCoinsHUD();
        updateOwnedPropertiesGrid();

        state.lastPlayerCoins = state.players[0].coins;
        clock.getDelta(); // reset clock delta

        triggerConfettiBurst();
        triggerPurchaseChime();
        
        triggerAlertLog(isThai 
            ? `🎒 ยินดีต้อนรับกลับมา! ท่องเที่ยวต่อจากรอบที่ ${state.turnsPlayed + 1} บอร์ด ${boardConfigurations[state.currentMap].name}!`
            : `🎒 Welcome back! Resumed your tour from round ${state.turnsPlayed + 1} at ${boardConfigurations[state.currentMap].name}!`
        );

        beginNewTurnFlow('announcing');
        triggerTurnStartAnnouncement(state.currentPlayerIndex);

    } catch (e) {
        console.error("Failed to load saved match:", e);
        triggerSadRentSFX();
    }
}

function initSaveSystemDOM() {
    const isThai = state.lang === 'th';
    
    // Check saved active match on lobby page boot
    const savedMatch = localStorage.getItem('thailand_toy_active_match');
    const btnContinue = document.getElementById('btn-continue-adventure');
    const btnNew = document.getElementById('btn-new-game');
    const btnReady = document.getElementById('btn-ready-tour');

    if (savedMatch !== null) {
        if (btnContinue) {
            btnContinue.style.display = 'block';
            const btnSpan = btnContinue.querySelector('.btn-bubble-content');
            if (btnSpan) {
                btnSpan.innerHTML = isThai ? `ท่องเที่ยวต่อจากเดิม! 🎒` : `CONTINUE ADVENTURE! 🎒`;
            }
        }
        if (btnNew) {
            btnNew.style.display = 'block';
            const btnSpan = btnNew.querySelector('.btn-bubble-content');
            if (btnSpan) {
                btnSpan.innerHTML = isThai ? `เริ่มเดินทางใหม่ 🎲` : `NEW ADVENTURE! 🎲`;
            }
        }
        if (btnReady) btnReady.style.display = 'none';
    } else {
        if (btnContinue) btnContinue.style.display = 'none';
        if (btnNew) btnNew.style.display = 'none';
        if (btnReady) btnReady.style.display = 'block';
    }

    // Manual Save button trigger
    const btnManualSave = document.getElementById('btn-manual-save');
    if (btnManualSave) {
        btnManualSave.addEventListener('click', () => {
            saveMatchState(true);
        });
    }

    // Save Confirm modal dismiss
    const btnSaveConfirm = document.getElementById('btn-save-confirm');
    if (btnSaveConfirm) {
        btnSaveConfirm.addEventListener('click', () => {
            hideModal('save-game-modal');
        });
    }

    // Continue Adventure click handler
    if (btnContinue) {
        btnContinue.addEventListener('click', () => {
            continueSavedMatch();
        });
    }

    // New Game click handler (wipes previous match state and launches normal flow)
    if (btnNew) {
        btnNew.addEventListener('click', () => {
            localStorage.removeItem('thailand_toy_active_match');
            triggerPurchaseChime();
            
            // Re-render lobby buttons back to standard
            if (btnContinue) btnContinue.style.display = 'none';
            if (btnNew) btnNew.style.display = 'none';
            if (btnReady) btnReady.style.display = 'block';
            
            // Trigger world map selection
            showWorldMapScreen();
        });
    }
}

// Initialize Save System on boot
initSaveSystemDOM();

