let activeFestivalInterval = null;

function triggerFestivalRoll(roundNumber) {
    let targetFest = null;
    
    // Choose active festival depending on current round
    if (roundNumber >= 4 && roundNumber <= 6) {
        targetFest = seasonalFestivals[0]; // Songkran
    } else if (roundNumber >= 7 && roundNumber <= 9) {
        targetFest = seasonalFestivals[1]; // Loy Krathong
    } else if (roundNumber >= 10 && roundNumber <= 12) {
        targetFest = seasonalFestivals[2]; // Chinese New Year
    } else if (roundNumber >= 13 && roundNumber <= 15) {
        targetFest = seasonalFestivals[4]; // Durian Season
    }
    
    const banner = document.getElementById('hud-festival-banner');
    const bEmoji = document.getElementById('festival-banner-emoji');
    const bText = document.getElementById('festival-banner-text');
    const isThai = state.lang === 'th';
    
    // Clear old festival particles interval
    if (activeFestivalInterval) {
        clearInterval(activeFestivalInterval);
        activeFestivalInterval = null;
    }

    if (targetFest) {
        state.activeFestival = targetFest;
        
        // Show banner marquee
        if (banner) {
            banner.style.display = 'flex';
            banner.style.background = targetFest.color;
        }
        if (bEmoji) bEmoji.innerText = targetFest.emoji;
        if (bText) {
            bText.innerText = isThai
                ? `${targetFest.thName.toUpperCase()} - ${targetFest.thBonus}`
                : `${targetFest.name.toUpperCase()} - ${targetFest.bonus}`;
        }
        
        // Set dynamic announce popup elements
        const aBadge = document.getElementById('fest-announce-badge');
        const aTitle = document.getElementById('fest-announce-title');
        const aEmoji = document.getElementById('fest-announce-emoji');
        const aBonus = document.getElementById('fest-announce-bonus');
        const aDesc = document.getElementById('fest-announce-desc');
        
        if (aBadge) aBadge.innerText = isThai ? "เทศกาลกำลังมา! 🎪" : "FESTIVAL INCOMING! 🎪";
        if (aTitle) aTitle.innerText = isThai ? targetFest.thName : targetFest.name;
        if (aEmoji) aEmoji.innerText = targetFest.emoji;
        if (aBonus) aBonus.innerText = isThai ? targetFest.thBonus : targetFest.bonus;
        if (aDesc) aDesc.innerText = isThai ? targetFest.thDesc : targetFest.desc;
        
        // Custom sound fanfare
        triggerUpgradeFanfare();
        triggerConfettiBurst();
        
        // Open announce modal
        showModal('festival-announcement-modal');
        
        // Wire floating CSS particles loop
        activeFestivalInterval = setInterval(() => {
            spawnFestivalFloatingCSSParticle(targetFest.emoji);
        }, 800);
    } else {
        state.activeFestival = null;
        if (banner) banner.style.display = 'none';
    }
}

function spawnFestivalFloatingCSSParticle(emoji) {
    const parent = document.body;
    const p = document.createElement('div');
    p.innerText = emoji;
    p.style.position = 'fixed';
    p.style.bottom = '-30px';
    p.style.left = `${Math.random() * 100}vw`;
    p.style.fontSize = `${1.2 + Math.random() * 1.5}rem`;
    p.style.opacity = '0.7';
    p.style.zIndex = '99999';
    p.style.pointerEvents = 'none';
    p.style.transition = 'all 5.5s cubic-bezier(0.1, 0.8, 0.3, 1)';
    p.style.filter = 'drop-shadow(0 2px 0 var(--border-dark))';
    
    parent.appendChild(p);
    
    // Animate up and sway
    requestAnimationFrame(() => {
        p.style.transform = `translateY(-105vh) rotate(${Math.random() * 360}deg)`;
        p.style.opacity = '0';
    });
    
    setTimeout(() => {
        p.remove();
    }, 5500);
}

