function advanceTimeOfDay(targetIndex = null) {
    if (targetIndex !== null) {
        timeOfDayIndex = targetIndex;
    } else {
        timeOfDayIndex = (timeOfDayIndex + 1) % timeOfDayStages.length;
    }
    
    const stage = timeOfDayStages[timeOfDayIndex];
    const isThai = state.lang === 'th';
    
    // Update Three.js Background & Fog
    if (scene) {
        // Smoothly set sky background color
        scene.background = new THREE.Color(stage.sky);
        
        // Update hemisphere light
        if (hemiLight) {
            hemiLight.color.setHex(stage.ambientColor);
        }
        
        // Update sun light position, color, intensity
        if (sunLight) {
            sunLight.color.setHex(stage.sunColor);
            sunLight.intensity = stage.sunIntensity;
            sunLight.position.set(stage.sunPos.x, stage.sunPos.y, stage.sunPos.z);
        }
        
        // If scene has fog, update it too
        if (scene.fog) {
            scene.fog.color.setHex(stage.fog);
        }
    }
    
    // Update HUD Indicator Elements
    const badge = document.getElementById('hud-time-of-day');
    const bEmoji = document.getElementById('tod-indicator-emoji');
    const bText = document.getElementById('tod-indicator-text');
    
    if (badge) {
        badge.style.backgroundColor = stage.bgColor;
        if (stage.name === 'night') {
            badge.style.color = '#ffffff';
        } else {
            badge.style.color = 'var(--text-dark)';
        }
    }
    if (bEmoji) bEmoji.innerText = stage.particlesEmoji;
    if (bText) {
        bText.innerText = isThai ? stage.thLabel : stage.label;
    }
    
    // Manage ambient particles
    if (ambientParticleInterval) {
        clearInterval(ambientParticleInterval);
    }
    
    // Start ambient particle drift loop
    ambientParticleInterval = setInterval(() => {
        if (document.hidden) return;
        spawnTimeOfDayParticle(stage.particlesEmoji, stage.name);
    }, 1500);
}

function spawnTimeOfDayParticle(emoji, timeName) {
    const parent = document.body;
    const p = document.createElement('div');
    p.innerText = emoji;
    p.style.position = 'fixed';
    p.style.top = `${-20 - Math.random() * 20}px`;
    p.style.left = `${Math.random() * 100}vw`;
    p.style.fontSize = `${0.8 + Math.random() * 0.9}rem`;
    p.style.opacity = timeName === 'night' ? '0.9' : '0.4';
    p.style.zIndex = '9999';
    p.style.pointerEvents = 'none';
    p.style.transition = 'all 7.5s linear';
    
    if (timeName === 'night') {
        p.style.filter = 'drop-shadow(0 0 4px #22c55e)'; // firefly neon glow!
        p.style.top = 'auto';
        p.style.bottom = '-30px'; // Fireflies float UP from bottom!
    }
    
    parent.appendChild(p);
    
    // Sway drifting animation
    requestAnimationFrame(() => {
        if (timeName === 'night') {
            p.style.transform = `translate(${50 - Math.random() * 100}px, -105vh) rotate(${Math.random() * 180}deg)`;
            p.style.opacity = '0';
        } else {
            p.style.transform = `translate(${100 - Math.random() * 200}px, 105vh) rotate(${Math.random() * 360}deg)`;
            p.style.opacity = '0';
        }
    });
    
    setTimeout(() => {
        p.remove();
    }, 7500);
}

function initTimeOfDayStartup() {
    advanceTimeOfDay(0); // Default morning on load
}

// Trigger Morning on start!
initTimeOfDayStartup();

