// ============================================================================
// PHOTO MODE SYSTEM
// ============================================================================

function initPhotoMode() {
    // 1. Enter camera button
    const btnPhoto = document.getElementById('btn-photo-mode');
    if (btnPhoto) {
        btnPhoto.addEventListener('click', () => {
            triggerPurchaseChime();
            enterPhotoMode();
        });
    }

    // 2. Control deck bindings
    const btnExit = document.getElementById('btn-photo-exit');
    if (btnExit) {
        btnExit.addEventListener('click', () => {
            triggerSadRentSFX();
            exitPhotoMode();
        });
    }

    const btnRotLeft = document.getElementById('btn-photo-rot-left');
    if (btnRotLeft) {
        btnRotLeft.addEventListener('click', () => {
            triggerFootstepSFX();
            photoCameraAngle -= 0.25;
            updatePhotoCamera();
        });
    }

    const btnRotRight = document.getElementById('btn-photo-rot-right');
    if (btnRotRight) {
        btnRotRight.addEventListener('click', () => {
            triggerFootstepSFX();
            photoCameraAngle += 0.25;
            updatePhotoCamera();
        });
    }

    const zoomSlider = document.getElementById('photo-zoom-slider');
    if (zoomSlider) {
        zoomSlider.addEventListener('input', () => {
            updatePhotoCamera();
        });
    }

    const btnZoomIn = document.getElementById('btn-photo-zoom-in');
    if (btnZoomIn) {
        btnZoomIn.addEventListener('click', () => {
            triggerFootstepSFX();
            if (zoomSlider) {
                zoomSlider.value = Math.max(10, parseFloat(zoomSlider.value) - 2);
                updatePhotoCamera();
            }
        });
    }

    const btnZoomOut = document.getElementById('btn-photo-zoom-out');
    if (btnZoomOut) {
        btnZoomOut.addEventListener('click', () => {
            triggerFootstepSFX();
            if (zoomSlider) {
                zoomSlider.value = Math.min(32, parseFloat(zoomSlider.value) + 2);
                updatePhotoCamera();
            }
        });
    }

    const selectFrame = document.getElementById('select-frame-style');
    if (selectFrame) {
        selectFrame.addEventListener('change', () => {
            triggerPurchaseChime();
            const val = selectFrame.value;
            const guideText = document.getElementById('postcard-guide-text');
            const stamp = document.getElementById('postcard-guide-stamp');
            const isThai = state.lang === 'th';
            
            if (val === 'classic') {
                stamp.innerText = '🐘';
                guideText.innerText = isThai ? 'ยินดีต้อนรับจากเมืองไทย! 🛺' : 'GREETINGS FROM THAILAND! 🛺';
            } else if (val === 'beach') {
                stamp.innerText = '🏖️';
                guideText.innerText = isThai ? 'เที่ยวภูเก็ตและพัทยาแสนรื่นเริง! 🏖️' : 'SUNNY VIBES FROM PHUKET! 🏖️';
            } else if (val === 'sunset') {
                stamp.innerText = '🛕';
                guideText.innerText = isThai ? 'นมัสการยามเย็นจากวัดอรุณ! 🛕' : 'GOLDEN HOUR AT WAT ARUN! 🛕';
            } else {
                stamp.innerText = '📸';
                guideText.innerText = isThai ? 'ทริปการเดินทางของฉัน! 🌟' : 'MY THAI TOY ADVENTURE! 🌟';
            }
        });
    }

    const btnSnap = document.getElementById('btn-photo-snap');
    if (btnSnap) {
        btnSnap.addEventListener('click', () => {
            capturePostcardScreenshot();
        });
    }
}

function enterPhotoMode() {
    isPhotoModeActive = true;
    
    // Store original camera variables
    originalCameraPos.copy(camera.position);
    if (orbitControls) {
        originalCameraTarget.copy(orbitControls.target);
    }
    
    // Set cute photo values
    photoCameraAngle = Math.PI / 4; // 45 degrees default
    
    // Hide hud and show photo overlay
    const hud = document.getElementById('game-hud');
    if (hud) hud.style.display = 'none';
    
    const photoOverlay = document.getElementById('photo-mode-overlay');
    if (photoOverlay) photoOverlay.style.display = 'block';
    
    updatePhotoCamera();
    
    const isThai = state.lang === 'th';
    triggerAlertLog(isThai 
        ? '📸 เข้าสู่โหมดถ่ายภาพโปสการ์ด! หมุนกล้องและตกแต่งสแตมป์ตามต้องการเลยครับ'
        : '📸 Entered Postcard Photo Mode! Frame your chibi toys and stamp away!'
    );
}

function exitPhotoMode() {
    isPhotoModeActive = false;
    
    // Hide photo overlay & restore normal HUD
    const photoOverlay = document.getElementById('photo-mode-overlay');
    if (photoOverlay) photoOverlay.style.display = 'none';
    
    const hud = document.getElementById('game-hud');
    if (hud) hud.style.display = 'block';
    
    // Restore camera
    camera.position.copy(originalCameraPos);
    if (orbitControls) {
        orbitControls.target.copy(originalCameraTarget);
        orbitControls.update();
    }
    
    const isThai = state.lang === 'th';
    triggerAlertLog(isThai ? '📸 ออกจากโหมดถ่ายรูปแล้ว' : '📸 Exited Photo Mode.');
}

function updatePhotoCamera() {
    if (!isPhotoModeActive) return;
    const zoomSlider = document.getElementById('photo-zoom-slider');
    const radius = parseFloat(zoomSlider ? zoomSlider.value : 18) || 18;
    const target = new THREE.Vector3(0, 0.8, 0); // Focus directly on the center details
    
    camera.position.x = target.x + radius * Math.cos(photoCameraAngle);
    camera.position.z = target.z + radius * Math.sin(photoCameraAngle);
    camera.position.y = 8.5; // Sweet cute diagonal tilt angle
    camera.lookAt(target);
    
    if (orbitControls) {
        orbitControls.target.copy(target);
        orbitControls.update();
    }
}

function capturePostcardScreenshot() {
    if (!renderer || !canvas) return;
    
    // 1. Trigger Flash overlay animation
    const flash = document.getElementById('camera-flash');
    if (flash) {
        flash.style.opacity = '1';
        triggerUpgradeFanfare();
        setTimeout(() => {
            flash.style.opacity = '0';
        }, 150);
    }
    
    const isThai = state.lang === 'th';
    
    // 2. Create offscreen 2D canvas for Postcard composting
    const postcard = document.createElement('canvas');
    const ctx = postcard.getContext('2d');
    
    // Set standard high-res postcard aspect ratio 1200 x 800 (1.5)
    postcard.width = 1200;
    postcard.height = 800;
    
    // 3. Capture Three.js WebGL canvas image
    renderer.render(scene, camera);
    const webglDataUrl = renderer.domElement.toDataURL('image/png');
    
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = webglDataUrl;
    
    img.onload = function() {
        // A. Draw warm, cozy paper postcard border card backdrop
        ctx.fillStyle = '#fffdf5'; // Cozy cream white
        ctx.fillRect(0, 0, postcard.width, postcard.height);
        
        // B. Draw stylized drop shadows around inner frame
        ctx.shadowColor = 'rgba(58, 50, 50, 0.22)';
        ctx.shadowBlur = 15;
        ctx.shadowOffsetX = 0;
        ctx.shadowOffsetY = 4;
        
        // C. Crop WebGL render into the center (Postcard viewport box)
        const framePadding = 40;
        const innerW = postcard.width - (framePadding * 2);
        const innerH = postcard.height - (framePadding * 2) - 30; // Leave space for captions below!
        
        ctx.drawImage(img, framePadding, framePadding, innerW, innerH);
        
        // Reset shadows for details
        ctx.shadowBlur = 0;
        ctx.shadowOffsetX = 0;
        ctx.shadowOffsetY = 0;
        
        // D. Draw clean beveled frame borders
        ctx.lineWidth = 6;
        ctx.strokeStyle = '#3a3232'; // dark stamp ink color
        ctx.strokeRect(framePadding, framePadding, innerW, innerH);
        
        // E. Draw Retro dashed postmark dividers at the bottom center
        ctx.beginPath();
        ctx.setLineDash([8, 8]);
        ctx.moveTo(postcard.width / 2, postcard.height - 60);
        ctx.lineTo(postcard.width / 2, postcard.height - 15);
        ctx.stroke();
        ctx.setLineDash([]); // Reset dash
        
        // F. Determine frame style elements
        const val = document.getElementById('select-frame-style').value;
        
        // Render Postmark Stamp in Top-Right
        let stampEmoji = '🐘';
        let stampTitle = 'THAILAND';
        let stampColor = 'rgba(239, 68, 68, 0.85)'; // Red stamp ink
        
        if (val === 'beach') {
            stampEmoji = '🏖️';
            stampTitle = 'PHUKET';
            stampColor = 'rgba(59, 130, 246, 0.85)'; // Ocean Blue
        } else if (val === 'sunset') {
            stampEmoji = '🛕';
            stampTitle = 'ARUN';
            stampColor = 'rgba(245, 158, 11, 0.85)'; // Golden Amber
        } else if (val === 'clean') {
            stampEmoji = '📸';
            stampTitle = 'TOY TRIP';
            stampColor = 'rgba(168, 85, 247, 0.85)'; // Cozy Purple
        }
        
        // Draw Retro dash stamp outer box
        const sX = postcard.width - 160;
        const sY = 60;
        const sW = 100;
        const sH = 120;
        
        ctx.lineWidth = 3;
        ctx.strokeStyle = stampColor;
        ctx.setLineDash([5, 5]);
        ctx.strokeRect(sX, sY, sW, sH);
        ctx.setLineDash([]);
        
        // Draw stamp text details
        ctx.fillStyle = stampColor;
        ctx.font = 'bold 12px "Inter", "Outfit", "Arial", sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(stampTitle, sX + sW / 2, sY + 20);
        ctx.fillText('2026', sX + sW / 2, sY + sH - 12);
        
        // Stamp emoji
        ctx.font = '36px "Apple Color Emoji", "Segoe UI Emoji", "Arial"';
        ctx.fillText(stampEmoji, sX + sW / 2, sY + sH / 2 + 10);
        
        // Draw wavy postmark cancellation lines over stamp!
        ctx.strokeStyle = 'rgba(58, 50, 50, 0.4)';
        ctx.lineWidth = 2.5;
        for (let i = 0; i < 4; i++) {
            ctx.beginPath();
            ctx.arc(sX - 30 + (i * 12), sY + 60, 60, -Math.PI / 4, Math.PI / 4);
            ctx.stroke();
        }
        
        // G. Draw dynamic greetings text on bottom-left page side
        ctx.fillStyle = '#3a3232';
        ctx.font = 'bold 22px "Inter", "Outfit", "Arial", sans-serif';
        ctx.textAlign = 'left';
        
        let mapGreeting = 'Greetings from Thailand! / สวัสดีจากเมืองไทย!';
        if (state.currentMap === 'bangkok') {
            mapGreeting = 'Greetings from Bangkok! 🛺✨ / สวัสดีจากกรุงเทพฯ!';
        } else if (state.currentMap === 'chiangmai') {
            mapGreeting = 'Warm Hugs from Chiang Mai! 🏮🌸 / สวัสดีเจ้าจากเชียงใหม่!';
        } else if (state.currentMap === 'phuket') {
            mapGreeting = 'Sunny Vibes from Phuket! 🏝️🍹 / สวัสดีจากภูเก็ต!';
        } else if (state.currentMap === 'pattaya') {
            mapGreeting = 'Greetings from Pattaya Beach! 🏖️⛵ / สวัสดีจากพัทยา!';
        } else if (state.currentMap === 'ayutthaya') {
            mapGreeting = 'Historic Wonders of Ayutthaya! 🏛️🐘 / สวัสดีจากอยุธยา!';
        }
        
        ctx.fillText(mapGreeting, framePadding + 15, postcard.height - 35);
        
        // H. Draw dashed stamp post lines on bottom-right page side
        ctx.strokeStyle = 'rgba(58, 50, 50, 0.35)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        // Line 1
        ctx.moveTo(postcard.width / 2 + 50, postcard.height - 45);
        ctx.lineTo(postcard.width - 60, postcard.height - 45);
        // Line 2
        ctx.moveTo(postcard.width / 2 + 50, postcard.height - 25);
        ctx.lineTo(postcard.width - 60, postcard.height - 25);
        ctx.stroke();
        
        // 4. Download file
        const postcardDataUrl = postcard.toDataURL('image/png');
        const link = document.createElement('a');
        link.download = `thailand_toy_postcard_${state.currentMap || 'bangkok'}.png`;
        link.href = postcardDataUrl;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        
        triggerAlertLog(isThai 
            ? '💾 บันทึกโปสการ์ดลงอัลบั้มภาพสำเร็จแล้ว! สวยงามมากครับ'
            : '💾 Saved your travel postcard successfully!'
        );
    };
}

// Trigger Photo Mode initializer on load
initPhotoMode();


