function initCampaignMode() {
    // 1. Hook Game Mode button triggers
    const btnParty = document.getElementById('btn-mode-party');
    const btnCampaign = document.getElementById('btn-mode-campaign');
    
    if (btnParty) {
        btnParty.addEventListener('click', () => {
            triggerPurchaseChime();
            isCampaignModeActive = false;
            btnParty.classList.add('active');
            if (btnCampaign) btnCampaign.classList.remove('active');
            
            // Highlight Party Ready
            const btnReady = document.getElementById('btn-ready-tour');
            if (btnReady) {
                const isThai = state.lang === 'th';
                btnReady.querySelector('.btn-bubble-content').innerHTML = isThai 
                    ? `พร้อมเที่ยวฟรีเพลย์! 🎲` 
                    : `PARTY PLAY READY! 🎲`;
            }
        });
    }
    
    if (btnCampaign) {
        btnCampaign.addEventListener('click', () => {
            triggerPurchaseChime();
            isCampaignModeActive = true;
            btnCampaign.classList.add('active');
            if (btnParty) btnParty.classList.remove('active');
            
            // Open Campaign roadmap directly!
            openCampaignModal();
        });
    }

    // Modal Close
    const btnClose = document.getElementById('btn-close-campaign');
    if (btnClose) {
        btnClose.addEventListener('click', () => {
            triggerSadRentSFX();
            hideModal('campaign-modal');
            const modal = document.getElementById('campaign-modal');
            if (modal) modal.style.display = 'none';
        });
    }

    const btnRelicClaim = document.getElementById('btn-relic-claim');
    if (btnRelicClaim) {
        btnRelicClaim.addEventListener('click', () => {
            triggerConfettiBurst();
            triggerPurchaseChime();
            hideModal('relic-unlock-modal');
        });
    }
}

function openCampaignModal() {
    renderCampaignPathway();
    const modal = document.getElementById('campaign-modal');
    if (modal) modal.style.display = 'flex';
    state.activeModal = null; // Clear any zombie modal blocks
    showModal('campaign-modal');
}

function renderCampaignPathway() {
    const pathwayDiv = document.getElementById('campaign-road-pathway');
    if (!pathwayDiv) return;
    
    pathwayDiv.innerHTML = '';
    const isThai = state.lang === 'th';
    
    // Calculate total completed percentage
    const completedCount = state.progression.campaignBeaten.length;
    const totalCount = campaignNodes.length;
    const pct = Math.floor((completedCount / totalCount) * 100);
    
    const pctLabel = document.getElementById('campaign-pct-value');
    if (pctLabel) {
        pctLabel.innerText = isThai 
            ? `${pct}% (ชนะแล้ว ${completedCount}/${totalCount} ด่าน)`
            : `${pct}% (${completedCount}/${totalCount} BEATEN)`;
    }
    
    const fill = document.getElementById('campaign-progress-fill');
    if (fill) {
        fill.style.width = `${pct}%`;
    }
    
    // Render Nodes
    campaignNodes.forEach((node, index) => {
        // Bangkok is index 0 (always unlocked)
        // Others unlock if the previous index's id is inside state.progression.campaignBeaten
        let isUnlocked = (index === 0);
        if (index > 0) {
            const prevNode = campaignNodes[index - 1];
            if (state.progression.campaignBeaten.includes(prevNode.id)) {
                isUnlocked = true;
            }
        }
        
        const isBeaten = state.progression.campaignBeaten.includes(node.id);
        const hasRelic = state.progression.relics.includes(node.relicId);
        
        const card = document.createElement('div');
        card.style.background = isUnlocked ? node.bgGradient : '#e2e8f0';
        card.style.border = '3px solid var(--border-dark)';
        card.style.borderRadius = '20px';
        card.style.padding = '12px 16px';
        card.style.display = 'flex';
        card.style.flexDirection = 'column';
        card.style.gap = '8px';
        card.style.position = 'relative';
        card.style.boxShadow = 'var(--toy-shadow-small)';
        card.style.opacity = isUnlocked ? '1' : '0.65';
        
        // Locked pad overlay
        if (!isUnlocked) {
            card.innerHTML = `
                <div style="position: absolute; inset: 0; background: rgba(58,50,50,0.12); border-radius: 17px; display: flex; align-items: center; justify-content: center; font-size: 2.2rem; pointer-events: none; z-index: 5;">
                    🔒
                </div>
            `;
        }
        
        // Node contents
        const diffStars = '⭐'.repeat(node.difficulty);
        const statusText = isBeaten 
            ? (isThai ? '🏆 สำเร็จแล้ว (ทอง)' : '🏆 STORY COMPLETED (GOLD)')
            : (isUnlocked ? (isThai ? '🎲 พร้อมตะลุย!' : '🎲 ACTIVE ENTRY') : (isThai ? '🔒 ล็อกอยู่' : '🔒 LOCKED ROAD'));
            
        const badgeColor = isBeaten ? 'var(--pastel-green)' : (isUnlocked ? 'var(--pastel-yellow)' : '#94a3b8');
        const badgeTextColor = isBeaten ? 'white' : 'var(--text-dark)';
        
        const titleText = isThai ? node.thName : node.name;
        const descText = isThai ? node.thDesc : node.desc;
        const relicText = isThai ? node.relicThName : node.relicName;
        
        const relicStyle = hasRelic 
            ? `background-color: var(--pastel-mint); border-color: var(--border-dark);`
            : `background-color: #cbd5e1; border-color: rgba(0,0,0,0.15); color: #64748b;`;
            
        const relicEmoji = hasRelic ? node.relicEmoji : '❓';
        const relicLabel = hasRelic ? relicText : (isThai ? 'ของสะสมลึกลับ' : 'Mystery Relic');
        
        card.innerHTML += `
            <!-- Top Row: Badge status & Stars -->
            <div style="display: flex; justify-content: space-between; align-items: center; width: 100%;">
                <span style="font-size: 0.68rem; font-weight: 800; border: 2px solid var(--border-dark); border-radius: 8px; padding: 2px 8px; background: ${badgeColor}; color: ${badgeTextColor}; text-transform: uppercase;">
                    ${statusText}
                </span>
                <span style="font-size: 0.85rem; filter: drop-shadow(1px 1px 0 var(--border-dark));">${diffStars}</span>
            </div>
            
            <!-- Middle details -->
            <div style="display: flex; gap: 12px; align-items: center;">
                <div style="font-size: 2.8rem; filter: drop-shadow(0 2px 0 var(--border-dark));">${node.emoji}</div>
                <div style="flex: 1; text-align: left;">
                    <h3 style="font-size: 1.15rem; font-weight: 800; color: var(--text-dark); margin: 0;">${titleText}</h3>
                    <p style="font-size: 0.76rem; color: var(--text-muted); font-weight: 700; line-height: 1.3; margin: 3px 0 0 0;">${descText}</p>
                </div>
            </div>
            
            <!-- Relic collectibles bar -->
            <div style="display: flex; justify-content: space-between; align-items: center; width: 100%; margin-top: 2px; padding: 5px 10px; border-radius: 10px; border: 2px solid; ${relicStyle}">
                <span style="font-size: 0.72rem; font-weight: 800; display: flex; align-items: center; gap: 4px;">
                    <i class="fa-solid fa-gift"></i> STAMP RELIC: ${relicLabel}
                </span>
                <span style="font-size: 1.05rem;">${relicEmoji}</span>
            </div>
            
            <!-- Action bottom launcher -->
            ${isUnlocked ? `
                <button class="cute-mini-btn btn-campaign-launch" data-id="${node.id}" style="width: 100%; font-weight: 800; font-size: 0.85rem; padding: 8px; border-radius: 10px; border: 2.5px solid var(--border-dark); box-shadow: 0 3.5px 0 var(--border-dark); background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%); color: white; cursor: pointer; margin-top: 4px;">
                    ${isBeaten ? (isThai ? 'REPLAY STORY / ตะลุยบอร์ดอีกครั้ง 🎲' : 'REPLAY STORY MATCH 🎲') : (isThai ? 'START CAMPAIGN / เริ่มตะลุยเนื้อเรื่อง 🎲' : 'START CAMPAIGN MATCH 🎲')}
                </button>
            ` : ''}
        `;
        
        pathwayDiv.appendChild(card);
    });
    
    // Bind Click launching
    const launchBtns = pathwayDiv.querySelectorAll('.btn-campaign-launch');
    launchBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const themeId = btn.getAttribute('data-id');
            triggerPurchaseChime();
            hideModal('campaign-modal');
            const modal = document.getElementById('campaign-modal');
            if (modal) modal.style.display = 'none';
            startCampaignMatch(themeId);
        });
    });
}

function startCampaignMatch(themeId) {
    isCampaignModeActive = true;
    
    // Set map carousel index
    const keys = ['bangkok', 'chiangmai', 'phuket', 'pattaya', 'ayutthaya'];
    state.mapCarouselIndex = keys.indexOf(themeId);
    
    // Launch campaign flight!
    const isThai = state.lang === 'th';
    selectMapAndLaunchTravel(themeId);
}

// Trigger Campaign mode initializer on load
initCampaignMode();





