function showWelcomeTour() {
    state.welcomeTourIndex = 0;
    
    // Clear any active modals or overlays to avoid conflicts
    state.activeModal = 'welcome-tour-modal';
    
    const tourModal = document.getElementById('welcome-tour-modal');
    if (tourModal) {
        tourModal.style.display = 'flex';
        // Wait one frame to trigger CSS transitions nicely
        setTimeout(() => {
            tourModal.classList.add('active');
        }, 50);
    }
    
    updateWelcomeTourSlide();
}

function updateWelcomeTourSlide() {
    const isThai = state.lang === 'th';
    const slide = welcomeTourSlides[state.welcomeTourIndex];
    if (!slide) return;
    
    const emojiEl = document.getElementById('welcome-tour-emoji');
    const titleEl = document.getElementById('welcome-tour-title');
    const descEl = document.getElementById('welcome-tour-desc');
    const nextBtnText = document.querySelector('#btn-welcome-next .btn-bubble-content');
    
    if (emojiEl) emojiEl.innerText = slide.emoji;
    if (titleEl) titleEl.innerText = isThai ? slide.thTitle : slide.enTitle;
    if (descEl) descEl.innerText = isThai ? slide.thDesc : slide.enDesc;
    
    // Update Next button label on the final step
    if (nextBtnText) {
        if (state.welcomeTourIndex === welcomeTourSlides.length - 1) {
            nextBtnText.innerHTML = isThai ? 'เริ่มทัวร์! 🎲' : 'START TOUR! 🎲';
        } else {
            nextBtnText.innerHTML = isThai ? 'ขั้นตอนถัดไป ➡️' : 'NEXT STEP ➡️';
        }
    }
    
    // Update Dots Indicators active status
    const dots = document.querySelectorAll('.welcome-tour-dot');
    dots.forEach((dot, idx) => {
        if (idx === state.welcomeTourIndex) {
            dot.classList.add('active');
            dot.style.backgroundColor = 'var(--pastel-pink)';
        } else {
            dot.classList.remove('active');
            dot.style.backgroundColor = '#fff';
        }
    });
}

function closeWelcomeTour() {
    // Save that the welcome tour has been completed
    localStorage.setItem('thailand_toy_welcome_tour_seen', 'true');
    
    const tourModal = document.getElementById('welcome-tour-modal');
    if (tourModal) {
        tourModal.classList.remove('active');
        setTimeout(() => {
            tourModal.style.display = 'none';
        }, 400);
    }
    
    if (state.activeModal === 'welcome-tour-modal') {
        state.activeModal = null;
    }
    
    checkAndShowQueuedLevelUp();
}

let discoveryCloseCallback = null;

function showTileDiscoveryPopup(tile, propType, xpReward, onCloseCallback, isInitialShow = true) {
    discoveryCloseCallback = onCloseCallback;
    
    // Save in state so applyLanguage can update it live!
    state.activeDiscoveryLandmark = { tile, propType, xpReward };
    
    const isThai = state.lang === 'th';
    const activeBoardId = state.currentMap || 'bangkok';
    
    // City name translation
    const mapNameTranslations = {
        bangkok: { en: 'Bangkok', th: 'กรุงเทพฯ' },
        chiangmai: { en: 'Chiang Mai', th: 'เชียงใหม่' },
        phuket: { en: 'Phuket', th: 'ภูเก็ต' },
        pattaya: { en: 'Pattaya', th: 'พัทยา' },
        ayutthaya: { en: 'Ayutthaya', th: 'อยุธยา' }
    };
    
    const cityObj = mapNameTranslations[activeBoardId] || { en: 'Bangkok', th: 'กรุงเทพฯ' };
    const cityName = isThai ? cityObj.th : cityObj.en;
    
    // Elements
    const modal = document.getElementById('tile-discovery-modal');
    const subtitleEl = document.getElementById('discovery-landmark-subtitle');
    const emojiEl = document.getElementById('discovery-landmark-emoji');
    const nameEl = document.getElementById('discovery-landmark-name');
    const descEl = document.getElementById('discovery-landmark-desc');
    const rewardAlbumEl = document.getElementById('discovery-reward-album');
    const rewardXpEl = document.getElementById('discovery-reward-xp');
    const claimBtnText = document.querySelector('#btn-discovery-claim .btn-bubble-content');
    
    if (subtitleEl) {
        subtitleEl.innerText = isThai 
            ? `ค้นพบแลนด์มาร์กใหม่แห่ง${cityName}! 🌟` 
            : `NEW ${cityName.toUpperCase()} LANDMARK DISCOVERED!`;
    }
    
    if (emojiEl) emojiEl.innerText = tile.icon || '🛕';
    
    const propMeta = collectionProperties.find(p => p.id === propType);
    if (nameEl) {
        if (isThai) {
            nameEl.innerText = propMeta ? propMeta.thName : getThaiLocationName(tile.name);
        } else {
            nameEl.innerText = propMeta ? propMeta.name : tile.name;
        }
    }
    
    if (descEl) {
        if (isThai) {
            descEl.innerText = typeof getThaiLocationDesc === 'function' ? getThaiLocationDesc(tile) : tile.desc;
        } else {
            descEl.innerText = tile.desc;
        }
    }
    
    if (rewardAlbumEl) {
        rewardAlbumEl.innerText = isThai ? 'สะสมในอัลบั้ม! 📖' : 'Sticker unlocked! 📖';
    }
    
    if (rewardXpEl) {
        rewardXpEl.innerText = isThai ? `ได้รับ +${xpReward} XP` : `+${xpReward} XP`;
    }
    
    if (claimBtnText) {
        claimBtnText.innerText = isThai ? 'ดำเนินการต่อ' : 'Continue';
    }
    
    cleanupInactiveLandingModals('tile-discovery-modal');
    configureLandingButtons('tile-discovery-modal');

    // Block other modals
    state.activeModal = 'tile-discovery-modal';
    
    if (modal) {
        modal.style.display = 'flex';
        modal.style.pointerEvents = '';
        setTimeout(() => {
            modal.classList.add('active');
            renderLandingModalUX('tile-discovery-modal', 'discovery', {
                labelEn: 'Continue',
                labelTh: 'ดำเนินการต่อ'
            });
        }, 50);
    }
    
    // Play celebratory sound & visual confetti
    if (isInitialShow) {
        if (typeof triggerPurchaseChime === 'function') triggerPurchaseChime();
        if (typeof triggerConfettiBurst === 'function') triggerConfettiBurst();
    }
}

function closeTileDiscoveryPopup() {
    consumeLandingAction('discovery');
    const modal = document.getElementById('tile-discovery-modal');
    if (modal) {
        modal.classList.remove('active');
        modal.style.pointerEvents = 'none';
        setTimeout(() => {
            modal.style.display = 'none';
        }, 400);
    }
    
    if (state.activeModal === 'tile-discovery-modal') {
        state.activeModal = null;
    }
    
    state.activeDiscoveryLandmark = null;
    
    // Trigger callback to resume gameplay turns
    if (typeof discoveryCloseCallback === 'function') {
        const callback = discoveryCloseCallback;
        discoveryCloseCallback = null;
        callback();
    }
    
    checkAndShowQueuedLevelUp();
}

function checkFirstTimeUserFlow() {
    const isFirstTime = localStorage.getItem('thailand_toy_first_time') === null;
    if (!isFirstTime) {
        restoreAdvancedMenus();
    }
}

function restoreAdvancedMenus() {
    document.querySelectorAll('.first-time-hidden').forEach(el => {
        el.classList.remove('first-time-hidden');
    });
}

function showTutorialStepOverlay(stepNum) {
    state.interactiveTutorialActive = true;
    state.tutorialStep = stepNum;
    
    // Steps are 1-indexed for logic, but tutorialSteps array is 0-indexed (stepNum - 1)
    const isThai = state.lang === 'th';
    const step = tutorialSteps[stepNum - 1];
    if (!step) return;

    const overlay = document.getElementById('tutorial-overlay');
    const iconEl = document.getElementById('tutorial-icon');
    const titleEl = document.getElementById('tutorial-title');
    const textEl = document.getElementById('tutorial-text');
    const nextBtn = document.getElementById('btn-next-tutorial');
    const skipBtn = document.getElementById('btn-skip-tutorial');

    if (iconEl) iconEl.innerText = step.emoji;
    if (titleEl) titleEl.innerText = isThai ? step.thTitle : step.enTitle;
    if (textEl) textEl.innerText = isThai ? step.thText : step.enText;

    // Apply specific visual spotlights
    document.querySelectorAll('.tutorial-highlight').forEach(el => el.classList.remove('tutorial-highlight'));

    if (stepNum === 1) {
        const btnRoll = document.getElementById('btn-roll-dice');
        if (btnRoll) btnRoll.classList.add('tutorial-highlight');
        if (nextBtn) nextBtn.style.display = 'none';
        if (skipBtn) skipBtn.style.display = 'block';
    } else if (stepNum === 2) {
        // Spotlights Buy Yes inside the modal
        const btnBuyYes = document.getElementById('btn-buy-yes');
        if (btnBuyYes) btnBuyYes.classList.add('tutorial-highlight');
        if (nextBtn) nextBtn.style.display = 'none';
        if (skipBtn) skipBtn.style.display = 'block';
    } else if (stepNum === 3) {
        // Spotlight none (read rent notification)
        if (nextBtn) {
            nextBtn.style.display = 'block';
            nextBtn.innerText = isThai ? 'ขั้นตอนถัดไป ➡️' : 'NEXT STEP ➡️';
        }
        if (skipBtn) skipBtn.style.display = 'block';
    } else if (stepNum === 4) {
        // Spotlight Upgrade Yes inside the modal
        const btnUpgradeYes = document.getElementById('btn-upgrade-yes');
        if (btnUpgradeYes) btnUpgradeYes.classList.add('tutorial-highlight');
        if (nextBtn) nextBtn.style.display = 'none';
        if (skipBtn) skipBtn.style.display = 'block';
    } else if (stepNum === 5) {
        if (nextBtn) {
            nextBtn.style.display = 'block';
            nextBtn.innerText = isThai ? 'เริ่มเล่นเลย! 🎉' : "LET'S PLAY! 🎉";
        }
        if (skipBtn) skipBtn.style.display = 'none'; // No need to skip once finished!
    }

    // Update dots active class
    const dots = document.querySelectorAll('.tutorial-dot');
    dots.forEach((dot, idx) => {
        if (idx === (stepNum - 1)) {
            dot.classList.add('active');
        } else {
            dot.classList.remove('active');
        }
    });

    if (overlay) {
        overlay.style.display = 'flex';
        overlay.classList.add('active');
    }
}

function showTutorialOverlay() {
    showTutorialStepOverlay(1);
}

function hideTutorialOverlay() {
    const overlay = document.getElementById('tutorial-overlay');
    if (overlay) {
        overlay.classList.remove('active');
        setTimeout(() => {
            overlay.style.display = 'none';
        }, 300);
    }
}

function showUpgradeModalForTutorial() {
    const tile = state.board[2]; // Pad Thai Stall
    const activePlayer = state.players[0]; // Human
    const cost = calculatePropertyUpgradeCost(activePlayer, tile);
    
    showModal('upgrade-property-modal');
    
    const isThai = state.lang === 'th';
    const headerText = isThai ? "อัปเกรดกระท่อมของเล่น! 🏗️" : "UPGRADE COTTAGE! 🏗️";
    document.getElementById('upgrade-modal-header').innerText = headerText;
    document.getElementById('upgrade-name').innerText = isThai ? "ร้านผัดไทย" : "Pad Thai Stall";
    document.getElementById('upgrade-icon').innerText = "🍜";
    
    const descText = isThai
        ? "อัปเกรดร้านค้าของคุณให้เป็นสองชั้นพร้อมป้ายไฟนีออนพาสเทลเพื่อเพิ่มค่าเช่า 2 เท่า! 🏡"
        : "Upgrade your shop into a larger double-story shop with a glowing neon sign to boost rent 2X! 🏡";
    document.getElementById('upgrade-desc').innerText = descText;
    
    document.getElementById('prop-upgrade-price').innerText = cost;
    document.getElementById('prop-new-rent-price').innerText = (tile.rent || 40) * 2;
    
    // Highlight the upgrade yes button
    const btnUpgradeYes = document.getElementById('btn-upgrade-yes');
    if (btnUpgradeYes) {
        btnUpgradeYes.classList.add('tutorial-highlight');
    }
}

function completeTutorial() {
    localStorage.setItem('thailand_toy_first_time', 'false');
    state.interactiveTutorialActive = false;
    state.tutorialStep = 0;
    
    // Clear highlights
    document.querySelectorAll('.tutorial-highlight').forEach(el => el.classList.remove('tutorial-highlight'));
    document.querySelectorAll('.tutorial-dimmed').forEach(el => el.classList.remove('tutorial-dimmed'));
    
    restoreAdvancedMenus();
    hideTutorialOverlay();
    
    // Relaunch the match as a clean Campaign or Selection play from scratch!
    triggerConfettiBurst();
    restartGame();
}

function launchQuickStartMatch() {
    const isThai = state.lang === 'th';
    const targetMapId = 'bangkok';
    const config = boardConfigurations[targetMapId];
    
    state.carouselIndex = 0; // Select Toury Cat
    state.mapCarouselIndex = 0; // Select Bangkok map
    state.isSelectionActive = true; // Set selection active so character states are populated correctly
    
    // Play Clouds transition and change map
    triggerTravelJingle();
    
    const transition = document.getElementById('travel-transition-overlay');
    const leftCloud = transition.querySelector('.flight-clouds-left');
    const rightCloud = transition.querySelector('.flight-clouds-right');
    const statusText = document.getElementById('flight-status-text');
    
    statusText.innerText = isThai ? 'กำลังบินไปกรุงเทพฯ... \u2708\ufe0f' : 'FLYING TO BANGKOK... \u2708\ufe0f';
    transition.style.display = 'flex';
    transition.style.opacity = 1;
    
    // Slide clouds in
    leftCloud.style.left = '0px';
    rightCloud.style.right = '0px';
    
    setTimeout(() => {
        // Dynamically swap board environment under the hood
        loadBoardTheme(targetMapId);
        
        statusText.innerText = isThai ? 'แลนดิ้งที่กรุงเทพฯแล้ว! \U0001f3dd\ufe0f' : 'LANDED AT BANGKOK! \U0001f3dd\ufe0f';
        
        setTimeout(() => {
            // Part the clouds
            leftCloud.style.left = '-600px';
            rightCloud.style.right = '-600px';
            
            setTimeout(() => {
                transition.style.opacity = 0;
                setTimeout(() => transition.style.display = 'none', 500);
                
                triggerConfettiBurst();
                
                // Set match parameters from selections
                state.isSelectionActive = false;
                const selectScreen = document.getElementById('char-select-screen');
                if (selectScreen) {
                    selectScreen.classList.remove('active');
                    selectScreen.style.opacity = 0;
                    selectScreen.style.display = 'none';
                }
                
                // Copy selected templates (Cat as player 0, others as bots)
                const humanTemplate = playableTemplates[0];
                const botTemplates = playableTemplates.filter((_, idx) => idx !== 0);
                
                state.players[0].name = humanTemplate.name;
                state.players[0].emoji = humanTemplate.emoji;
                state.players[0].color = humanTemplate.color;
                state.players[0].characterType = humanTemplate.type;
                state.players[0].isBot = false;
                state.players[0].personality = 'human';
                
                for (let i = 1; i <= 3; i++) {
                    const t = botTemplates[i - 1];
                    state.players[i].name = t.name;
                    state.players[i].emoji = t.emoji;
                    state.players[i].color = t.color;
                    state.players[i].characterType = t.type;
                    state.players[i].isBot = true;
                    state.players[i].personality = t.personality;
                }
                
                // Recreate 3D meshes
                recreatePlayerMeshes();
                
                state.player = state.players[0];
                state.opponent = state.players[1];
                
                updateTurnIndicatorHUD();
                renderLeaderboard();
                
                state.lastPlayerCoins = state.players[0].coins;
                
                const hud = document.getElementById('game-hud');
                if (hud) hud.style.display = 'block';
                state.started = true;
                clock.getDelta(); // reset clock delta
                
                // Check if first-time user
                const isFirstTime = localStorage.getItem('thailand_toy_first_time') === null;
                if (isFirstTime) {
                    showTutorialStepOverlay(1);
                } else {
                    beginNewTurnFlow('announcing');
                    triggerConfettiBurst();
                    triggerPlayerEmote('\u2728', state.players[0].mesh);
                    triggerAlertLog(isThai
                        ? `\u0e40ริ่มการผจญภัย! คุณกำลังเที่ยวเมืองไทยในฐานะ ${humanTemplate.name}! \u2708\ufe0f\U0001f3dd\ufe0f`
                        : `Trip started! You are exploring Thailand as ${humanTemplate.name}! \u2708\ufe0f\U0001f3dd\ufe0f`
                    );
                    triggerTurnStartAnnouncement(0);
                }
            }, 500);
        }, 1000);
    }, 1500);
}

