// Toggle standard gameplay meshes (player chibis, dice, indicator glows)
function setMatchMeshesVisible(visible) {
    if (state.players) {
        state.players.forEach(p => {
            if (p.mesh) p.mesh.visible = visible;
        });
    }
    if (activePlayerIndicatorGroup) {
        activePlayerIndicatorGroup.visible = visible;
    }
    if (scene) {
        scene.children.forEach(child => {
            if (child.name === "3d_die" || child.name === "3d_die_platform") {
                child.visible = visible;
            }
        });
    }
}

// Global Canvas click raycasting for interactive portals
function onVillageCanvasClick(e) {
    if (state.started || !window.villageHubActive) return;

    // Norm device coordinates
    const rect = canvas.getBoundingClientRect();
    const clickX = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    const clickY = -((e.clientY - rect.top) / rect.height) * 2 + 1;

    const clickMouse = new THREE.Vector2(clickX, clickY);
    const clickRaycaster = new THREE.Raycaster();
    clickRaycaster.setFromCamera(clickMouse, camera);

    const intersects = clickRaycaster.intersectObjects(window.villageHubInteractiveMeshes, true);
    if (intersects.length > 0) {
        let obj = intersects[0].object;
        while (obj && !obj.userData.portalType) {
            obj = obj.parent;
        }

        if (obj && obj.userData.portalType) {
            const portalType = obj.userData.portalType;
            
            // Trigger feedback
            triggerHaptic(15);
            triggerButtonPressChime();
            
            // Visual bounce pop on clicked group
            obj.scale.set(1.25, 1.25, 1.25);
            setTimeout(() => {
                if (obj.scale) obj.scale.set(1.0, 1.0, 1.0);
            }, 250);

            // Execute portal modal actions!
            if (portalType === 'play') {
                showSelectionScreen();
            } else if (portalType === 'heroes') {
                if (typeof openGalleryModal === 'function') openGalleryModal();
            } else if (portalType === 'album') {
                if (typeof openCollectionBook === 'function') openCollectionBook();
            } else if (portalType === 'achievements') {
                if (typeof openAchievementsModal === 'function') openAchievementsModal();
            } else if (portalType === 'settings') {
                const panelAudio = document.querySelector('.hud-audio-panel');
                if (panelAudio) {
                    panelAudio.classList.toggle('active');
                }
            }
        }
    }
}

// Custom function to register click and UI visibility button
let villageListenersBound = false;
function setupVillageHubListeners() {
    if (villageListenersBound) return;
    villageListenersBound = true;

    if (canvas) {
        canvas.addEventListener('pointerup', onVillageCanvasClick);
    }

    const btnHideUI = document.getElementById('btn-hide-lobby-ui');
    if (btnHideUI) {
        btnHideUI.addEventListener('click', (e) => {
            e.stopPropagation();
            triggerHaptic(15);
            triggerButtonPressChime();
            const selectScreen = document.getElementById('char-select-screen');
            if (selectScreen) {
                selectScreen.classList.toggle('ui-hidden');
                const hidden = selectScreen.classList.contains('ui-hidden');
                btnHideUI.innerText = hidden ? '👁️‍🗨️' : '👁️';
            }
        });
    }
}

