// Check set completion helper
function isFullDistrictSetOwned(ownerId, tileName) {
    if (!ownerId || !window.DISTRICT_SETS) return false;
    const district = window.DISTRICT_SETS.find(d => d.tiles.includes(tileName));
    if (!district) return false;
    
    return district.tiles.every(name => {
        const matchingTile = state.board.find(t => t.name === name);
        return matchingTile && matchingTile.owner === ownerId;
    });
}

// Purchase check trigger for set updates, coins, XP, achievement updates
function checkDistrictCollectionUpdates(player, boughtTile) {
    if (!player || !boughtTile || !window.DISTRICT_SETS) return;
    
    player.completedDistricts = player.completedDistricts || [];
    
    // Find district for this tile
    const district = window.DISTRICT_SETS.find(d => d.tiles.includes(boughtTile.name));
    if (!district) return;
    
    // Verify if player has completed this set
    const isCompletedNow = district.tiles.every(name => {
        const matchingTile = state.board.find(t => t.name === name);
        return matchingTile && matchingTile.owner === player.id;
    });
    
    if (isCompletedNow && !player.completedDistricts.includes(district.id)) {
        player.completedDistricts.push(district.id);
        
        // Award set rewards
        player.coins += district.rewardCoins;
        player.stats.totalCoinsEarned += district.rewardCoins;
        
        const isThai = state.lang === 'th';
        
        if (player.id === 'player') {
            addXP(district.rewardXp);
            
            // Trigger achievement updates
            if (typeof updateAchievementProgress === 'function') {
                updateAchievementProgress('complete_district_sets', 1);
            }
            
            // Celebratory alert log
            const descStr = isThai
                ? `สะสมที่ดินย่าน ${district.name.split('/')[1].trim()} สำเร็จ! รับโบนัส 💰 ${district.rewardCoins} เหรียญ และ ⚡ ${district.rewardXp} XP! 🎉`
                : `Completed ${district.name.split('/')[0].trim()} Set! Received 💰 ${district.rewardCoins} Coins and ⚡ ${district.rewardXp} XP! 🎉`;
            triggerAlertLog(descStr);
            
            // Pop completion overlay animation card!
            if (typeof triggerDistrictCompletedAnimation === 'function') {
                triggerDistrictCompletedAnimation(district);
            }
        } else {
            // bot alert log
            const descStr = isThai
                ? `${player.name} สะสมที่ดินย่าน ${district.name.split('/')[1].trim()} สำเร็จ! รับโบนัส 💰 ${district.rewardCoins} เหรียญ! 🤖🏆`
                : `${player.name} completed ${district.name.split('/')[0].trim()} Set! Received 💰 ${district.rewardCoins} Coins! 🤖🏆`;
            triggerAlertLog(descStr);
        }
        
        // Sync HUD & owned items grid
        updateCoinsHUD();
        updateOwnedPropertiesGrid();
    }
}

// Celebratory pop up overlay animation
function triggerDistrictCompletedAnimation(district) {
    const pop = document.getElementById('district-completed-popup');
    if (!pop) return;
    
    const isThai = state.lang === 'th';
    const tileIcon = district.tiles[0] ? state.board.find(t => t.name === district.tiles[0])?.icon || '🏮' : '🏮';
    
    // Set text contents
    document.getElementById('dist-pop-emoji').innerText = tileIcon;
    document.getElementById('dist-pop-sub').innerText = isThai ? 'เซ็ตย่านสำเร็จ 🏆' : 'DISTRICT COMPLETED! 🏆';
    document.getElementById('dist-pop-title').innerText = isThai ? district.name.split('/')[1].trim() : district.name.split('/')[0].trim();
    document.getElementById('dist-pop-desc').innerText = isThai
        ? `คุณสะสมที่ดินครบแล้ว: ${district.tiles.map(t => getThaiLocationName(t)).join(', ')}!`
        : `You collected: ${district.tiles.join(', ')}!`;
    document.getElementById('dist-pop-coins').innerText = `+${district.rewardCoins}`;
    document.getElementById('dist-pop-xp').innerText = `+${district.rewardXp} XP`;
    
    const badgeEl = document.getElementById('dist-pop-badge');
    if (badgeEl) {
        badgeEl.style.background = district.color;
        badgeEl.innerText = isThai ? district.badge.split(' ').slice(1).join(' ') : district.badge;
    }
    
    // Celebration Sound & sparklers Confetti!
    triggerPurchaseChime();
    triggerConfettiBurst();
    setTimeout(triggerConfettiBurst, 250);
    setTimeout(triggerConfettiBurst, 500);
    
    // Slide popup open with elastic scale bounce
    pop.style.display = 'block';
    pop.offsetHeight; // force reflow
    pop.classList.add('district-popup-animate');
    pop.style.opacity = '1';
    
    // Animate pop-out after 3.8s
    setTimeout(() => {
        pop.style.opacity = '0';
        pop.style.transform = 'translate(-50%, -50%) scale(0.8)';
        setTimeout(() => {
            pop.style.display = 'none';
            pop.classList.remove('district-popup-animate');
        }, 400);
    }, 3800);
}

// Update Buy Property Modal District set badges
function updateBuyPropertyModalDistrictBadge(tile) {
    const badge = document.getElementById('prop-district-badge');
    if (!badge) return;
    
    if (!tile || !window.DISTRICT_SETS) {
        badge.style.display = 'none';
        return;
    }
    
    // Find matching district
    const district = window.DISTRICT_SETS.find(d => d.tiles.includes(tile.name));
    if (!district) {
        badge.style.display = 'none';
        return;
    }
    
    // Count active player's owned items
    const player = state.players[0];
    let ownedCount = 0;
    district.tiles.forEach(name => {
        const t = state.board.find(x => x.name === name);
        if (t && t.owner === player.id) ownedCount++;
    });
    
    const isThai = state.lang === 'th';
    badge.style.display = 'inline-block';
    badge.style.background = district.color;
    badge.style.borderColor = 'var(--border-dark)';
    badge.style.color = '#fff';
    
    badge.innerText = isThai
        ? `${district.badge.split(' ').slice(1).join(' ')} (${ownedCount}/${district.tiles.length} ในครอบครอง)`
        : `${district.badge} (${ownedCount}/${district.tiles.length} OWNED)`;
}

// Render dynamic progress bars and completed badges inside Properties Owned board drawer
function renderDistrictCollectionsHUD() {
    const list = document.getElementById('district-progress-list');
    if (!list) return;
    
    list.innerHTML = '';
    const player = state.players[0];
    if (!player || !window.DISTRICT_SETS) return;
    
    const isThai = state.lang === 'th';
    
    window.DISTRICT_SETS.forEach(dist => {
        let ownedCount = 0;
        const subItemsHtml = dist.tiles.map(name => {
            const tile = state.board.find(t => t.name === name);
            const isOwned = tile && tile.owner === player.id;
            if (isOwned) ownedCount++;
            
            const textColor = isOwned ? 'var(--text-dark)' : '#94a3b8';
            const icon = tile ? tile.icon : '🏡';
            const cleanName = isThai ? getThaiLocationName(name).split(' ')[0] : name.split(' ')[0];
            
            return `
                <div style="display: flex; align-items: center; gap: 4px; font-size: 0.65rem; color: ${textColor}; font-weight: 700; background: ${isOwned ? '#fff' : 'rgba(0,0,0,0.03)'}; border: 1.5px solid ${isOwned ? 'var(--border-dark)' : '#cbd5e1'}; border-radius: 8px; padding: 2px 6px; white-space: nowrap; box-shadow: ${isOwned ? 'var(--toy-shadow-small)' : 'none'};">
                    <span style="font-size: 0.72rem;">${icon}</span>
                    <span>${cleanName}</span>
                    ${isOwned ? '<i class="fa-solid fa-check" style="color: #10b981; font-size: 0.6rem; margin-left: 2px;"></i>' : ''}
                </div>
            `;
        }).join('');
        
        const isComplete = ownedCount === dist.tiles.length;
        const percent = Math.floor((ownedCount / dist.tiles.length) * 100);
        
        const badgeTitle = isThai ? dist.name.split('/')[1].trim() : dist.name.split('/')[0].trim();
        const statusLabel = isComplete
            ? (isThai ? '🏆 สำเร็จครบย่าน (+50% ค่าเช่า)' : '🏆 COMPLETED (+50% RENT)')
            : `${ownedCount}/${dist.tiles.length} (${percent}%)`;
            
        const itemHtml = `
            <div style="background: ${isComplete ? 'rgba(254, 243, 199, 0.45)' : 'transparent'}; border: 2.2px solid ${isComplete ? 'var(--pastel-yellow)' : 'transparent'}; border-radius: 12px; padding: 5px 6px; display: flex; flex-direction: column; gap: 4px; transition: background 0.3s;">
                <div style="display: flex; justify-content: space-between; align-items: center; font-size: 0.7rem; font-weight: 800;">
                    <span style="color: var(--text-dark);">${badgeTitle}</span>
                    <span style="font-size: 0.62rem; background: ${isComplete ? dist.color : '#64748b'}; color: white; border: 1.5px solid var(--border-dark); border-radius: 6px; padding: 1px 6px; font-weight: 900; box-shadow: var(--toy-shadow-small); letter-spacing: 0.2px;">
                        ${statusLabel}
                    </span>
                </div>
                <div style="display: flex; gap: 5px; overflow-x: auto; padding: 2px 0; scrollbar-width: none;">
                    ${subItemsHtml}
                </div>
            </div>
        `;
        
        list.innerHTML += itemHtml;
    });
}

