        fogColor: new THREE.Color('#ffd5c6'), // Soft warm orange
        hemiSky: new THREE.Color('#ffa64d'),
        hemiGround: new THREE.Color('#7a4d80'),
        hemiInt: 1.4,
        sunColor: new THREE.Color('#ff5c33'),
